        const now = new Date();
        const past = new Date();
        past.setFullYear(now.getFullYear() - 2); // 2 years

        const start = past.toISOString();

        const alpacaResponse = await axios.get(`${ALPACA_BASE_URL}/stocks/${ticker}/bars`, {
            params: {
                start: start,
                timeframe: '1Day',
                limit: 1000
            },
            headers: {
                'APCA-API-KEY-ID': ALPACA_KEY,
                'APCA-API-SECRET-KEY': ALPACA_SECRET
            }
        });

        const bars = alpacaResponse.data.bars;

        if (bars && bars.length > 0) {
            const historical = bars.map(bar => ({
                date: bar.t.split('T')[0],
                close: bar.c,
                open: bar.o,
                high: bar.h,
                low: bar.l,
                volume: bar.v
            })).reverse(); 

            const mappedData = { 
                symbol: ticker, 
                historical: historical.reverse() 
            };

            return res.json(mappedData);
        }

    } catch (alpacaError) {
        console.warn(`[API] Alpaca History failed for ${ticker} (${alpacaError.message}), trying Yahoo...`);
    }

    // Attempt 2: Yahoo Finance (Fallback)
    try {
        console.log(`[API] Trying Yahoo Finance for ${ticker}...`);
        const yahooUrl = `https://query1.finance.yahoo.com/v8/finance/chart/${ticker}?range=2y&interval=1d`;
        const yResponse = await axios.get(yahooUrl, {
            headers: {
