            }
        });

        const result = yResponse.data?.chart?.result?.[0];
        if (result) {
            const timestamps = result.timestamp;
            const quotes = result.indicators.quote[0];

            // Map to standard format
            const historical = timestamps.map((t, i) => ({
                date: new Date(t * 1000).toISOString().split('T')[0],
                close: quotes.close[i],
                open: quotes.open[i],
                high: quotes.high[i],
                low: quotes.low[i],
                volume: quotes.volume[i]
            }))
            .filter(day => day.close !== null)
            .reverse(); 

            const mappedData = { symbol: ticker, historical };
            return res.json(mappedData);
        }
    } catch (yahooError) {
        console.warn(`[API] Yahoo Finance failed for ${ticker} (${yahooError.message}), trying FMP...`);
    }

    // Attempt 3: Financial Modeling Prep (Last Resort)
    const response = await axios.get(`https://financialmodelingprep.com/api/v3/historical-price-full/${ticker}?timeseries=365&apikey=${FMP_KEY}`);
