      sourceColor = 'text-rose-400';
      sourceIcon = <AlertTriangle className="w-3 h-3" />;
  }

  return (
    <div className="w-full bg-slate-900/60 backdrop-blur-md border border-white/10 rounded-2xl overflow-hidden mt-4 animate-fade-in group">
