    console.log(`[API] Fetching Quote for ${ticker} via Polygon (Prev Aggs)...`);

    const prevUrl = `https://api.polygon.io/v2/aggs/ticker/${ticker}/prev?adjusted=true&apiKey=${POLYGON_KEY}`;
