        // For 'Prev' endpoint, we calculate the day's move as Close - Open
        const change = price - open; 
        const changePercent = (change / open) * 100;

        return res.json({
            symbol: result.T || ticker,
            price: price,
            previousClose: open, 
            change: change,
            changePercent: changePercent,
            source: 'Polygon.io'
        });
    }

    throw new Error('No data in Prev endpoint');

  } catch (prevError) {
    console.warn(`[API] Polygon Prev failed for ${ticker} (${prevError.message}). Trying Snapshot...`);

    // PRIORITY 2: v2/snapshot (Fallback)
    try {
