  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [rotation, setRotation] = useState(0);
  const animationRef = useRef<number>(0);

  // Surface Configuration
  const gridResolution = 20; // 20x20 grid
  const spotRange = { min: 80, max: 120 }; // Underlying Price Range
  const timeRange = { min: 0.1, max: 1.0 }; // Time in Years (approx 36 days to 1 year)
  const strikePrice = 100; // Fixed Strike for this visualization

  // Generate the Mesh Data
  const generateMesh = (): Point3D[][] => {
    const mesh: Point3D[][] = [];

    for (let i = 0; i <= gridResolution; i++) {
      const row: Point3D[] = [];
      // Z-Axis: Time to Expiry (Normalized 0 to 1 for drawing)
      const tNorm = i / gridResolution;
      const t = timeRange.min + (timeRange.max - timeRange.min) * tNorm;

      for (let j = 0; j <= gridResolution; j++) {
        // X-Axis: Spot Price (Normalized 0 to 1 for drawing)
        const sNorm = j / gridResolution;
        const s = spotRange.min + (spotRange.max - spotRange.min) * sNorm;

        // Y-Axis: Option Price (The "Height")
        const price = calculateBlackScholes(
            isCall ? 'call' : 'put',
            s,
            strikePrice,
            t,
            riskFreeRate,
            volatility
        );

        // Normalize Price for display height (assuming max price roughly 40)
        const yNorm = price / 40;

        // Map to 3D Coordinate Space (-1 to 1)
        row.push({
            x: (sNorm - 0.5) * 2, // -1 to 1
            y: (yNorm - 0.5) * 2, // -1 to 1 (Height)
            z: (tNorm - 0.5) * 2  // -1 to 1
        });
      }
      mesh.push(row);
    }
    return mesh;
  };

  const project = (p: Point3D, width: number, height: number, rot: number): { x: number, y: number } => {
    // 1. Rotate around Y-axis
    const cos = Math.cos(rot);
    const sin = Math.sin(rot);

    const x1 = p.x * cos - p.z * sin;
    const z1 = p.x * sin + p.z * cos;

    // 2. Add perspective
    // Tilt camera slightly up (rotate X)
    const tilt = 0.5; 
    const y2 = p.y * Math.cos(tilt) - z1 * Math.sin(tilt);
    const z2 = p.y * Math.sin(tilt) + z1 * Math.cos(tilt);

    const fov = 1.5;
    const distance = 2.5;
    const scale = (fov / (distance + z2)) * (Math.min(width, height) / 2);

    return {
        x: x1 * scale + width / 2,
        y: -y2 * scale + height / 2 // Invert Y for canvas
    };
  };

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const width = canvas.width;
    const height = canvas.height;

    // Clear
    ctx.clearRect(0, 0, width, height);

    // Generate Mesh based on current props
    const mesh = generateMesh();

    // Draw Settings
    ctx.lineWidth = 1;
    ctx.lineJoin = 'round';

    // Draw Grid
    for (let i = 0; i < mesh.length; i++) {
      for (let j = 0; j < mesh[i].length; j++) {
        const p = mesh[i][j];
        const projP = project(p, width, height, rotation);

        // Draw Line to Right Neighbor (Spot Price Axis)
        if (j < mesh[i].length - 1) {
            const right = mesh[i][j+1];
            const projRight = project(right, width, height, rotation);

            ctx.beginPath();
            ctx.moveTo(projP.x, projP.y);
            ctx.lineTo(projRight.x, projRight.y);

            // Color based on height (Price)
            const heightVal = (p.y + 1) / 2; // 0 to 1
            ctx.strokeStyle = `hsla(${240 - (heightVal * 240)}, 100%, 60%, 0.6)`; // Blue to Red heatmap
            ctx.stroke();
        }

        // Draw Line to Bottom Neighbor (Time Axis)
        if (i < mesh.length - 1) {
            const bottom = mesh[i+1][j];
            const projBottom = project(bottom, width, height, rotation);

            ctx.beginPath();
            ctx.moveTo(projP.x, projP.y);
            ctx.lineTo(projBottom.x, projBottom.y);

            // Color based on height
            const heightVal = (p.y + 1) / 2;
            ctx.strokeStyle = `hsla(${240 - (heightVal * 240)}, 100%, 60%, 0.6)`;
            ctx.stroke();
        }
      }
    }

    // Draw Axes Labels (Simplified billboards)
    // We project specific points to find where to put text
    ctx.fillStyle = '#94a3b8';
    ctx.font = '10px monospace';

    // Origin (Low Price, Low Time)
    const origin = project({x: -1, y: -1, z: -1}, width, height, rotation);
    // ctx.fillText("Origin", origin.x, origin.y);

    // Spot Axis End
    const spotEnd = project({x: 1, y: -1, z: -1}, width, height, rotation);
    ctx.fillText("Spot Price ($)", spotEnd.x, spotEnd.y);

    // Time Axis End
    const timeEnd = project({x: -1, y: -1, z: 1}, width, height, rotation);
    ctx.fillText("Time (DTE)", timeEnd.x, timeEnd.y);

    // Value Axis Top
    const valTop = project({x: -1, y: 1, z: -1}, width, height, rotation);
    ctx.fillText("Option Value", valTop.x, valTop.y - 10);

  };

  useEffect(() => {
    const loop = () => {
        setRotation(r => r + 0.005); // Auto rotate
        animationRef.current = requestAnimationFrame(loop);
    };
    loop();
    return () => cancelAnimationFrame(animationRef.current);
  }, []);

  useEffect(() => {
      draw();
  }, [rotation, volatility, riskFreeRate, isCall]); // Redraw on frame or prop change

  return (
    <div className="relative w-full h-full bg-slate-950/80 rounded-xl overflow-hidden border border-white/5 shadow-inner">
        <canvas 
            ref={canvasRef} 
            width={800} 
            height={500} 
            className="w-full h-full object-contain"
        />

        {/* Overlay UI */}
        <div className="absolute top-4 left-4 pointer-events-none">
            <h4 className="text-white font-bold text-lg flex items-center gap-2">
                <Maximize className="w-4 h-4 text-indigo-400" />
                Pricing Surface
            </h4>
            <p className="text-xs text-slate-400">
                Visualizing <span className="text-indigo-300">Black-Scholes</span> Model
            </p>
        </div>

        <div className="absolute bottom-4 right-4 flex items-center gap-2 text-[10px] text-slate-500 bg-black/40 px-2 py-1 rounded backdrop-blur-sm">
            <RefreshCw className="w-3 h-3 animate-spin" />
            Live Rendering
        </div>
    </div>
  );
};

