const TickerTape = () => {
  const [quotes, setQuotes] = useState<StockQuote[]>([]);
  const tickers = ['SPY', 'QQQ', 'IWM', 'NVDA', 'TSLA', 'AAPL', 'AMD', 'MSFT', 'AMZN', 'GOOGL'];

  useEffect(() => {
    const loadQuotes = async () => {
      // Fetch all quotes in parallel
      const promises = tickers.map(t => fetchStockQuote(t));
      try {
        const results = await Promise.all(promises);
        setQuotes(results);
      } catch (error) {
        console.error("Failed to load ticker tape data", error);
      }
    };

    loadQuotes();
    // Refresh every 30 seconds
    const interval = setInterval(loadQuotes, 30000);
    return () => clearInterval(interval);
  }, []);

  const displayItems = quotes.length > 0 ? quotes : tickers.map(t => ({ 
      symbol: t, 
      price: 0, 
      changePercent: 0 
  } as StockQuote));

  return (
    <div className="w-full bg-slate-950 border-b border-white/5 overflow-hidden py-1.5 flex items-center h-[34px]">
      <div className="whitespace-nowrap animate-marquee flex items-center gap-8 text-xs font-mono font-medium opacity-70">
         {/* Original List */}
         {displayItems.map((item, i) => (
           <span key={i} className="flex items-center gap-2 text-slate-400">
             <span className="text-white font-bold">{item.symbol}</span>
             <span>${item.price > 0 ? item.price.toFixed(2) : '---'}</span>
             <span className={item.changePercent >= 0 ? 'text-emerald-400' : 'text-rose-400'}>
               {item.changePercent > 0 ? '+' : ''}{item.changePercent.toFixed(2)}%
             </span>
             {item.source?.includes('Simulation') && (
                 <span title="Simulated Data - Network Error">
                   <AlertTriangle className="w-3 h-3 text-rose-500 animate-pulse" />
                 </span>
             )}
           </span>
         ))}
         {/* Duplicate for seamless loop */}
         {displayItems.map((item, i) => (
           <span key={`dup-${i}`} className="flex items-center gap-2 text-slate-400">
             <span className="text-white font-bold">{item.symbol}</span>
             <span>${item.price > 0 ? item.price.toFixed(2) : '---'}</span>
             <span className={item.changePercent >= 0 ? 'text-emerald-400' : 'text-rose-400'}>
               {item.changePercent > 0 ? '+' : ''}{item.changePercent.toFixed(2)}%
             </span>
           </span>
         ))}
      </div>
    </div>
  );
};

