                           msg.role === 'user' 
                           ? 'bg-indigo-600 text-white rounded-br-none shadow-[0_0_20px_-5px_rgba(79,70,229,0.3)]' 
                           : 'bg-slate-900/60 border border-white/5 text-slate-300 rounded-bl-none'
