function generateSimulatedQuote(ticker, source = 'Simulation') {
    const hash = ticker.split('').reduce((acc, char) => acc + char.charCodeAt(0), 0);
    const basePrice = (hash % 500) + 50; 

    return {
      symbol: ticker,
      price: basePrice + (Math.random() * 5),
      change: 1.25,
      changePercent: 0.85,
      source: source
    };
}

