                                           <td className="p-4 font-mono text-amber-400 font-medium">
                                               {log.durationMinutes} min
                                           </td>
                                           <td className="p-4 text-slate-500 text-xs font-mono">
                                                {log.ipAddress || 'Unknown'}
                                           </td>
                                           <td className="p-4">
                                               {isOnline ? (
                                                   <span className="inline-flex items-center gap-1.5 px-2 py-0.5 rounded-full bg-emerald-500/10 text-emerald-400 text-[10px] font-bold uppercase border border-emerald-500/20">
                                                       <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span> Online
                                                   </span>
                                               ) : (
                                                   <span className="text-slate-600 text-[10px] uppercase font-bold">Offline</span>
                                               )}
                                           </td>
                                       </tr>
                                   );
                               })}
                           </tbody>
                       </table>
                   ) : (
                       <table className="w-full text-left border-collapse">
                           <thead>
                               <tr className="bg-slate-950 text-[10px] uppercase font-bold text-slate-500 border-b border-white/5">
                                   <th className="p-4">Callsign</th>
                                   <th className="p-4">Secure Email</th>
                                   <th className="p-4">Registration Date</th>
                                   <th className="p-4">Reg IP</th>
                               </tr>
                           </thead>
                           <tbody className="divide-y divide-white/5 text-sm text-slate-300">
                               {loading ? (
                                   <tr><td colSpan={4} className="p-8 text-center text-slate-500">Loading Registry...</td></tr>
                               ) : users.map((u, idx) => (
                                   <tr key={idx} className="hover:bg-white/5 transition-colors">
                                       <td className="p-4 font-mono font-bold text-white">{u.username}</td>
                                       <td className="p-4 font-mono text-slate-400">{u.email}</td>
                                       <td className="p-4 text-slate-500 text-xs">{new Date(u.created_at).toLocaleString()}</td>
                                       <td className="p-4 text-slate-500 text-xs font-mono">{u.ipAddress || 'Unknown'}</td>
                                   </tr>
                               ))}
                           </tbody>
                       </table>
                   )}
               </div>
           </div>
       )}
    </div>
  );
};

export default AdminDashboard;

import React, { useRef, useEffect, useState } from 'react';
import { calculateBlackScholes } from '../services/marketDataService';
import { RefreshCw, Maximize, HelpCircle, Eye, Info, DollarSign, Layers } from 'lucide-react';

interface Point3D {
  x: number;
  y: number;
  z: number;
  price: number; // Store raw price for PnL calc
}

interface SurfaceProps {
  volatility: number;
  riskFreeRate: number;
  isCall: boolean;
  strikePrice?: number;
}

const VolatilitySurface: React.FC<SurfaceProps> = ({ volatility, riskFreeRate, isCall, strikePrice = 100 }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [rotation, setRotation] = useState(0);
  const [showGuides, setShowGuides] = useState(true);
  const [showPnL, setShowPnL] = useState(false); // Toggle PnL Visualization
  const animationRef = useRef<number>(0);

  // Dynamic Configuration based on Strike
  const gridResolution = 24; 

  // Center range: 60% to 140% of strike
  const spotRange = { 
      min: strikePrice * 0.6, 
      max: strikePrice * 1.4 
  }; 

  const timeRange = { min: 0.05, max: 1.0 }; // 18 days to 1 year

  // Generate the Mesh Data
  const generateMesh = (): Point3D[][] => {
    const mesh: Point3D[][] = [];
    const heightScale = strikePrice * 0.4; 

    for (let i = 0; i <= gridResolution; i++) {
      const row: Point3D[] = [];
      // Z-Axis: Time (Normalized 0 to 1)
      const tNorm = i / gridResolution;
      const t = timeRange.min + (timeRange.max - timeRange.min) * tNorm;

      for (let j = 0; j <= gridResolution; j++) {
        // X-Axis: Spot Price (Normalized 0 to 1)
        const sNorm = j / gridResolution;
        const s = spotRange.min + (spotRange.max - spotRange.min) * sNorm;

        // Y-Axis: Option Price
        const price = calculateBlackScholes(
            isCall ? 'call' : 'put',
            s,
            strikePrice,
            t,
            riskFreeRate,
            volatility
        );

        const yNorm = price / heightScale;

        row.push({
            x: (sNorm - 0.5) * 2, // -1 to 1
            y: Math.min(Math.max((yNorm - 0.5) * 2, -1.5), 1.5), 
            z: (tNorm - 0.5) * 2,  // -1 to 1
            price: price
        });
      }
      mesh.push(row);
    }
    return mesh;
  };

  const project = (p: Point3D, width: number, height: number, rot: number): { x: number, y: number, scale: number } => {
    // 1. Rotate around Y-axis
    const cos = Math.cos(rot);
    const sin = Math.sin(rot);

    const x1 = p.x * cos - p.z * sin;
    const z1 = p.x * sin + p.z * cos;

    // 2. Add perspective tilt
    const tilt = 0.5; 
    const y2 = p.y * Math.cos(tilt) - z1 * Math.sin(tilt);
    const z2 = p.y * Math.sin(tilt) + z1 * Math.cos(tilt);

    const fov = 1.5;
    const distance = 2.5;
    const scale = (fov / (distance + z2)) * (Math.min(width, height) / 2);

    return {
        x: x1 * scale + width / 2,
        y: -y2 * scale + height / 2,
        scale: scale
    };
  };

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const width = canvas.width;
    const height = canvas.height;

    // Clear
    ctx.clearRect(0, 0, width, height);

    // Generate Mesh
    const mesh = generateMesh();

    // Calculate Entry Price (Basis for PnL)
    // Assume entry at ATM today (Strike Price, T=Max)
    const entryPrice = calculateBlackScholes(
        isCall ? 'call' : 'put', 
        strikePrice, 
        strikePrice, 
        timeRange.max, 
        riskFreeRate, 
        volatility
    );
    const heightScale = strikePrice * 0.4;
    const entryYNorm = entryPrice / heightScale;
    const entryY = (entryYNorm - 0.5) * 2;

    ctx.lineJoin = 'round';

    // Helper to draw text with background
    const drawLabel = (text: string, x: number, y: number, color: string = '#94a3b8', bg: boolean = false) => {
        ctx.font = 'bold 11px monospace';
        if (bg) {
            const metrics = ctx.measureText(text);
            ctx.fillStyle = 'rgba(0,0,0,0.8)';
            ctx.fillRect(x - 4, y - 11, metrics.width + 8, 16);
        }
        ctx.fillStyle = color;
        ctx.fillText(text, x, y);
    };

    // --- DRAW BREAK-EVEN PLANE (PnL Mode) ---
    if (showPnL) {
        const p1 = { x: -1, y: entryY, z: -1, price: 0 };
        const p2 = { x: 1, y: entryY, z: -1, price: 0 };
        const p3 = { x: 1, y: entryY, z: 1, price: 0 };
        const p4 = { x: -1, y: entryY, z: 1, price: 0 };

        const pp1 = project(p1, width, height, rotation);
        const pp2 = project(p2, width, height, rotation);
        const pp3 = project(p3, width, height, rotation);
        const pp4 = project(p4, width, height, rotation);

        ctx.beginPath();
        ctx.moveTo(pp1.x, pp1.y);
        ctx.lineTo(pp2.x, pp2.y);
        ctx.lineTo(pp3.x, pp3.y);
        ctx.lineTo(pp4.x, pp4.y);
        ctx.closePath();
        ctx.fillStyle = 'rgba(255, 255, 255, 0.05)';
        ctx.fill();
        ctx.strokeStyle = 'rgba(255, 255, 255, 0.2)';
        ctx.setLineDash([5, 5]);
        ctx.stroke();
        ctx.setLineDash([]);

        // Cost Basis Label
        const centerPlane = project({x: 0, y: entryY, z: 0, price: 0}, width, height, rotation);
        drawLabel(`COST BASIS: $${entryPrice.toFixed(2)}`, centerPlane.x, centerPlane.y, '#ffffff', true);
    }

    // --- DRAW MESH ---
    for (let i = 0; i < mesh.length; i++) {
      for (let j = 0; j < mesh[i].length; j++) {
        const p = mesh[i][j];
        const projP = project(p, width, height, rotation);

        // Check if this point is on the Strike Line
        const isStrikeLine = j === gridResolution / 2;

        // Draw Line to Right (Spot Axis)
        if (j < mesh[i].length - 1) {
            const right = mesh[i][j+1];
            const projRight = project(right, width, height, rotation);

            ctx.beginPath();
            ctx.moveTo(projP.x, projP.y);
            ctx.lineTo(projRight.x, projRight.y);

            if (showPnL) {
                // PnL Coloring
                const isProfit = p.price > entryPrice;
                const alpha = Math.min(Math.abs(p.price - entryPrice) / (entryPrice * 0.5), 1); // Opacity based on magnitude
                if (isProfit) {
                    ctx.strokeStyle = `rgba(16, 185, 129, ${0.2 + alpha * 0.8})`; // Emerald
                } else {
                    ctx.strokeStyle = `rgba(244, 63, 94, ${0.2 + alpha * 0.8})`; // Rose
                }
                ctx.lineWidth = 1.5;
            } else {
                // Standard Price Coloring (Heatmap style)
                const heightVal = (p.y + 1) / 2; 
                ctx.strokeStyle = `hsla(${240 - (heightVal * 200)}, 90%, 60%, 0.4)`; 
                ctx.lineWidth = 1;
            }
            ctx.stroke();
        }

        // Draw Line to Bottom (Time Axis)
        if (i < mesh.length - 1) {
            const bottom = mesh[i+1][j];
            const projBottom = project(bottom, width, height, rotation);

            ctx.beginPath();
            ctx.moveTo(projP.x, projP.y);
            ctx.lineTo(projBottom.x, projBottom.y);

            if (showPnL) {
                const isProfit = p.price > entryPrice;
                const alpha = Math.min(Math.abs(p.price - entryPrice) / (entryPrice * 0.5), 1);
                ctx.strokeStyle = isProfit ? `rgba(16, 185, 129, ${0.1 + alpha * 0.4})` : `rgba(244, 63, 94, ${0.1 + alpha * 0.4})`;
                ctx.lineWidth = 1;
            } else {
                ctx.lineWidth = isStrikeLine && showGuides ? 2 : 1;
                if (isStrikeLine && showGuides) {
                    ctx.strokeStyle = '#ffffff'; 
                    ctx.setLineDash([2, 2]);
                } else {
                    const heightVal = (p.y + 1) / 2;
                    ctx.strokeStyle = `hsla(${240 - (heightVal * 200)}, 90%, 60%, 0.4)`;
                    ctx.setLineDash([]);
                }
            }

            ctx.stroke();
            ctx.setLineDash([]);
        }
      }
    }

    // --- CUES & LABELS ---
    if (showGuides) {
        // 1. Strike Line Label
        const topStrikePt = project(mesh[mesh.length-1][gridResolution/2], width, height, rotation);
        drawLabel("STRIKE PRICE", topStrikePt.x - 30, topStrikePt.y - 15, '#ffffff', true);

        // 2. Zones
        const itmPt = project({x: (isCall ? 0.6 : -0.6), y: -1.2, z: 0, price: 0}, width, height, rotation);
        const otmPt = project({x: (isCall ? -0.6 : 0.6), y: -1.2, z: 0, price: 0}, width, height, rotation);

        drawLabel(isCall ? "ITM (Deep Value)" : "OTM (Lotto)", itmPt.x - 40, itmPt.y, '#10b981');
        drawLabel(isCall ? "OTM (Lotto)" : "ITM (Deep Value)", otmPt.x - 40, otmPt.y, '#f43f5e');

        // 3. Time Labels
        const todayPt = project({x: -1.2, y: -1, z: 1, price: 0}, width, height, rotation);
        const expiryPt = project({x: -1.2, y: -1, z: -1, price: 0}, width, height, rotation);

        drawLabel("TODAY", todayPt.x, todayPt.y, '#fbbf24');
        drawLabel("EXPIRY", expiryPt.x, expiryPt.y, '#fbbf24');

        ctx.beginPath();
        ctx.moveTo(todayPt.x + 10, todayPt.y + 5);
        ctx.lineTo(expiryPt.x + 10, expiryPt.y + 5);
        ctx.strokeStyle = '#fbbf24';
        ctx.lineWidth = 1;
        ctx.stroke();
    }
  };

  useEffect(() => {
    const loop = () => {
        setRotation(r => r + 0.002); 
        animationRef.current = requestAnimationFrame(loop);
    };
    loop();
    return () => cancelAnimationFrame(animationRef.current);
  }, []);

  useEffect(() => {
      draw();
  }, [rotation, volatility, riskFreeRate, isCall, strikePrice, showGuides, showPnL]); 

  return (
    <div className="relative w-full h-full bg-slate-950/80 rounded-xl overflow-hidden border border-white/5 shadow-inner">
        <canvas 
            ref={canvasRef} 
            width={800} 
            height={500} 
            className="w-full h-full object-contain"
        />

        {/* Overlay Controls */}
        <div className="absolute top-4 left-4 pointer-events-none">
            <h4 className="text-white font-bold text-lg flex items-center gap-2">
                <Maximize className="w-4 h-4 text-indigo-400" />
                3D Pricing Surface
            </h4>
            <div className="flex items-center gap-2 mt-1">
                 <span className={`px-1.5 py-0.5 rounded text-[10px] font-bold uppercase ${isCall ? 'bg-emerald-500/20 text-emerald-400' : 'bg-rose-500/20 text-rose-400'}`}>
                    {isCall ? 'CALL' : 'PUT'}
                 </span>
                 <span className="text-xs text-slate-400">
                    Strike: <span className="text-white font-mono">${strikePrice}</span>
                 </span>
            </div>
        </div>

        {/* Decoder Overlay */}
        <div className="absolute top-4 right-4 flex flex-col items-end gap-2">
            <div className="flex gap-2">
                <button 
                    onClick={() => setShowPnL(!showPnL)}
                    className={`flex items-center gap-2 px-3 py-1.5 rounded-lg border text-xs font-bold uppercase transition-all ${showPnL ? 'bg-emerald-600 border-emerald-500 text-white shadow-[0_0_15px_rgba(16,185,129,0.4)]' : 'bg-black/40 border-white/10 text-slate-400 hover:text-white'}`}
                >
                    <DollarSign className="w-3.5 h-3.5" />
                    {showPnL ? 'PnL Heatmap' : 'Price Map'}
                </button>
                <button 
                    onClick={() => setShowGuides(!showGuides)}
                    className={`flex items-center gap-2 px-3 py-1.5 rounded-lg border text-xs font-bold uppercase transition-all ${showGuides ? 'bg-indigo-600 border-indigo-500 text-white' : 'bg-black/40 border-white/10 text-slate-400 hover:text-white'}`}
                >
                    <Eye className="w-3.5 h-3.5" />
                    Guides
                </button>
            </div>

            <div className="bg-slate-900/90 backdrop-blur-md border border-white/10 p-4 rounded-xl w-64 mt-2 animate-fade-in text-xs shadow-2xl transition-all">
                <h5 className="text-indigo-300 font-bold mb-3 flex items-center gap-2">
                    <Info className="w-3.5 h-3.5" /> Surface Decoder
                </h5>

                <div className="space-y-3">
                    <div className="flex gap-3">
                        {showPnL ? (
                            <div className="w-1 bg-gradient-to-b from-emerald-500 via-slate-500 to-rose-500 rounded-full"></div>
                        ) : (
                            <div className="w-1 bg-gradient-to-b from-rose-500 to-indigo-500 rounded-full"></div>
                        )}
                        <div>
                            <span className="text-white font-bold block">{showPnL ? 'Color = Profit/Loss' : 'Height = Price'}</span>
                            <p className="text-slate-400 leading-tight">
                                {showPnL 
                                    ? "Green peaks are profit (ITM). Red valleys are loss (OTM)." 
                                    : "The taller the mountain, the more expensive the option."}
                            </p>
                        </div>
                    </div>

                    <div className="flex gap-3">
                        <div className="w-1 bg-white border-l border-dashed border-slate-500"></div>
                        <div>
                            <span className="text-white font-bold block">Dotted Line = Strike</span>
                            <p className="text-slate-400 leading-tight">
                                The "Equator". If stock price crosses this, you start winning (ITM).
                            </p>
                        </div>
                    </div>

                    <div className="flex gap-3">
                        <div className="w-1 bg-gradient-to-b from-amber-400 to-transparent rounded-full"></div>
                        <div>
                            <span className="text-white font-bold block">Slope = Time Decay</span>
                            <p className="text-slate-400 leading-tight">
                                Notice the hill sliding down? That's your money vanishing as days pass.
                            </p>
                        </div>
                    </div>
                </div>
            </div>
        </div>

        <div className="absolute bottom-4 right-4 flex items-center gap-2 text-[10px] text-slate-500 bg-black/40 px-2 py-1 rounded backdrop-blur-sm border border-white/5">
            <RefreshCw className="w-3 h-3 animate-spin" />
            Rendering 24x24 Mesh
        </div>
    </div>
  );
};

export default VolatilitySurface;

import React, { useRef, useEffect, useState } from 'react';
import { calculateBlackScholes } from '../services/marketDataService';
import { Maximize, Eye, Info, DollarSign, Target, Pause, Play, ScanLine, Crosshair } from 'lucide-react';

interface Point3D {
  x: number;
  y: number;
  z: number;
  price: number;
  spot: number;
  time: number;
}

interface SurfaceProps {
  volatility: number;
  riskFreeRate: number;
  isCall: boolean;
  strikePrice?: number;
}

const VolatilitySurface: React.FC<SurfaceProps> = ({ volatility, riskFreeRate, isCall, strikePrice = 100 }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // Animation State
  const [rotation, setRotation] = useState(0.5);
  const [isScanning, setIsScanning] = useState(true);
  const [scanPos, setScanPos] = useState({ x: 0.5, z: 0.5 }); // Normalized 0-1 coordinates for scanner

  // View Modes
  const [showPnL, setShowPnL] = useState(false);
  const [showGuides, setShowGuides] = useState(true);

  // Data for HUD
  const [hudData, setHudData] = useState<{price: number, pnl: number, spot: number, daysLeft: number} | null>(null);

  const animationRef = useRef<number>(0);
  const timeRef = useRef<number>(0);

  // Constants
  const GRID_RES = 30;
  const SPOT_RANGE = { min: strikePrice * 0.7, max: strikePrice * 1.3 };
  const TIME_RANGE = { min: 0.02, max: 1.0 }; // ~1 week to 1 year

  // Calculate Entry Price (Cost Basis) - ATM option with max time
  const entryPrice = calculateBlackScholes(
      isCall ? 'call' : 'put', 
      strikePrice, 
      strikePrice, 
      TIME_RANGE.max, 
      riskFreeRate, 
      volatility
  );

  const generateMesh = (): Point3D[][] => {
    const mesh: Point3D[][] = [];
    const heightScale = strikePrice * 0.3; // Scale height for visibility

    for (let i = 0; i <= GRID_RES; i++) {
      const row: Point3D[] = [];
      const tNorm = i / GRID_RES;
      const t = TIME_RANGE.min + (TIME_RANGE.max - TIME_RANGE.min) * tNorm; // Time axis (Back to Front)

      for (let j = 0; j <= GRID_RES; j++) {
        const sNorm = j / GRID_RES;
        const s = SPOT_RANGE.min + (SPOT_RANGE.max - SPOT_RANGE.min) * sNorm; // Spot axis (Left to Right)

        const price = calculateBlackScholes(
            isCall ? 'call' : 'put',
            s,
            strikePrice,
            t,
            riskFreeRate,
            volatility
        );

        // Map to 3D Space (-1 to 1)
        row.push({
            x: (sNorm - 0.5) * 2, 
            y: (price / heightScale) - 0.5, // Lift up slightly
            z: (tNorm - 0.5) * 2,
            price,
            spot: s,
            time: t
        });
      }
      mesh.push(row);
    }
    return mesh;
  };

  const project = (p: Point3D, width: number, height: number, rot: number): { x: number, y: number, scale: number, zDepth: number } => {
    const cos = Math.cos(rot);
    const sin = Math.sin(rot);

    // Rotate Y
    const x1 = p.x * cos - p.z * sin;
    const z1 = p.x * sin + p.z * cos;

    // Tilt X (Perspective)
    const tilt = 0.6; 
    const y2 = p.y * Math.cos(tilt) - z1 * Math.sin(tilt);
    const z2 = p.y * Math.sin(tilt) + z1 * Math.cos(tilt);

    const fov = 1.8;
    const distance = 3.0;
    const scale = (fov / (distance + z2)) * (Math.min(width, height) / 2.2);

    return {
        x: x1 * scale + width / 2,
        y: -y2 * scale + height / 2 + 20, // Offset Y slightly down
        scale: scale,
        zDepth: z2
    };
  };

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // High DPI fix
    const dpr = window.devicePixelRatio || 1;
    const rect = canvas.getBoundingClientRect();
    canvas.width = rect.width * dpr;
    canvas.height = rect.height * dpr;
    ctx.scale(dpr, dpr);
    const width = rect.width;
    const height = rect.height;

    // Clear
    ctx.clearRect(0, 0, width, height);

    const mesh = generateMesh();

    // Calculate Scanner Indices
    const scanIndexX = Math.floor(scanPos.x * GRID_RES);
    const scanIndexZ = Math.floor(scanPos.z * GRID_RES);

    // --- 1. Draw Floor (Strike Plane / Break Even) ---
    // Cost Basis Plane Height
    const heightScale = strikePrice * 0.3;
    const basisY = (entryPrice / heightScale) - 0.5;

    // Helper to draw lines
    const drawLine = (p1: Point3D, p2: Point3D, color: string, width: number = 1, dash: number[] = []) => {
        const pp1 = project(p1, width, height, rotation);
        const pp2 = project(p2, width, height, rotation);
        ctx.beginPath();
        ctx.moveTo(pp1.x, pp1.y);
        ctx.lineTo(pp2.x, pp2.y);
        ctx.strokeStyle = color;
        ctx.lineWidth = width;
        ctx.setLineDash(dash);
        ctx.stroke();
        ctx.setLineDash([]);
    };

    // Draw Cost Basis Plane
    if (showPnL) {
        const planeColor = 'rgba(255, 255, 255, 0.1)';
        const p1 = { x: -1, y: basisY, z: -1, price: 0, spot: 0, time: 0 };
        const p2 = { x: 1, y: basisY, z: -1, price: 0, spot: 0, time: 0 };
        const p3 = { x: 1, y: basisY, z: 1, price: 0, spot: 0, time: 0 };
        const p4 = { x: -1, y: basisY, z: 1, price: 0, spot: 0, time: 0 };

        const pp1 = project(p1, width, height, rotation);
        const pp2 = project(p2, width, height, rotation);
        const pp3 = project(p3, width, height, rotation);
        const pp4 = project(p4, width, height, rotation);

        ctx.beginPath();
        ctx.moveTo(pp1.x, pp1.y);
        ctx.lineTo(pp2.x, pp2.y);
        ctx.lineTo(pp3.x, pp3.y);
        ctx.lineTo(pp4.x, pp4.y);
        ctx.closePath();
        ctx.fillStyle = 'rgba(79, 70, 229, 0.05)'; // Indigo tint
        ctx.fill();
        ctx.strokeStyle = 'rgba(255, 255, 255, 0.15)';
        ctx.stroke();
    }

    // --- 2. Draw Mesh ---
    for (let i = 0; i < mesh.length; i++) {
        for (let j = 0; j < mesh[i].length; j++) {
            const p = mesh[i][j];
            const pp = project(p, width, height, rotation);

            // Determine Color based on Height/PnL
            let strokeStyle = `hsla(${240 - ((p.y + 0.5) * 120)}, 80%, 60%, 0.3)`; // Heatmap default
            if (showPnL) {
                const pnl = p.price - entryPrice;
                const opacity = 0.2 + Math.min(Math.abs(pnl) / (entryPrice), 0.8);
                if (pnl >= 0) strokeStyle = `rgba(16, 185, 129, ${opacity})`; // Green
                else strokeStyle = `rgba(244, 63, 94, ${opacity})`; // Red
            }

            // Highlight Scanner Lines
            const isScannedRow = i === scanIndexZ;
            const isScannedCol = j === scanIndexX;

            if (isScannedRow || isScannedCol) {
                ctx.lineWidth = 2;
                ctx.strokeStyle = 'rgba(255, 255, 255, 0.8)';
                strokeStyle = 'rgba(255, 255, 255, 0.5)';
            } else {
                ctx.lineWidth = 1;
            }

            // Draw X-segments
            if (j < mesh[i].length - 1) {
                const right = mesh[i][j+1];
                const pr = project(right, width, height, rotation);
                ctx.beginPath();
                ctx.moveTo(pp.x, pp.y);
                ctx.lineTo(pr.x, pr.y);
                ctx.strokeStyle = strokeStyle;
                ctx.stroke();
            }
            // Draw Z-segments
            if (i < mesh.length - 1) {
                const bottom = mesh[i+1][j];
                const pb = project(bottom, width, height, rotation);
                ctx.beginPath();
                ctx.moveTo(pp.x, pp.y);
                ctx.lineTo(pb.x, pb.y);
                ctx.strokeStyle = strokeStyle;
                ctx.stroke();
            }
        }
    }

    // --- 3. Draw Scanner & Data Points ---
    const scanPoint = mesh[scanIndexZ][scanIndexX];
    const projScan = project(scanPoint, width, height, rotation);

    // Update React State for HUD
    const pnlVal = scanPoint.price - entryPrice;
    const daysLeft = Math.floor(scanPoint.time * 365);
    setHudData({
        price: scanPoint.price,
        pnl: pnlVal,
        spot: scanPoint.spot,
        daysLeft: daysLeft
    });

    // Draw Scanner Vertical Drop Line (The "Pole")
    const floorY = -0.5; // Visual bottom
    const floorPoint = { ...scanPoint, y: floorY };
    const projFloor = project(floorPoint, width, height, rotation);

    // Gradient Line
    const grad = ctx.createLinearGradient(projScan.x, projScan.y, projFloor.x, projFloor.y);
    grad.addColorStop(0, 'rgba(255, 255, 255, 1)');
    grad.addColorStop(1, 'rgba(255, 255, 255, 0)');

    ctx.beginPath();
    ctx.moveTo(projScan.x, projScan.y);
    ctx.lineTo(projFloor.x, projFloor.y);
    ctx.strokeStyle = grad;
    ctx.lineWidth = 2;
    ctx.setLineDash([2, 2]);
    ctx.stroke();
    ctx.setLineDash([]);

    // Draw PnL Difference Line (if PnL mode)
    if (showPnL) {
        const basisPoint = { ...scanPoint, y: basisY };
        const projBasis = project(basisPoint, width, height, rotation);

        ctx.beginPath();
        ctx.moveTo(projScan.x, projScan.y);
        ctx.lineTo(projBasis.x, projBasis.y);
        ctx.lineWidth = 3;
        ctx.strokeStyle = pnlVal >= 0 ? '#10b981' : '#f43f5e'; // Green/Red thick line
        ctx.stroke();

        // Little dot at basis intersection
        ctx.beginPath();
        ctx.arc(projBasis.x, projBasis.y, 3, 0, Math.PI * 2);
        ctx.fillStyle = pnlVal >= 0 ? '#10b981' : '#f43f5e';
        ctx.fill();
    }

    // Draw Glowing Orb at Scan Point
    ctx.beginPath();
    ctx.arc(projScan.x, projScan.y, 5, 0, Math.PI * 2);
    ctx.fillStyle = '#ffffff';
    ctx.fill();
    // Glow ring
    ctx.beginPath();
    ctx.arc(projScan.x, projScan.y, 12, 0, Math.PI * 2);
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.4)';
    ctx.lineWidth = 1;
    ctx.stroke();

    // Floating Label next to point
    const labelX = projScan.x + 15;
    const labelY = projScan.y - 15;

    ctx.fillStyle = 'rgba(15, 23, 42, 0.8)'; // Dark BG
    ctx.fillRect(labelX, labelY - 12, 80, 40);
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.2)';
    ctx.strokeRect(labelX, labelY - 12, 80, 40);

    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 12px monospace';
    ctx.fillText(`$${scanPoint.price.toFixed(2)}`, labelX + 8, labelY + 2);

    ctx.font = '10px monospace';
    ctx.fillStyle = pnlVal >= 0 ? '#34d399' : '#fb7185';
    ctx.fillText(`${pnlVal >= 0 ? '+' : ''}${pnlVal.toFixed(2)} P/L`, labelX + 8, labelY + 16);

    // --- 4. Draw Labels/Guides ---
    if (showGuides) {
        // Strike Line
        const strikeP = { x: 0, y: -0.5, z: 0, price: 0, spot: 0, time: 0 }; // Center
        const strikePFront = { x: 0, y: -0.5, z: 1, price: 0, spot: 0, time: 0 };
        const strikePBack = { x: 0, y: -0.5, z: -1, price: 0, spot: 0, time: 0 };
        drawLine(strikePFront, strikePBack, 'rgba(255, 255, 255, 0.2)', 1, [5, 5]);

        const projStrike = project(strikeP, width, height, rotation);
        ctx.fillStyle = '#94a3b8';
        ctx.font = '10px sans-serif';
        ctx.fillText(`STRIKE $${strikePrice}`, projStrike.x - 30, projStrike.y + 40);
    }

  };

  useEffect(() => {
    const loop = () => {
        timeRef.current += 0.01;

        // Auto-Rotate
        setRotation(r => r + 0.001); 

        // Auto-Scan Logic
        if (isScanning) {
            setScanPos({
                x: 0.5 + Math.sin(timeRef.current * 0.5) * 0.45, // Oscillate Spot
                z: 0.5 + Math.cos(timeRef.current * 0.3) * 0.45  // Oscillate Time
            });
        }

        draw();
        animationRef.current = requestAnimationFrame(loop);
    };
    loop();
    return () => cancelAnimationFrame(animationRef.current);
  }, [rotation, volatility, riskFreeRate, isCall, strikePrice, showGuides, showPnL, isScanning]); 

  return (
    <div className="relative w-full h-full bg-slate-950/80 rounded-xl overflow-hidden border border-white/5 shadow-inner group">
        <canvas 
            ref={canvasRef} 
            className="w-full h-full object-cover cursor-crosshair"
            style={{ width: '100%', height: '100%' }}
        />

        {/* Holographic HUD Overlay */}
        {hudData && (
            <div className="absolute top-4 right-4 w-64 animate-fade-in pointer-events-none">
                <div className="bg-slate-900/90 backdrop-blur-xl border border-white/10 p-4 rounded-xl shadow-2xl relative overflow-hidden">
                    {/* Scanner Line Decorator */}
                    <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-indigo-500 via-purple-500 to-emerald-500 animate-pulse"></div>

                    <div className="flex justify-between items-start mb-3">
                        <h5 className="text-white font-bold text-sm flex items-center gap-2">
                            <Crosshair className="w-4 h-4 text-indigo-400 animate-spin-slow" />
                            Scanner Data
                        </h5>
                        <span className="text-[10px] text-slate-500 font-mono">{isScanning ? 'LIVE' : 'PAUSED'}</span>
                    </div>

                    <div className="grid grid-cols-2 gap-3 mb-3">
                        <div className="bg-slate-950/50 p-2 rounded-lg border border-white/5">
                            <div className="text-[9px] text-slate-400 uppercase font-bold mb-0.5">Option Price</div>
                            <div className="text-xl font-mono font-bold text-white tracking-tight">
                                ${hudData.price.toFixed(2)}
                            </div>
                        </div>
                        <div className="bg-slate-950/50 p-2 rounded-lg border border-white/5">
                            <div className="text-[9px] text-slate-400 uppercase font-bold mb-0.5">Est. P/L</div>
                            <div className={`text-xl font-mono font-bold tracking-tight ${hudData.pnl >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                                {hudData.pnl >= 0 ? '+' : ''}{hudData.pnl.toFixed(2)}
                            </div>
                        </div>
                    </div>

                    <div className="space-y-2">
                        <div className="flex justify-between items-center text-xs border-b border-white/5 pb-1">
                            <span className="text-slate-400">Spot Price</span>
                            <span className="font-mono text-amber-400">${hudData.spot.toFixed(2)}</span>
                        </div>
                        <div className="flex justify-between items-center text-xs border-b border-white/5 pb-1">
                            <span className="text-slate-400">Time to Expiry</span>
                            <span className="font-mono text-cyan-400">{hudData.daysLeft} Days</span>
                        </div>
                        <div className="flex justify-between items-center text-xs">
                            <span className="text-slate-400">Profitability</span>
                            <span className={`font-bold ${hudData.pnl > 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                                {hudData.pnl > 0 ? 'IN THE MONEY' : 'OUT OF MONEY'}
                            </span>
                        </div>
                    </div>
                </div>
            </div>
        )}

        {/* Top Left Controls */}
        <div className="absolute top-4 left-4 flex flex-col gap-2">
             <div className="bg-black/40 backdrop-blur-md p-2 rounded-lg border border-white/10">
                <h4 className="text-white font-bold text-xs flex items-center gap-2 mb-1">
                    <Maximize className="w-3 h-3 text-indigo-400" />
                    3D Visualizer
                </h4>
                <div className="flex items-center gap-2">
                    <span className={`text-[9px] px-1.5 py-0.5 rounded font-bold uppercase ${isCall ? 'bg-emerald-500/20 text-emerald-400' : 'bg-rose-500/20 text-rose-400'}`}>
                        {isCall ? 'CALL' : 'PUT'}
                    </span>
                    <span className="text-[10px] text-slate-400 font-mono">
                        ${strikePrice} Strike
                    </span>
                </div>
             </div>
        </div>

        {/* Bottom Toolbar */}
        <div className="absolute bottom-4 left-1/2 -translate-x-1/2 flex items-center gap-2 bg-slate-900/90 backdrop-blur-md p-1.5 rounded-xl border border-white/10 shadow-lg transition-opacity opacity-0 group-hover:opacity-100">
            <button 
                onClick={() => setIsScanning(!isScanning)}
                className="p-2 hover:bg-white/10 rounded-lg text-slate-300 hover:text-white transition-colors"
                title={isScanning ? "Pause Scanner" : "Resume Scanner"}
            >
                {isScanning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />}
            </button>
            <div className="w-px h-4 bg-white/10"></div>
            <button 
                onClick={() => setShowPnL(!showPnL)}
                className={`p-2 rounded-lg transition-colors ${showPnL ? 'bg-emerald-500/20 text-emerald-400' : 'text-slate-300 hover:text-white hover:bg-white/10'}`}
                title="Toggle PnL Heatmap"
            >
                <DollarSign className="w-4 h-4" />
            </button>
            <button 
                onClick={() => setShowGuides(!showGuides)}
                className={`p-2 rounded-lg transition-colors ${showGuides ? 'bg-indigo-500/20 text-indigo-400' : 'text-slate-300 hover:text-white hover:bg-white/10'}`}
                title="Toggle Guides"
            >
                <ScanLine className="w-4 h-4" />
            </button>
        </div>

    </div>
  );
};

