    };
};


// --- Backtesting Engine ---

const roundToStrike = (price: number): number => {
    return Math.round(price * 2) / 2;
};

const fetchHistoricalPrices = async (ticker: string, days: number = 252): Promise<{date: string, close: number}[]> => {
    try {
        const response = await fetch(`/api/history/${ticker}`);
        const data = await response.json();

        if (data && data.historical) {
            return data.historical.reverse().map((d: any) => ({
                date: d.date,
                close: d.close
            }));
        }
        throw new Error("No historical data");
    } catch (e) {
        console.warn("Historical fetch failed, using mock data", e);
        const mockData = [];
        let price = 100;
        const now = new Date();
        for(let i=days; i>0; i--) {
            const date = new Date(now);
            date.setDate(date.getDate() - i);
            price = price * (1 + (Math.random() * 0.04 - 0.018));
            mockData.push({
                date: date.toISOString().split('T')[0],
                close: price
            });
        }
        return mockData;
    }
};

export const runStrategyBacktest = async (
    ticker: string, 
    strategyType: 'Covered Call' | 'Long Call' | 'Short Put',
    customConfig?: { dte?: number, moneyness?: number }
): Promise<BacktestResult> => {
    const history = await fetchHistoricalPrices(ticker, 252); 
    if (history.length === 0) throw new Error("No Data");

    const equityCurve: EquityPoint[] = [];
    const trades: TradeLog[] = [];
    const initialCapital = 10000;
    let cash = initialCapital;
    let shares = 0;
    let optionPosition = null; 
    let tradeCount = 0;
    let wins = 0;
    let tradeId = 1;

    const initialPrice = history[0].close;
    const benchmarkShares = Math.floor(initialCapital / initialPrice);
    const benchmarkCash = initialCapital - (benchmarkShares * initialPrice);

    // Use Custom Config or Defaults
    const DTE = customConfig?.dte || 30; 
    const TARGET_MONEYNESS = customConfig?.moneyness || 1.0; // 1.0 = ATM
    const IV = 0.35; 
    const RISK_FREE = 0.05;

    for (let i = 0; i < history.length; i++) {
        const day = history[i];
        const currentPrice = day.close;
        let dailyAction: 'entry' | 'exit' | 'hold' = 'hold';

        // 1. Check if we need to open a trade
        if (!optionPosition) {
             if (strategyType === 'Long Call') {
                 // Buy Call at specified moneyness
                 const strike = roundToStrike(currentPrice * TARGET_MONEYNESS);
                 const premium = calculateBlackScholes('call', currentPrice, strike, DTE/365, RISK_FREE, IV);
                 const contracts = Math.floor((cash * 0.5) / (premium * 100));

                 if (contracts > 0) {
                    optionPosition = {
                        type: 'call',
                        action: 'buy',
                        strike: strike,
                        entryPremium: premium,
                        contracts: contracts,
                        entryDate: i,
                        expiryDateIndex: i + DTE,
                        stockPriceAtEntry: currentPrice
                    };
                    cash -= contracts * premium * 100;
                    tradeCount++;
                    dailyAction = 'entry';
                 }
             } 
             else if (strategyType === 'Covered Call') {
                 if (shares < 100) {
                     const sharesToBuy = Math.floor(cash / currentPrice);
                     if (sharesToBuy >= 100) {
                         shares += 100;
                         cash -= 100 * currentPrice;
                     }
                 }

                 if (shares >= 100) {
                     // Sell Call at specified moneyness (default 1.05 OTM)
                     const strike = roundToStrike(currentPrice * (customConfig?.moneyness || 1.05));
                     const premium = calculateBlackScholes('call', currentPrice, strike, DTE/365, RISK_FREE, IV);

                     optionPosition = {
                         type: 'call',
                         action: 'sell',
                         strike: strike,
                         entryPremium: premium,
                         contracts: 1, 
                         entryDate: i,
                         expiryDateIndex: i + DTE,
                         stockPriceAtEntry: currentPrice
                     };
                     cash += premium * 100;
                     tradeCount++;
                     dailyAction = 'entry';
                 }
             }
             else if (strategyType === 'Short Put') {
                 // Sell Put at specified moneyness (default 0.95 OTM)
                 const strike = roundToStrike(currentPrice * (customConfig?.moneyness || 0.95));
                 const collateral = strike * 100;

                 if (cash >= collateral) {
                     const premium = calculateBlackScholes('put', currentPrice, strike, DTE/365, RISK_FREE, IV);

                     optionPosition = {
                         type: 'put',
                         action: 'sell',
                         strike: strike,
                         entryPremium: premium,
                         contracts: 1,
                         entryDate: i,
                         expiryDateIndex: i + DTE,
                         stockPriceAtEntry: currentPrice
                     };
                     cash += premium * 100;
                     tradeCount++;
                     dailyAction = 'entry';
                 }
             }
        }

        // 2. Check if we need to close trade
        else if (optionPosition && i >= optionPosition.expiryDateIndex) {
            const p = optionPosition;
            let settlementValue = 0;
            if (p.type === 'call') settlementValue = Math.max(0, currentPrice - p.strike);
            if (p.type === 'put') settlementValue = Math.max(0, p.strike - currentPrice);

            let tradePnL = 0;

            if (p.action === 'buy') {
                cash += settlementValue * 100 * p.contracts;
                tradePnL = (settlementValue - p.entryPremium) * 100 * p.contracts;
                if (settlementValue > p.entryPremium) wins++;
            } else {
                cash -= settlementValue * 100 * p.contracts;
                tradePnL = (p.entryPremium - settlementValue) * 100 * p.contracts;

                if (strategyType === 'Covered Call' && settlementValue > 0) {
                    shares -= 100;
                    cash += p.strike * 100;
                }

                if (settlementValue < p.entryPremium) wins++;
            }

            trades.push({
                id: tradeId++,
                entryDate: history[p.entryDate].date,
                exitDate: history[i].date,
                type: p.type as 'call' | 'put',
                action: p.action as 'buy' | 'sell',
                strike: parseFloat(p.strike.toFixed(2)),
                stockPrice: parseFloat(p.stockPriceAtEntry.toFixed(2)),
                entryPrice: parseFloat(p.entryPremium.toFixed(2)),
                exitPrice: parseFloat(settlementValue.toFixed(2)),
                pnl: parseFloat(tradePnL.toFixed(2)),
                status: tradePnL >= 0 ? 'Win' : 'Loss'
            });

            optionPosition = null;
            dailyAction = 'exit';
        }

        // 3. Mark to Market & Record Granular Data
        let currentOptionValue = 0;

        if (optionPosition) {
            const p = optionPosition;
            const daysLeft = Math.max(0, (p.expiryDateIndex - i));
            const currentOptionPrice = calculateBlackScholes(p.type, currentPrice, p.strike, daysLeft/365, RISK_FREE, IV);

            if (p.action === 'buy') {
                currentOptionValue = currentOptionPrice * 100 * p.contracts;
            } else {
                currentOptionValue = -(currentOptionPrice * 100 * p.contracts);
            }
        }

        let dailyStrategyValue = cash + (shares * currentPrice) + currentOptionValue;
        const benchmarkValue = benchmarkCash + (benchmarkShares * currentPrice);

        equityCurve.push({
            date: day.date,
            strategyValue: dailyStrategyValue,
            benchmarkValue: benchmarkValue,
            underlyingPrice: currentPrice,
            // Granular Data
            cash: parseFloat(cash.toFixed(2)),
            sharesHeld: shares,
            contractsHeld: optionPosition ? optionPosition.contracts : 0,
            optionValue: parseFloat(currentOptionValue.toFixed(2)),
            action: dailyAction
        });
    }

    const finalValue = equityCurve[equityCurve.length - 1].strategyValue;
    const totalReturn = ((finalValue - initialCapital) / initialCapital) * 100;

    let peak = -Infinity;
    let maxDrawdown = 0;
    equityCurve.forEach(pt => {
        if (pt.strategyValue > peak) peak = pt.strategyValue;
        const dd = (peak - pt.strategyValue) / peak;
        if (dd > maxDrawdown) maxDrawdown = dd;
    });

    return {
        ticker,
        strategy: strategyType,
        totalReturn,
        winRate: tradeCount > 0 ? (wins / tradeCount) * 100 : 0,
        maxDrawdown: maxDrawdown * 100,
        tradeCount,
        equityCurve,
        trades
    };
};

import React, { useRef, useEffect, useState, useMemo } from 'react';
import { calculateBlackScholes, calculateHestonPrice } from '../services/marketDataService';
import { Maximize, Eye, Info, DollarSign, Target, Pause, Play, ScanLine, Crosshair, Settings2, Sigma, Waves, Divide } from 'lucide-react';

interface Point3D {
  x: number;
  y: number;
  z: number;
  price: number;
  spot: number;
  time: number;
}

interface SurfaceProps {
  volatility: number;
  riskFreeRate: number;
  isCall: boolean;
  strikePrice?: number;
}

const VolatilitySurface: React.FC<SurfaceProps> = ({ volatility, riskFreeRate, isCall, strikePrice = 100 }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // Animation State
  const [rotation, setRotation] = useState(0.5);
  const [isScanning, setIsScanning] = useState(true);
  const [scanPos, setScanPos] = useState({ x: 0.5, z: 0.5 }); // Normalized 0-1 coordinates

  // View Modes
  const [showPnL, setShowPnL] = useState(false);
  const [showGuides, setShowGuides] = useState(true);

  // Model State
  const [pricingModel, setPricingModel] = useState<'BS' | 'HESTON'>('BS');

  // Heston Parameters (Defaults)
  const [hestonParams, setHestonParams] = useState({
      v0: volatility * volatility, // Initial variance derived from prop input initially
      theta: volatility * volatility, // Long-term variance
      kappa: 1.5, // Mean reversion speed
      xi: 0.3, // Vol of Vol
      rho: -0.3 // Correlation
  });

  // Sync v0/theta if main volatility prop changes significantly and user hasn't overridden model
  useEffect(() => {
     if (pricingModel === 'BS') {
         // Reset Heston baseline if we switch back or props change, to keep them in sync roughly
         setHestonParams(prev => ({
             ...prev,
             v0: volatility * volatility,
             theta: volatility * volatility
         }));
     }
  }, [volatility]);

  // Data for HUD
  const [hudData, setHudData] = useState<{price: number, pnl: number, spot: number, daysLeft: number} | null>(null);

  const animationRef = useRef<number>(0);
  const timeRef = useRef<number>(0);

  // Constants
  const GRID_RES = 24; // Reduce slightly for Heston performance
  const SPOT_RANGE = { min: strikePrice * 0.7, max: strikePrice * 1.3 };
  const TIME_RANGE = { min: 0.02, max: 1.0 }; // ~1 week to 1 year

  // --- MEMOIZED MESH GENERATION ---
  // We decouple math from rendering loop to allow complex models like Heston
  const mesh = useMemo(() => {
      const m: Point3D[][] = [];
      const heightScale = strikePrice * 0.3; 

      for (let i = 0; i <= GRID_RES; i++) {
        const row: Point3D[] = [];
        const tNorm = i / GRID_RES;
        const t = TIME_RANGE.min + (TIME_RANGE.max - TIME_RANGE.min) * tNorm;

        for (let j = 0; j <= GRID_RES; j++) {
          const sNorm = j / GRID_RES;
          const s = SPOT_RANGE.min + (SPOT_RANGE.max - SPOT_RANGE.min) * sNorm;

          let price = 0;

          if (pricingModel === 'BS') {
              price = calculateBlackScholes(
                  isCall ? 'call' : 'put',
                  s,
                  strikePrice,
                  t,
                  riskFreeRate,
                  volatility
              );
          } else {
              price = calculateHestonPrice(
                  isCall ? 'call' : 'put',
                  s,
                  strikePrice,
                  t,
                  riskFreeRate,
                  hestonParams.v0,
                  hestonParams.theta,
                  hestonParams.kappa,
                  hestonParams.xi,
                  hestonParams.rho
              );
          }

          row.push({
              x: (sNorm - 0.5) * 2, 
              y: (price / heightScale) - 0.5,
              z: (tNorm - 0.5) * 2,
              price,
              spot: s,
              time: t
          });
        }
        m.push(row);
      }
      return m;
  }, [pricingModel, volatility, riskFreeRate, isCall, strikePrice, hestonParams]);

  // Calculate Entry Price (Cost Basis) for PnL
  const entryPrice = useMemo(() => {
      if (pricingModel === 'BS') {
          return calculateBlackScholes(
            isCall ? 'call' : 'put', strikePrice, strikePrice, TIME_RANGE.max, riskFreeRate, volatility
          );
      } else {
          return calculateHestonPrice(
            isCall ? 'call' : 'put', strikePrice, strikePrice, TIME_RANGE.max, riskFreeRate, 
            hestonParams.v0, hestonParams.theta, hestonParams.kappa, hestonParams.xi, hestonParams.rho
          );
      }
  }, [mesh, pricingModel]); // Re-calc when mesh inputs change

  const project = (p: Point3D, width: number, height: number, rot: number) => {
    const cos = Math.cos(rot);
    const sin = Math.sin(rot);
    const x1 = p.x * cos - p.z * sin;
    const z1 = p.x * sin + p.z * cos;
    const tilt = 0.6; 
    const y2 = p.y * Math.cos(tilt) - z1 * Math.sin(tilt);
    const z2 = p.y * Math.sin(tilt) + z1 * Math.cos(tilt);
    const fov = 1.8;
    const distance = 3.0;
    const scale = (fov / (distance + z2)) * (Math.min(width, height) / 2.2);
    return {
        x: x1 * scale + width / 2,
        y: -y2 * scale + height / 2 + 20, 
        scale: scale,
        zDepth: z2
    };
  };

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dpr = window.devicePixelRatio || 1;
    const rect = canvas.getBoundingClientRect();
    if (canvas.width !== rect.width * dpr) {
        canvas.width = rect.width * dpr;
        canvas.height = rect.height * dpr;
    }

    ctx.setTransform(dpr, 0, 0, dpr, 0, 0); // Reset transform
    const width = rect.width;
    const height = rect.height;

    ctx.clearRect(0, 0, width, height);

    const scanIndexX = Math.floor(scanPos.x * GRID_RES);
    const scanIndexZ = Math.floor(scanPos.z * GRID_RES);

    const heightScale = strikePrice * 0.3;
    const basisY = (entryPrice / heightScale) - 0.5;

    // --- Draw Cost Basis Plane ---
    if (showPnL) {
        const p1 = { x: -1, y: basisY, z: -1, price: 0, spot: 0, time: 0 };
        const p2 = { x: 1, y: basisY, z: -1, price: 0, spot: 0, time: 0 };
        const p3 = { x: 1, y: basisY, z: 1, price: 0, spot: 0, time: 0 };
        const p4 = { x: -1, y: basisY, z: 1, price: 0, spot: 0, time: 0 };
        const points = [p1, p2, p3, p4].map(p => project(p, width, height, rotation));

        ctx.beginPath();
        ctx.moveTo(points[0].x, points[0].y);
        ctx.lineTo(points[1].x, points[1].y);
        ctx.lineTo(points[2].x, points[2].y);
        ctx.lineTo(points[3].x, points[3].y);
        ctx.closePath();
        ctx.fillStyle = 'rgba(79, 70, 229, 0.05)'; 
        ctx.fill();
        ctx.strokeStyle = 'rgba(255, 255, 255, 0.15)';
        ctx.stroke();
    }

    // --- Draw Mesh ---
    for (let i = 0; i < mesh.length; i++) {
        for (let j = 0; j < mesh[i].length; j++) {
            const p = mesh[i][j];
            const pp = project(p, width, height, rotation);

            let strokeStyle = `hsla(${240 - ((p.y + 0.5) * 120)}, 80%, 60%, 0.3)`;
            if (showPnL) {
                const pnl = p.price - entryPrice;
                const opacity = 0.2 + Math.min(Math.abs(pnl) / (entryPrice), 0.8);
                strokeStyle = pnl >= 0 ? `rgba(16, 185, 129, ${opacity})` : `rgba(244, 63, 94, ${opacity})`;
            }

            const isScannedRow = i === scanIndexZ;
            const isScannedCol = j === scanIndexX;
            if (isScannedRow || isScannedCol) {
                ctx.lineWidth = 2;
                strokeStyle = 'rgba(255, 255, 255, 0.5)';
            } else {
                ctx.lineWidth = 1;
            }

            if (j < mesh[i].length - 1) {
                const pr = project(mesh[i][j+1], width, height, rotation);
                ctx.beginPath();
                ctx.moveTo(pp.x, pp.y);
                ctx.lineTo(pr.x, pr.y);
                ctx.strokeStyle = strokeStyle;
                ctx.stroke();
            }
            if (i < mesh.length - 1) {
                const pb = project(mesh[i+1][j], width, height, rotation);
                ctx.beginPath();
                ctx.moveTo(pp.x, pp.y);
                ctx.lineTo(pb.x, pb.y);
                ctx.strokeStyle = strokeStyle;
                ctx.stroke();
            }
        }
    }

    // --- Draw Scanner ---
    if (scanIndexZ < mesh.length && scanIndexX < mesh[0].length) {
        const scanPoint = mesh[scanIndexZ][scanIndexX];
        const projScan = project(scanPoint, width, height, rotation);

        // Only update HUD state if needed to prevent react render loop in draw
        // (Handled by effects usually, but here we derive visual from scanPos state)
        // We'll update ref or check inside the interval loop instead of here

        // Scanner Visuals
        const floorY = -0.5;
        const projFloor = project({ ...scanPoint, y: floorY }, width, height, rotation);

        const grad = ctx.createLinearGradient(projScan.x, projScan.y, projFloor.x, projFloor.y);
        grad.addColorStop(0, 'rgba(255, 255, 255, 1)');
        grad.addColorStop(1, 'rgba(255, 255, 255, 0)');

        ctx.beginPath();
        ctx.moveTo(projScan.x, projScan.y);
        ctx.lineTo(projFloor.x, projFloor.y);
        ctx.strokeStyle = grad;
        ctx.lineWidth = 2;
        ctx.setLineDash([2, 2]);
        ctx.stroke();
        ctx.setLineDash([]);

        if (showPnL) {
             const projBasis = project({ ...scanPoint, y: basisY }, width, height, rotation);
             ctx.beginPath();
             ctx.moveTo(projScan.x, projScan.y);
             ctx.lineTo(projBasis.x, projBasis.y);
             ctx.lineWidth = 3;
             ctx.strokeStyle = (scanPoint.price - entryPrice) >= 0 ? '#10b981' : '#f43f5e';
             ctx.stroke();
        }

        ctx.beginPath();
        ctx.arc(projScan.x, projScan.y, 4, 0, Math.PI * 2);
        ctx.fillStyle = '#ffffff';
        ctx.fill();

        // Label
        const labelX = projScan.x + 15;
        const labelY = projScan.y - 15;
        ctx.fillStyle = 'rgba(15, 23, 42, 0.8)';
        ctx.fillRect(labelX, labelY - 12, 80, 20);
        ctx.fillStyle = '#ffffff';
        ctx.font = 'bold 12px monospace';
        ctx.fillText(`$${scanPoint.price.toFixed(2)}`, labelX + 8, labelY + 2);
    }

    if (showGuides) {
        // Strike Line
        const p1 = project({ x: 0, y: -0.5, z: 1, price: 0, spot: 0, time: 0 }, width, height, rotation);
        const p2 = project({ x: 0, y: -0.5, z: -1, price: 0, spot: 0, time: 0 }, width, height, rotation);
        ctx.beginPath();
        ctx.moveTo(p1.x, p1.y);
        ctx.lineTo(p2.x, p2.y);
        ctx.strokeStyle = 'rgba(255, 255, 255, 0.2)';
        ctx.setLineDash([5, 5]);
        ctx.stroke();
        ctx.setLineDash([]);
        ctx.fillStyle = '#94a3b8';
        ctx.fillText(`STRIKE $${strikePrice}`, width/2 - 30, height - 20);
    }
  };

  // Animation Loop
  useEffect(() => {
    const loop = () => {
        timeRef.current += 0.01;
        setRotation(r => r + 0.001); 
        if (isScanning) {
            setScanPos({
                x: 0.5 + Math.sin(timeRef.current * 0.5) * 0.45, 
                z: 0.5 + Math.cos(timeRef.current * 0.3) * 0.45  
            });
        }
        draw();
        animationRef.current = requestAnimationFrame(loop);
    };
    loop();
    return () => cancelAnimationFrame(animationRef.current);
  }, [isScanning, mesh, showPnL, showGuides, rotation]); 

  // Sync HUD with ScanPos state (decoupled from draw loop for React purity)
  useEffect(() => {
      if (!mesh || mesh.length === 0) return;
      const xIdx = Math.floor(scanPos.x * GRID_RES);
      const zIdx = Math.floor(scanPos.z * GRID_RES);
      if (zIdx < mesh.length && xIdx < mesh[0].length) {
          const p = mesh[zIdx][xIdx];
          setHudData({
              price: p.price,
              pnl: p.price - entryPrice,
              spot: p.spot,
              daysLeft: Math.floor(p.time * 365)
          });
      }
  }, [scanPos, mesh, entryPrice]);

  return (
    <div className="relative w-full h-full bg-slate-950/80 rounded-xl overflow-hidden border border-white/5 shadow-inner group">
        <canvas 
            ref={canvasRef} 
            className="w-full h-full object-cover cursor-crosshair"
        />

        {/* Heston Controls Overlay */}
        <div className="absolute top-4 left-4 flex flex-col gap-2 pointer-events-auto">
             <div className="bg-black/40 backdrop-blur-md p-3 rounded-xl border border-white/10 w-64">
                <div className="flex justify-between items-center mb-2">
                    <h4 className="text-white font-bold text-xs flex items-center gap-2">
                        <Settings2 className="w-3 h-3 text-indigo-400" /> Model Params
                    </h4>
                    <div className="flex bg-slate-900 rounded p-0.5 border border-white/10">
                        <button 
                            onClick={() => setPricingModel('BS')} 
                            className={`text-[9px] px-2 py-0.5 rounded font-bold ${pricingModel === 'BS' ? 'bg-indigo-600 text-white' : 'text-slate-500'}`}
                        >BS</button>
                        <button 
                            onClick={() => setPricingModel('HESTON')} 
                            className={`text-[9px] px-2 py-0.5 rounded font-bold ${pricingModel === 'HESTON' ? 'bg-indigo-600 text-white' : 'text-slate-500'}`}
                        >HESTON</button>
                    </div>
                </div>

                {pricingModel === 'HESTON' && (
                    <div className="space-y-3 animate-fade-in">
                        <div className="space-y-1">
                            <div className="flex justify-between text-[9px] uppercase font-bold text-slate-500">
                                <span>Mean Reversion (κ)</span> <span className="text-white">{hestonParams.kappa}</span>
                            </div>
                            <input type="range" min="0.1" max="10" step="0.1" value={hestonParams.kappa} onChange={e => setHestonParams(p => ({...p, kappa: Number(e.target.value)}))} className="w-full h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-400" />
                        </div>
                        <div className="space-y-1">
                            <div className="flex justify-between text-[9px] uppercase font-bold text-slate-500">
                                <span>Vol of Vol (ξ)</span> <span className="text-white">{hestonParams.xi}</span>
                            </div>
                            <input type="range" min="0.01" max="2" step="0.05" value={hestonParams.xi} onChange={e => setHestonParams(p => ({...p, xi: Number(e.target.value)}))} className="w-full h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-rose-400" />
                        </div>
                        <div className="space-y-1">
                            <div className="flex justify-between text-[9px] uppercase font-bold text-slate-500">
                                <span>Correlation (ρ)</span> <span className="text-white">{hestonParams.rho}</span>
                            </div>
                            <input type="range" min="-0.99" max="0.99" step="0.05" value={hestonParams.rho} onChange={e => setHestonParams(p => ({...p, rho: Number(e.target.value)}))} className="w-full h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-amber-400" />
                        </div>
                        <div className="p-2 bg-indigo-500/10 border border-indigo-500/20 rounded text-[9px] text-indigo-300 leading-tight">
                            <strong>Stochastic Volatility Active.</strong> Prices now reflect skew and smile dynamics based on mean-reverting variance.
                        </div>
                    </div>
                )}
                {pricingModel === 'BS' && (
                     <div className="p-2 bg-slate-800/50 border border-white/5 rounded text-[9px] text-slate-400 leading-tight">
                        Standard Black-Scholes assumption: Constant volatility ({ (volatility*100).toFixed(0) }%) across time and strike.
                     </div>
                )}
             </div>
        </div>

        {/* Holographic HUD Overlay */}
        {hudData && (
            <div className="absolute top-4 right-4 w-64 animate-fade-in pointer-events-none">
                <div className="bg-slate-900/90 backdrop-blur-xl border border-white/10 p-4 rounded-xl shadow-2xl relative overflow-hidden">
                    <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-indigo-500 via-purple-500 to-emerald-500 animate-pulse"></div>
                    <div className="flex justify-between items-start mb-3">
                        <h5 className="text-white font-bold text-sm flex items-center gap-2">
                            <Crosshair className="w-4 h-4 text-indigo-400 animate-spin-slow" />
                            Scanner Data
                        </h5>
                        <span className="text-[10px] text-slate-500 font-mono">{isScanning ? 'LIVE' : 'PAUSED'}</span>
                    </div>

                    <div className="grid grid-cols-2 gap-3 mb-3">
                        <div className="bg-slate-950/50 p-2 rounded-lg border border-white/5">
                            <div className="text-[9px] text-slate-400 uppercase font-bold mb-0.5">Option Price</div>
                            <div className="text-xl font-mono font-bold text-white tracking-tight">
                                ${hudData.price.toFixed(2)}
                            </div>
                        </div>
                        <div className="bg-slate-950/50 p-2 rounded-lg border border-white/5">
                            <div className="text-[9px] text-slate-400 uppercase font-bold mb-0.5">Est. P/L</div>
                            <div className={`text-xl font-mono font-bold tracking-tight ${hudData.pnl >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                                {hudData.pnl >= 0 ? '+' : ''}{hudData.pnl.toFixed(2)}
                            </div>
                        </div>
                    </div>
                    <div className="space-y-2">
                        <div className="flex justify-between items-center text-xs border-b border-white/5 pb-1">
                            <span className="text-slate-400">Spot Price</span>
                            <span className="font-mono text-amber-400">${hudData.spot.toFixed(2)}</span>
                        </div>
                        <div className="flex justify-between items-center text-xs">
                            <span className="text-slate-400">Time to Expiry</span>
                            <span className="font-mono text-cyan-400">{hudData.daysLeft} Days</span>
                        </div>
                    </div>
                </div>
            </div>
        )}

        {/* Bottom Toolbar */}
        <div className="absolute bottom-4 left-1/2 -translate-x-1/2 flex items-center gap-2 bg-slate-900/90 backdrop-blur-md p-1.5 rounded-xl border border-white/10 shadow-lg transition-opacity opacity-0 group-hover:opacity-100">
            <button 
                onClick={() => setIsScanning(!isScanning)}
                className="p-2 hover:bg-white/10 rounded-lg text-slate-300 hover:text-white transition-colors"
                title={isScanning ? "Pause Scanner" : "Resume Scanner"}
            >
                {isScanning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />}
            </button>
            <div className="w-px h-4 bg-white/10"></div>
            <button 
                onClick={() => setShowPnL(!showPnL)}
                className={`p-2 rounded-lg transition-colors ${showPnL ? 'bg-emerald-500/20 text-emerald-400' : 'text-slate-300 hover:text-white hover:bg-white/10'}`}
                title="Toggle PnL Heatmap"
            >
                <DollarSign className="w-4 h-4" />
            </button>
            <button 
                onClick={() => setShowGuides(!showGuides)}
                className={`p-2 rounded-lg transition-colors ${showGuides ? 'bg-indigo-500/20 text-indigo-400' : 'text-slate-300 hover:text-white hover:bg-white/10'}`}
                title="Toggle Guides"
            >
                <ScanLine className="w-4 h-4" />
            </button>
        </div>

    </div>
  );
};

export default VolatilitySurface;

import React, { useRef, useEffect, useState, useMemo } from 'react';
import { calculateBlackScholes, calculateHestonPrice } from '../services/marketDataService';
import { Maximize, Eye, Info, DollarSign, Target, Pause, Play, ScanLine, Crosshair, Settings2, Move3d, MousePointer2 } from 'lucide-react';

interface Point3D {
  x: number;
  y: number;
  z: number;
  price: number;
  spot: number;
  time: number;
}

interface Particle {
    x: number;
    y: number;
    z: number;
    speed: number;
    size: number;
    alpha: number;
}

interface SurfaceProps {
  volatility: number;
  riskFreeRate: number;
  isCall: boolean;
  strikePrice?: number;
}

const VolatilitySurface: React.FC<SurfaceProps> = ({ volatility, riskFreeRate, isCall, strikePrice = 100 }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // Camera & Interaction State
  const [camera, setCamera] = useState({ yaw: 0.5, pitch: 0.5 });
  const [isDragging, setIsDragging] = useState(false);
  const [lastMouse, setLastMouse] = useState({ x: 0, y: 0 });

  // Animation State
  const [isScanning, setIsScanning] = useState(true);
  const [scanPos, setScanPos] = useState({ x: 0.5, z: 0.5 }); 

  // View Modes
  const [showPnL, setShowPnL] = useState(false);
  const [showGuides, setShowGuides] = useState(true);
  const [pricingModel, setPricingModel] = useState<'BS' | 'HESTON'>('BS');

  // Heston Parameters
  const [hestonParams, setHestonParams] = useState({
      v0: volatility * volatility,
      theta: volatility * volatility,
      kappa: 1.5,
      xi: 0.3,
      rho: -0.3
  });

  // Data for HUD
  const [hudData, setHudData] = useState<{price: number, pnl: number, spot: number, daysLeft: number} | null>(null);

  const animationRef = useRef<number>(0);
  const timeRef = useRef<number>(0);
  const particlesRef = useRef<Particle[]>([]);

  // Initialize Particles
  useEffect(() => {
      const p: Particle[] = [];
      for(let i=0; i<60; i++) {
          p.push({
              x: (Math.random() - 0.5) * 5,
              y: (Math.random() - 0.5) * 4 - 1, // Bias downwards slightly
              z: (Math.random() - 0.5) * 5,
              speed: 0.002 + Math.random() * 0.003,
              size: Math.random() * 1.5,
              alpha: Math.random() * 0.5
          });
      }
      particlesRef.current = p;
  }, []);

  // Sync Params
  useEffect(() => {
     if (pricingModel === 'BS') {
         setHestonParams(prev => ({
             ...prev,
             v0: volatility * volatility,
             theta: volatility * volatility
         }));
     }
  }, [volatility, pricingModel]);

  // Constants
  const GRID_RES = 24; 
  const SPOT_RANGE = { min: strikePrice * 0.6, max: strikePrice * 1.4 };
  const TIME_RANGE = { min: 0.02, max: 1.0 }; 

  // --- MEMOIZED MESH GENERATION ---
  const mesh = useMemo(() => {
      const m: Point3D[][] = [];
      const heightScale = strikePrice * 0.4; 

      for (let i = 0; i <= GRID_RES; i++) {
        const row: Point3D[] = [];
        const tNorm = i / GRID_RES;
        const t = TIME_RANGE.min + (TIME_RANGE.max - TIME_RANGE.min) * tNorm;

        for (let j = 0; j <= GRID_RES; j++) {
          const sNorm = j / GRID_RES;
          const s = SPOT_RANGE.min + (SPOT_RANGE.max - SPOT_RANGE.min) * sNorm;

          let price = 0;
          if (pricingModel === 'BS') {
              price = calculateBlackScholes(isCall ? 'call' : 'put', s, strikePrice, t, riskFreeRate, volatility);
          } else {
              price = calculateHestonPrice(isCall ? 'call' : 'put', s, strikePrice, t, riskFreeRate, hestonParams.v0, hestonParams.theta, hestonParams.kappa, hestonParams.xi, hestonParams.rho);
          }

          row.push({
              x: (sNorm - 0.5) * 2.5, 
              y: (price / heightScale) - 0.5,
              z: (tNorm - 0.5) * 2.5,
              price,
              spot: s,
              time: t
          });
        }
        m.push(row);
      }
      return m;
  }, [pricingModel, volatility, riskFreeRate, isCall, strikePrice, hestonParams]);

  // Calculate Entry Price (Cost Basis) for PnL
  const entryPrice = useMemo(() => {
      if (pricingModel === 'BS') {
          return calculateBlackScholes(isCall ? 'call' : 'put', strikePrice, strikePrice, TIME_RANGE.max, riskFreeRate, volatility);
      } else {
          return calculateHestonPrice(isCall ? 'call' : 'put', strikePrice, strikePrice, TIME_RANGE.max, riskFreeRate, hestonParams.v0, hestonParams.theta, hestonParams.kappa, hestonParams.xi, hestonParams.rho);
      }
  }, [mesh, pricingModel]);

  // --- 3D Projection Engine ---
  const project = (p: Point3D, width: number, height: number, yaw: number, pitch: number) => {
    const cosYaw = Math.cos(yaw);
    const sinYaw = Math.sin(yaw);
    const cosPitch = Math.cos(pitch);
    const sinPitch = Math.sin(pitch);

    // Rotate Y (Yaw)
    const x1 = p.x * cosYaw - p.z * sinYaw;
    const z1 = p.x * sinYaw + p.z * cosYaw;

    // Rotate X (Pitch)
    const y2 = p.y * cosPitch - z1 * sinPitch;
    const z2 = p.y * sinPitch + z1 * cosPitch;

    // Perspective
    const fov = 600;
    const distance = 4;

    // Z-Clipping
    if (z2 + distance < 0.1) return null;

    const scale = fov / (distance + z2);
    const x2d = x1 * scale + width / 2;
    const y2d = -y2 * scale + height / 2; // Invert Y

    return { x: x2d, y: y2d, scale, z: z2 };
  };

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const width = canvas.width;
    const height = canvas.height;

    // Clear with slight fade for trails? No, standard clear for crispness
    ctx.clearRect(0, 0, width, height);

    // Background Gradient
    const bgGrad = ctx.createLinearGradient(0, 0, 0, height);
    bgGrad.addColorStop(0, '#020617');
    bgGrad.addColorStop(1, '#0f172a');
    ctx.fillStyle = bgGrad;
    ctx.fillRect(0, 0, width, height);

    // --- Draw Particles ---
    particlesRef.current.forEach(p => {
        const proj = project({ x: p.x, y: p.y, z: p.z, price: 0, spot: 0, time: 0 }, width, height, camera.yaw, camera.pitch);
        if (proj) {
            ctx.beginPath();
            ctx.fillStyle = `rgba(100, 200, 255, ${p.alpha})`;
            ctx.arc(proj.x, proj.y, p.size * (proj.scale/100), 0, Math.PI * 2);
            ctx.fill();
        }
        // Animate
        p.y += p.speed;
        if (p.y > 2) p.y = -2;
    });

    const heightScale = strikePrice * 0.4;
    const basisY = (entryPrice / heightScale) - 0.5;

    // --- Draw Grid Floor ---
    if (showGuides) {
        ctx.lineWidth = 1;
        ctx.strokeStyle = 'rgba(79, 70, 229, 0.15)'; // Indigo
        const floorY = -0.8;
        const range = 2.0;
        const steps = 8;

        // Z-lines
        for(let i=-steps; i<=steps; i++) {
            const x = (i/steps) * range;
            const p1 = project({x, y: floorY, z: -range, price:0, spot:0, time:0}, width, height, camera.yaw, camera.pitch);
            const p2 = project({x, y: floorY, z: range, price:0, spot:0, time:0}, width, height, camera.yaw, camera.pitch);
            if(p1 && p2) {
                ctx.beginPath();
                ctx.moveTo(p1.x, p1.y);
                ctx.lineTo(p2.x, p2.y);
                ctx.stroke();
            }
        }
        // X-lines
        for(let i=-steps; i<=steps; i++) {
            const z = (i/steps) * range;
            const p1 = project({x: -range, y: floorY, z, price:0, spot:0, time:0}, width, height, camera.yaw, camera.pitch);
            const p2 = project({x: range, y: floorY, z, price:0, spot:0, time:0}, width, height, camera.yaw, camera.pitch);
            if(p1 && p2) {
                ctx.beginPath();
                ctx.moveTo(p1.x, p1.y);
                ctx.lineTo(p2.x, p2.y);
                ctx.stroke();
            }
        }
    }

    // --- Draw Surface Mesh ---
    // Enable glow
    ctx.shadowBlur = 10;
    ctx.lineJoin = 'round';

    for (let i = 0; i < mesh.length; i++) {
        for (let j = 0; j < mesh[i].length; j++) {
            const p = mesh[i][j];
            const pp = project(p, width, height, camera.yaw, camera.pitch);
            if (!pp) continue;

            // Determine Color
            let strokeStyle = '';
            let shadowColor = '';

            if (showPnL) {
                const pnl = p.price - entryPrice;
                // Green for profit, Red for loss
                if (pnl >= 0) {
                    strokeStyle = `rgba(16, 185, 129, 0.6)`;
                    shadowColor = '#10b981';
                } else {
                    strokeStyle = `rgba(244, 63, 94, 0.6)`;
                    shadowColor = '#f43f5e';
                }
            } else {
                // Neon Aesthetic: Height based color
                // Low = Purple, High = Cyan/White
                const normalizedH = (p.y + 0.5); 
                const hue = 260 - (normalizedH * 100); // 260 (purple) -> 160 (teal)
                const light = 50 + (normalizedH * 40);
                strokeStyle = `hsla(${hue}, 90%, ${light}%, 0.5)`;
                shadowColor = `hsla(${hue}, 90%, 50%, 1)`;
            }

            ctx.shadowColor = shadowColor;
            ctx.strokeStyle = strokeStyle;
            ctx.lineWidth = 2; // Thicker lines for neon feel

            // Scanner Highlight
            const isScannedRow = i === Math.floor(scanPos.z * GRID_RES);
            const isScannedCol = j === Math.floor(scanPos.x * GRID_RES);

            if (isScannedRow || isScannedCol) {
                ctx.strokeStyle = '#ffffff';
                ctx.shadowColor = '#ffffff';
                ctx.lineWidth = 3;
            }

            // Draw X-segments
            if (j < mesh[i].length - 1) {
                const right = mesh[i][j+1];
                const pr = project(right, width, height, camera.yaw, camera.pitch);
                if (pr) {
                    ctx.beginPath();
                    ctx.moveTo(pp.x, pp.y);
                    ctx.lineTo(pr.x, pr.y);
                    ctx.stroke();
                }
            }
            // Draw Z-segments
            if (i < mesh.length - 1) {
                const bottom = mesh[i+1][j];
                const pb = project(bottom, width, height, camera.yaw, camera.pitch);
                if (pb) {
                    ctx.beginPath();
                    ctx.moveTo(pp.x, pp.y);
                    ctx.lineTo(pb.x, pb.y);
                    ctx.stroke();
                }
            }
        }
    }

    // Reset Shadow for overlay elements
    ctx.shadowBlur = 0;

    // --- Draw Scanner Target & Drop Lines ---
    const sZ = Math.floor(scanPos.z * GRID_RES);
    const sX = Math.floor(scanPos.x * GRID_RES);

    if (sZ < mesh.length && sX < mesh[0].length) {
        const scanPoint = mesh[sZ][sX];
        const projScan = project(scanPoint, width, height, camera.yaw, camera.pitch);

        if (projScan) {
            // Drop Line to floor
            const floorY = -0.5;
            const projFloor = project({ ...scanPoint, y: floorY }, width, height, camera.yaw, camera.pitch);

            if (projFloor) {
                const grad = ctx.createLinearGradient(projScan.x, projScan.y, projFloor.x, projFloor.y);
                grad.addColorStop(0, 'rgba(255, 255, 255, 1)');
                grad.addColorStop(1, 'rgba(255, 255, 255, 0)');

                ctx.beginPath();
                ctx.moveTo(projScan.x, projScan.y);
                ctx.lineTo(projFloor.x, projFloor.y);
                ctx.strokeStyle = grad;
                ctx.lineWidth = 1;
                ctx.setLineDash([4, 4]);
                ctx.stroke();
                ctx.setLineDash([]);
            }

            // Target Circle
            ctx.beginPath();
            ctx.arc(projScan.x, projScan.y, 6, 0, Math.PI * 2);
            ctx.fillStyle = '#ffffff';
            ctx.fill();

            // Pulse Ring
            const pulse = (Math.sin(timeRef.current * 5) + 1) * 0.5;
            ctx.beginPath();
            ctx.arc(projScan.x, projScan.y, 8 + pulse * 10, 0, Math.PI * 2);
            ctx.strokeStyle = `rgba(255, 255, 255, ${1 - pulse})`;
            ctx.lineWidth = 2;
            ctx.stroke();

            // Label Box
            const labelX = projScan.x + 20;
            const labelY = projScan.y - 20;

            ctx.fillStyle = 'rgba(2, 6, 23, 0.8)';
            ctx.fillRect(labelX, labelY - 15, 90, 45);
            ctx.strokeStyle = 'rgba(255, 255, 255, 0.2)';
            ctx.strokeRect(labelX, labelY - 15, 90, 45);

            ctx.fillStyle = '#ffffff';
            ctx.font = 'bold 12px monospace';
            ctx.fillText(`$${scanPoint.price.toFixed(2)}`, labelX + 8, labelY);

            const pnl = scanPoint.price - entryPrice;
            ctx.font = '10px monospace';
            ctx.fillStyle = pnl >= 0 ? '#34d399' : '#fb7185';
            ctx.fillText(`${pnl >= 0 ? '+' : ''}${pnl.toFixed(2)} P/L`, labelX + 8, labelY + 18);
        }
    }
  };

  // Interaction Handlers
  const handleMouseDown = (e: React.MouseEvent) => {
      setIsDragging(true);
      setLastMouse({ x: e.clientX, y: e.clientY });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
      if (!isDragging) return;
      const deltaX = e.clientX - lastMouse.x;
      const deltaY = e.clientY - lastMouse.y;

      setCamera(prev => ({
          yaw: prev.yaw + deltaX * 0.005,
          pitch: Math.max(0.1, Math.min(Math.PI / 2, prev.pitch + deltaY * 0.005))
      }));
      setLastMouse({ x: e.clientX, y: e.clientY });
  };

  const handleMouseUp = () => setIsDragging(false);

  // Animation Loop
  useEffect(() => {
    const loop = () => {
        timeRef.current += 0.01;

        // Auto-Rotate if not dragging (slow orbit)
        if (!isDragging) {
            setCamera(prev => ({ ...prev, yaw: prev.yaw + 0.0005 }));
        }

        if (isScanning) {
            setScanPos({
                x: 0.5 + Math.sin(timeRef.current * 0.5) * 0.45, 
                z: 0.5 + Math.cos(timeRef.current * 0.3) * 0.45  
            });
        }
        draw();
        animationRef.current = requestAnimationFrame(loop);
    };
    loop();
    return () => cancelAnimationFrame(animationRef.current);
  }, [isScanning, mesh, showPnL, showGuides, camera, isDragging]); 

  // Sync HUD (Decoupled)
  useEffect(() => {
      if (!mesh || mesh.length === 0) return;
      const xIdx = Math.floor(scanPos.x * GRID_RES);
      const zIdx = Math.floor(scanPos.z * GRID_RES);
      if (zIdx < mesh.length && xIdx < mesh[0].length) {
          const p = mesh[zIdx][xIdx];
          setHudData({
              price: p.price,
              pnl: p.price - entryPrice,
              spot: p.spot,
              daysLeft: Math.floor(p.time * 365)
          });
      }
  }, [scanPos, mesh, entryPrice]);

  // Adjust canvas size for DPI
  useEffect(() => {
      const canvas = canvasRef.current;
      if (canvas) {
          const rect = canvas.getBoundingClientRect();
          const dpr = window.devicePixelRatio || 1;
          canvas.width = rect.width * dpr;
          canvas.height = rect.height * dpr;
          const ctx = canvas.getContext('2d');
          if (ctx) ctx.scale(dpr, dpr);
      }
  }, []);

  return (
    <div 
        className="relative w-full h-full bg-slate-950/80 rounded-xl overflow-hidden border border-white/5 shadow-inner group"
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
    >
        <canvas 
            ref={canvasRef} 
            className={`w-full h-full object-cover ${isDragging ? 'cursor-grabbing' : 'cursor-grab'}`}
            style={{ width: '100%', height: '100%' }}
        />

        {/* Interaction Hint */}
        <div className="absolute top-4 left-1/2 -translate-x-1/2 flex items-center gap-2 px-3 py-1 bg-black/40 rounded-full border border-white/10 pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity">
            <Move3d className="w-3 h-3 text-indigo-400" />
            <span className="text-[10px] text-slate-400 uppercase font-bold">Drag to Orbit</span>
        </div>

        {/* Heston Controls Overlay */}
        <div className="absolute top-4 left-4 flex flex-col gap-2 pointer-events-auto">
             <div className="bg-black/40 backdrop-blur-md p-3 rounded-xl border border-white/10 w-64">
                <div className="flex justify-between items-center mb-2">
                    <h4 className="text-white font-bold text-xs flex items-center gap-2">
                        <Settings2 className="w-3 h-3 text-indigo-400" /> Model Params
                    </h4>
                    <div className="flex bg-slate-900 rounded p-0.5 border border-white/10">
                        <button 
                            onClick={() => setPricingModel('BS')} 
                            className={`text-[9px] px-2 py-0.5 rounded font-bold ${pricingModel === 'BS' ? 'bg-indigo-600 text-white' : 'text-slate-500'}`}
                        >BS</button>
                        <button 
                            onClick={() => setPricingModel('HESTON')} 
                            className={`text-[9px] px-2 py-0.5 rounded font-bold ${pricingModel === 'HESTON' ? 'bg-indigo-600 text-white' : 'text-slate-500'}`}
                        >HESTON</button>
                    </div>
                </div>

                {pricingModel === 'HESTON' && (
                    <div className="space-y-3 animate-fade-in">
                        <div className="space-y-1">
                            <div className="flex justify-between text-[9px] uppercase font-bold text-slate-500">
                                <span>Mean Reversion (κ)</span> <span className="text-white">{hestonParams.kappa}</span>
                            </div>
                            <input type="range" min="0.1" max="10" step="0.1" value={hestonParams.kappa} onChange={e => setHestonParams(p => ({...p, kappa: Number(e.target.value)}))} className="w-full h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-400" />
                        </div>
                        <div className="space-y-1">
                            <div className="flex justify-between text-[9px] uppercase font-bold text-slate-500">
                                <span>Vol of Vol (ξ)</span> <span className="text-white">{hestonParams.xi}</span>
                            </div>
                            <input type="range" min="0.01" max="2" step="0.05" value={hestonParams.xi} onChange={e => setHestonParams(p => ({...p, xi: Number(e.target.value)}))} className="w-full h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-rose-400" />
                        </div>
                        <div className="space-y-1">
                            <div className="flex justify-between text-[9px] uppercase font-bold text-slate-500">
                                <span>Correlation (ρ)</span> <span className="text-white">{hestonParams.rho}</span>
                            </div>
                            <input type="range" min="-0.99" max="0.99" step="0.05" value={hestonParams.rho} onChange={e => setHestonParams(p => ({...p, rho: Number(e.target.value)}))} className="w-full h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-amber-400" />
                        </div>
                    </div>
                )}
                {pricingModel === 'BS' && (
                     <div className="p-2 bg-slate-800/50 border border-white/5 rounded text-[9px] text-slate-400 leading-tight">
                        Constant Volatility: <span className="text-white font-mono">{(volatility * 100).toFixed(1)}%</span>
                     </div>
                )}
             </div>
        </div>

        {/* Holographic HUD Overlay */}
        {hudData && (
            <div className="absolute top-4 right-4 w-64 animate-fade-in pointer-events-none">
                <div className="bg-slate-900/80 backdrop-blur-xl border border-white/10 p-4 rounded-xl shadow-2xl relative overflow-hidden">
                    <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-indigo-500 via-purple-500 to-emerald-500 animate-pulse"></div>
                    <div className="flex justify-between items-start mb-3">
                        <h5 className="text-white font-bold text-sm flex items-center gap-2">
                            <Crosshair className="w-4 h-4 text-indigo-400 animate-spin-slow" />
                            Scanner Data
                        </h5>
                        <span className="text-[10px] text-slate-500 font-mono">{isScanning ? 'LIVE' : 'PAUSED'}</span>
                    </div>

