import React, { useRef, useEffect, useState } from 'react';
import { OptionContract, OptionsChain } from '../types';
import { MousePointer2, Layers, BarChart3, Maximize } from 'lucide-react';

interface VisualizerProps {
  chain: OptionsChain;
  metric: 'volume' | 'openInterest';
  onSelectContract?: (contract: OptionContract) => void;
}

const OptionsChainVisualizer: React.FC<VisualizerProps> = ({ chain, metric, onSelectContract }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [hoverData, setHoverData] = useState<{ x: number, y: number, contract: OptionContract, type: 'call' | 'put' } | null>(null);

  // Configuration
  const BAR_WIDTH = 14;
  const BAR_GAP = 8;
  const MAX_BAR_HEIGHT = 150;
  const ANGLE = 0.5; // Isometric angle

  const getMetric = (c: OptionContract) => metric === 'volume' ? c.volume : c.openInterest;

  const drawCube = (
      ctx: CanvasRenderingContext2D, 
      x: number, 
      y: number, 
      width: number, 
      height: number, 
      color: string, 
      sideColor: string, 
      topColor: string,
      isHovered: boolean
  ) => {
      // Perspective offsets
      const dx = width * Math.cos(ANGLE);
      const dy = width * Math.sin(ANGLE);

      ctx.lineWidth = 1;
      ctx.lineJoin = 'round';

      // Top Face
      ctx.beginPath();
      ctx.moveTo(x, y - height);
      ctx.lineTo(x + dx, y - height - dy);
      ctx.lineTo(x + dx + width, y - height - dy);
      ctx.lineTo(x + width, y - height);
      ctx.closePath();
      ctx.fillStyle = isHovered ? '#ffffff' : topColor;
      ctx.fill();
      ctx.strokeStyle = isHovered ? '#ffffff' : sideColor;
      ctx.stroke();

      // Right Face
      ctx.beginPath();
      ctx.moveTo(x + width, y - height);
      ctx.lineTo(x + width + dx, y - height - dy);
      ctx.lineTo(x + width + dx, y - dy);
      ctx.lineTo(x + width, y);
      ctx.closePath();
      ctx.fillStyle = sideColor;
      ctx.fill();
      ctx.stroke();

      // Front Face
      ctx.beginPath();
      ctx.moveTo(x, y);
      ctx.lineTo(x + width, y);
      ctx.lineTo(x + width, y - height);
      ctx.lineTo(x, y - height);
      ctx.closePath();
      ctx.fillStyle = color;
      ctx.fill();
      ctx.stroke();
  };

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Responsive Canvas
    const dpr = window.devicePixelRatio || 1;
    const rect = canvas.getBoundingClientRect();
    canvas.width = rect.width * dpr;
    canvas.height = rect.height * dpr;
    ctx.scale(dpr, dpr);

    const width = rect.width;
    const height = rect.height;

    // Clear
    ctx.clearRect(0, 0, width, height);

    // Background Grid (Retro Floor)
    const centerX = width / 2;
    const bottomY = height - 50;

    // Calculate Max Metric for Scaling
    let maxVal = 0;
    chain.calls.forEach(c => maxVal = Math.max(maxVal, getMetric(c)));
    chain.puts.forEach(p => maxVal = Math.max(maxVal, getMetric(p)));
    if (maxVal === 0) maxVal = 1;

    // Filter Visible Strikes (Centered around ATM)
    // We want to show ~20 strikes, centered on current price
    const atmIndex = chain.calls.findIndex(c => c.strike >= chain.currentPrice);
    const startIndex = Math.max(0, atmIndex - 12);
    const endIndex = Math.min(chain.calls.length, atmIndex + 12);

    const visibleCalls = chain.calls.slice(startIndex, endIndex);
    const visiblePuts = chain.puts.slice(startIndex, endIndex);

    // Draw Central Axis (The "River")
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.1)';
    ctx.beginPath();
    ctx.moveTo(centerX, 0);
    ctx.lineTo(centerX, height);
    ctx.stroke();

    // Hit regions for mouse interaction
    const hitRegions: any[] = [];

    // Render Loop
    visibleCalls.forEach((call, i) => {
        const put = visiblePuts[i];
        if (!call || !put) return;

        // Position
        // We render from back to front to get stacking right? 
        // Actually for this top-down iso view, drawing order matters less if they don't overlap vertically
        // But let's center them vertically

        const yPos = 100 + (i * (BAR_WIDTH + BAR_GAP));

        // --- Call Bar (Left) ---
        const callH = (getMetric(call) / maxVal) * MAX_BAR_HEIGHT;
        const callX = centerX - 20 - BAR_WIDTH; // Offset left

        // Dynamic Color based on IV (Hotter = Higher IV)
        // Base Cyan (200), shift towards White/Blue
        const callIvIntensity = Math.min(call.impliedVolatility / 100, 1); 
        const callColor = `hsla(${180 + (callIvIntensity * 40)}, 80%, 60%, 0.8)`;
        const callSide = `hsla(${180 + (callIvIntensity * 40)}, 80%, 40%, 0.8)`;
        const callTop = `hsla(${180 + (callIvIntensity * 40)}, 80%, 80%, 0.9)`;

        // Draw Call
        drawCube(ctx, callX - callH, yPos, callH, BAR_WIDTH, callColor, callSide, callTop, false);

        // Add Hit Region (Approximate for hover)
        hitRegions.push({
            x: callX - callH, y: yPos - BAR_WIDTH, w: callH + 20, h: BAR_WIDTH + 10,
            contract: call, type: 'call'
        });

        // --- Put Bar (Right) ---
        const putH = (getMetric(put) / maxVal) * MAX_BAR_HEIGHT;
        const putX = centerX + 20; // Offset right

        // Base Rose (340)
        const putIvIntensity = Math.min(put.impliedVolatility / 100, 1);
        const putColor = `hsla(${330 + (putIvIntensity * 20)}, 80%, 60%, 0.8)`;
        const putSide = `hsla(${330 + (putIvIntensity * 20)}, 80%, 40%, 0.8)`;
        const putTop = `hsla(${330 + (putIvIntensity * 20)}, 80%, 80%, 0.9)`;

        drawCube(ctx, putX, yPos, putH, BAR_WIDTH, putColor, putSide, putTop, false);

        hitRegions.push({
            x: putX, y: yPos - BAR_WIDTH, w: putH + 20, h: BAR_WIDTH + 10,
            contract: put, type: 'put'
        });

        // --- Strike Label (Center) ---
        ctx.fillStyle = '#64748b';
        ctx.font = '10px monospace';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';

        // Highlight ATM
        const isAtm = Math.abs(call.strike - chain.currentPrice) < (chain.currentPrice * 0.005);
        if (isAtm) {
            ctx.fillStyle = '#fbbf24'; // Amber
            ctx.font = 'bold 11px monospace';
            // Draw Spot Line
            ctx.beginPath();
            ctx.moveTo(0, yPos + BAR_WIDTH/2);
            ctx.lineTo(width, yPos + BAR_WIDTH/2);
            ctx.strokeStyle = 'rgba(251, 191, 36, 0.3)';
            ctx.setLineDash([4, 4]);
            ctx.stroke();
            ctx.setLineDash([]);
        }

        ctx.fillText(call.strike.toString(), centerX, yPos + BAR_WIDTH/2);
    });

    // Store regions for event handler
    (canvas as any).hitRegions = hitRegions;

  }, [chain, metric]);

  // Interaction
  const handleMouseMove = (e: React.MouseEvent) => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const rect = canvas.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;

      const regions = (canvas as any).hitRegions || [];
      let found = null;

      // Simple hit detection
      for (const region of regions) {
          if (x >= region.x && x <= region.x + region.w && y >= region.y && y <= region.y + region.h) {
              found = region;
              break;
          }
      }

      if (found) {
          setHoverData({ x: e.clientX, y: e.clientY, contract: found.contract, type: found.type });
      } else {
          setHoverData(null);
      }
  };

  const handleLeave = () => setHoverData(null);

  const handleClick = () => {
      if (hoverData && onSelectContract) {
          onSelectContract(hoverData.contract);
      }
  };

  return (
    <div className="relative w-full h-full bg-slate-950 rounded-xl overflow-hidden cursor-crosshair group">
        <canvas 
            ref={canvasRef} 
            className="w-full h-full block"
            onMouseMove={handleMouseMove}
            onMouseLeave={handleLeave}
            onClick={handleClick}
        />

        {/* Tooltip HUD */}
        {hoverData && (
            <div 
                className="fixed z-50 bg-slate-900/90 backdrop-blur-xl border border-white/10 p-3 rounded-xl shadow-2xl pointer-events-none animate-fade-in"
                style={{ left: hoverData.x + 20, top: hoverData.y - 20 }}
            >
                <div className="flex items-center gap-2 mb-2 border-b border-white/10 pb-2">
                    <span className={`text-xs font-bold uppercase px-1.5 py-0.5 rounded ${hoverData.type === 'call' ? 'bg-emerald-500/20 text-emerald-400' : 'bg-rose-500/20 text-rose-400'}`}>
                        {hoverData.type}
                    </span>
                    <span className="text-sm font-mono font-bold text-white">${hoverData.contract.strike}</span>
                </div>
                <div className="grid grid-cols-2 gap-x-4 gap-y-1 text-xs">
                    <span className="text-slate-500">Premium</span>
                    <span className="text-white font-mono text-right">${hoverData.contract.lastPrice.toFixed(2)}</span>

                    <span className="text-slate-500">{metric === 'volume' ? 'Volume' : 'Open Int'}</span>
                    <span className="text-indigo-300 font-mono text-right font-bold">{getMetric(hoverData.contract).toLocaleString()}</span>

                    <span className="text-slate-500">Implied Vol</span>
                    <span className="text-amber-400 font-mono text-right">{hoverData.contract.impliedVolatility}%</span>
                </div>
            </div>
        )}

        {/* Labels Overlay */}
        <div className="absolute top-4 left-4 pointer-events-none flex flex-col gap-1">
            <div className="flex items-center gap-2">
                <div className="w-3 h-3 bg-cyan-500 rounded-sm shadow-[0_0_10px_#06b6d4]"></div>
                <span className="text-[10px] uppercase font-bold text-cyan-400">Calls</span>
            </div>
            <div className="flex items-center gap-2">
                <div className="w-3 h-3 bg-rose-500 rounded-sm shadow-[0_0_10px_#f43f5e]"></div>
                <span className="text-[10px] uppercase font-bold text-rose-400">Puts</span>
