import React, { useRef, useEffect, useState } from 'react';
import { OptionContract, OptionsChain } from '../types';
import { MousePointer2, Layers, BarChart3, Maximize, Activity } from 'lucide-react';

interface VisualizerProps {
  chain: OptionsChain;
  onSelectContract?: (contract: OptionContract) => void;
}

const OptionsChainVisualizer: React.FC<VisualizerProps> = ({ chain, onSelectContract }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [hoverData, setHoverData] = useState<{ x: number, y: number, contract: OptionContract, type: 'call' | 'put' } | null>(null);

  // Configuration
  const BAR_WIDTH_OI = 16;
  const BAR_WIDTH_VOL = 6;
  const BAR_GAP = 12;
  const MAX_BAR_HEIGHT = 140;
  const ANGLE = 0.5; // Isometric angle

  const drawCube = (
      ctx: CanvasRenderingContext2D, 
      x: number, 
      y: number, 
      width: number, 
      height: number, 
      faceColor: string, 
      sideColor: string, 
      topColor: string,
      alpha: number
  ) => {
      if (height < 2) return; // Skip tiny bars

      // Perspective offsets
      const dx = width * Math.cos(ANGLE);
      const dy = width * Math.sin(ANGLE);

      ctx.save();
      ctx.globalAlpha = alpha;
      ctx.lineWidth = 1;
      ctx.lineJoin = 'round';

      // Top Face
      ctx.beginPath();
      ctx.moveTo(x, y - height);
      ctx.lineTo(x + dx, y - height - dy);
      ctx.lineTo(x + dx + width, y - height - dy);
      ctx.lineTo(x + width, y - height);
      ctx.closePath();
      ctx.fillStyle = topColor;
      ctx.fill();
      ctx.strokeStyle = sideColor;
      ctx.stroke();

      // Right Face
      ctx.beginPath();
      ctx.moveTo(x + width, y - height);
      ctx.lineTo(x + width + dx, y - height - dy);
      ctx.lineTo(x + width + dx, y - dy);
      ctx.lineTo(x + width, y);
      ctx.closePath();
      ctx.fillStyle = sideColor;
      ctx.fill();
      ctx.stroke();

      // Front Face
      ctx.beginPath();
      ctx.moveTo(x, y);
      ctx.lineTo(x + width, y);
      ctx.lineTo(x + width, y - height);
      ctx.lineTo(x, y - height);
      ctx.closePath();
      ctx.fillStyle = faceColor;
      ctx.fill();
      ctx.stroke();

      ctx.restore();
  };

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Responsive Canvas
    const dpr = window.devicePixelRatio || 1;
    const rect = canvas.getBoundingClientRect();
    canvas.width = rect.width * dpr;
    canvas.height = rect.height * dpr;
    ctx.scale(dpr, dpr);

    const width = rect.width;
    const height = rect.height;

    // Clear
    ctx.clearRect(0, 0, width, height);

    // Background Grid
    const centerX = width / 2;

    // Calculate Max Metrics independently for Scaling
    let maxVol = 0;
    let maxOI = 0;
    chain.calls.forEach(c => {
        maxVol = Math.max(maxVol, c.volume);
        maxOI = Math.max(maxOI, c.openInterest);
    });
    chain.puts.forEach(p => {
        maxVol = Math.max(maxVol, p.volume);
        maxOI = Math.max(maxOI, p.openInterest);
    });

    if (maxVol === 0) maxVol = 1;
    if (maxOI === 0) maxOI = 1;

    // Filter Visible Strikes (Centered around ATM)
    const atmIndex = chain.calls.findIndex(c => c.strike >= chain.currentPrice);
    const startIndex = Math.max(0, atmIndex - 10);
    const endIndex = Math.min(chain.calls.length, atmIndex + 10);

    const visibleCalls = chain.calls.slice(startIndex, endIndex);
    const visiblePuts = chain.puts.slice(startIndex, endIndex);

    // Draw Central Axis (The "River")
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.1)';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(centerX, 0);
    ctx.lineTo(centerX, height);
    ctx.stroke();

    // Draw Spot Price Laser if visible
    const centerIndex = visibleCalls.findIndex(c => c.strike >= chain.currentPrice);
    if (centerIndex !== -1) {
        // We approximate Y position later, but a general glow is nice
    }

    const hitRegions: any[] = [];

    // Render Loop
    visibleCalls.forEach((call, i) => {
        const put = visiblePuts[i];
        if (!call || !put) return;

        const yPos = 80 + (i * (BAR_WIDTH_OI + BAR_GAP));

        // --- CALLS (Left Side) ---
        const callX = centerX - 40 - BAR_WIDTH_OI; 

        // 1. OI Building (Translucent Structure)
        const callOiH = (call.openInterest / maxOI) * MAX_BAR_HEIGHT;
        const callBaseColor = `hsla(180, 80%, 60%, 1)`; // Cyan
        // Darker sides for depth
        const callOiSide = `hsla(180, 80%, 30%, 1)`;
        const callOiTop = `hsla(180, 80%, 80%, 1)`;

        drawCube(ctx, callX, yPos, BAR_WIDTH_OI, callOiH, 
            'rgba(6, 182, 212, 0.15)', // Glassy Face
            callOiSide, 
            callOiTop, 
            0.4 // Alpha
        );

        // 2. Volume Core (Solid Bright Pillar inside/front)
        const callVolH = (call.volume / maxVol) * MAX_BAR_HEIGHT;
        // Center the volume bar relative to the OI bar
        const volOffset = (BAR_WIDTH_OI - BAR_WIDTH_VOL) / 2;

        drawCube(ctx, callX + volOffset, yPos + 2, BAR_WIDTH_VOL, callVolH,
            '#ffffff', // Bright Core
            '#a5f3fc',
            '#ffffff',
            0.9
        );

        // Interaction Hitbox (Covering max height area)
        hitRegions.push({
            x: callX, y: yPos - Math.max(callOiH, callVolH), 
            w: BAR_WIDTH_OI + 20, h: Math.max(callOiH, callVolH) + 20,
            contract: call, type: 'call'
        });


        // --- PUTS (Right Side) ---
        const putX = centerX + 40;

        // 1. OI Building
        const putOiH = (put.openInterest / maxOI) * MAX_BAR_HEIGHT;
        const putOiSide = `hsla(340, 80%, 30%, 1)`;
        const putOiTop = `hsla(340, 80%, 80%, 1)`;

        drawCube(ctx, putX, yPos, BAR_WIDTH_OI, putOiH,
            'rgba(244, 63, 94, 0.15)', // Glassy Rose
            putOiSide,
            putOiTop,
            0.4
        );

        // 2. Volume Core
        const putVolH = (put.volume / maxVol) * MAX_BAR_HEIGHT;

        drawCube(ctx, putX + volOffset, yPos + 2, BAR_WIDTH_VOL, putVolH,
            '#ffffff',
            '#fda4af',
            '#ffffff',
            0.9
        );

        hitRegions.push({
            x: putX, y: yPos - Math.max(putOiH, putVolH),
            w: BAR_WIDTH_OI + 20, h: Math.max(putOiH, putVolH) + 20,
            contract: put, type: 'put'
        });


        // --- Strike Label ---
        const isAtm = Math.abs(call.strike - chain.currentPrice) < (chain.currentPrice * 0.005);
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';

        if (isAtm) {
            ctx.shadowBlur = 10;
            ctx.shadowColor = '#fbbf24';
            ctx.fillStyle = '#fbbf24';
            ctx.font = 'bold 12px monospace';

            // Draw ATM Line
            ctx.beginPath();
            ctx.moveTo(0, yPos + BAR_WIDTH_OI/2);
            ctx.lineTo(width, yPos + BAR_WIDTH_OI/2);
            ctx.strokeStyle = 'rgba(251, 191, 36, 0.4)';
            ctx.setLineDash([4, 4]);
            ctx.stroke();
            ctx.setLineDash([]);
        } else {
            ctx.shadowBlur = 0;
            ctx.fillStyle = '#64748b';
            ctx.font = '10px monospace';
        }

        ctx.fillText(call.strike.toString(), centerX, yPos + BAR_WIDTH_OI/2);
        ctx.shadowBlur = 0;
    });

    // Store regions
    (canvas as any).hitRegions = hitRegions;

  }, [chain]);

  // Interaction
  const handleMouseMove = (e: React.MouseEvent) => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const rect = canvas.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;

      const regions = (canvas as any).hitRegions || [];
      let found = null;

      for (const region of regions) {
          if (x >= region.x && x <= region.x + region.w && y >= region.y && y <= region.y + region.h) {
              found = region;
              break;
          }
      }

      if (found) {
          setHoverData({ x: e.clientX, y: e.clientY, contract: found.contract, type: found.type });
      } else {
          setHoverData(null);
      }
  };

  const handleLeave = () => setHoverData(null);

  const handleClick = () => {
      if (hoverData && onSelectContract) {
          onSelectContract(hoverData.contract);
      }
  };

  return (
    <div className="relative w-full h-full bg-slate-950 rounded-xl overflow-hidden cursor-crosshair group">
        <canvas 
            ref={canvasRef} 
            className="w-full h-full block"
            onMouseMove={handleMouseMove}
            onMouseLeave={handleLeave}
            onClick={handleClick}
        />

        {/* Hover Hologram */}
        {hoverData && (
            <div 
                className="fixed z-50 bg-slate-900/95 backdrop-blur-xl border border-white/10 p-4 rounded-xl shadow-2xl pointer-events-none animate-fade-in min-w-[200px]"
                style={{ left: hoverData.x + 20, top: hoverData.y - 40 }}
            >
                <div className="flex items-center justify-between mb-3 border-b border-white/10 pb-2">
                    <span className={`text-xs font-bold uppercase px-2 py-0.5 rounded ${hoverData.type === 'call' ? 'bg-cyan-500/20 text-cyan-400' : 'bg-rose-500/20 text-rose-400'}`}>
                        {hoverData.type}
                    </span>
                    <span className="text-lg font-mono font-bold text-white tracking-tight">${hoverData.contract.strike}</span>
                </div>

                <div className="space-y-3">
                    {/* Volume Metric */}
                    <div className="flex items-center justify-between gap-4">
                        <div className="flex items-center gap-2">
                            <div className="w-1.5 h-1.5 bg-white rounded-full shadow-[0_0_8px_white]"></div>
                            <span className="text-xs text-slate-400 uppercase font-bold">Volume</span>
                        </div>
                        <span className="text-white font-mono font-bold">{hoverData.contract.volume.toLocaleString()}</span>
                    </div>

                    {/* OI Metric */}
                    <div className="flex items-center justify-between gap-4">
