                            <div className={`w-3 h-3 rounded border ${hoverData.type === 'call' ? 'border-cyan-500 bg-cyan-500/20' : 'border-rose-500 bg-rose-500/20'}`}></div>
                            <span className="text-xs text-slate-400 uppercase font-bold">Open Int</span>
                        </div>
                        <span className={`font-mono font-bold ${hoverData.type === 'call' ? 'text-cyan-400' : 'text-rose-400'}`}>
                            {hoverData.contract.openInterest.toLocaleString()}
