import React, { useRef, useEffect, useState, useMemo } from 'react';
import { OptionContract, OptionsChain } from '../types';
import { MousePointer2, Maximize, Zap, Layers } from 'lucide-react';

interface VisualizerProps {
  chain: OptionsChain;
  onSelectContract?: (contract: OptionContract) => void;
}

interface Particle {
  x: number;
  y: number;
  z: number;
  speed: number;
  offset: number; // Random starting pos
  brightness: number;
}

interface StreamData {
    particles: Particle[];
    height: number;
    contract: OptionContract;
    type: 'call' | 'put';
    xBase: number;
    zBase: number;
    colorBase: string; // hsl string base
}

const OptionsChainVisualizer: React.FC<VisualizerProps> = ({ chain, onSelectContract }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [hoverData, setHoverData] = useState<{ x: number, y: number, contract: OptionContract, type: 'call' | 'put' } | null>(null);
  const animationRef = useRef<number>(0);
  const timeRef = useRef<number>(0);

  // --- Configuration ---
  const MAX_HEIGHT = 180;
  const BAR_WIDTH = 24;
  const BAR_DEPTH = 24;
  const GAP = 10;
  const ANGLE_X = 0.6; // Pitch
  const ANGLE_Z = 0.6; // Yaw (Isometric-ish)

  // Helper to map 3D point to 2D screen
  const project = (x: number, y: number, z: number, centerX: number, centerY: number) => {
      // Iso projection
      const x2d = (x - z) * Math.cos(ANGLE_Z);
      const y2d = (x + z) * Math.sin(ANGLE_Z) - y;
      return { 
          x: centerX + x2d, 
          y: centerY + y2d 
      };
  };

  // --- Data Preparation ---
  // We prepare the particle systems once when chain changes to avoid doing it every frame
  const streams = useMemo(() => {
      const s: StreamData[] = [];
      if (!chain) return s;

      // Scaling Factors
      let maxOI = 0;
      let maxVol = 0;

      chain.calls.forEach(c => { maxOI = Math.max(maxOI, c.openInterest); maxVol = Math.max(maxVol, c.volume); });
      chain.puts.forEach(p => { maxOI = Math.max(maxOI, p.openInterest); maxVol = Math.max(maxVol, p.volume); });

      if (maxOI === 0) maxOI = 1;
      if (maxVol === 0) maxVol = 1;

      // Filter visible range (approx +/- 12 strikes from ATM)
      const atmIndex = chain.calls.findIndex(c => c.strike >= chain.currentPrice);
      const startIndex = Math.max(0, atmIndex - 12);
      const endIndex = Math.min(chain.calls.length, atmIndex + 12);

      const visibleCalls = chain.calls.slice(startIndex, endIndex);
      const visiblePuts = chain.puts.slice(startIndex, endIndex);

      // Generate Streams
      visibleCalls.forEach((call, i) => {
          const put = visiblePuts[i];
          if (!call || !put) return;

          // Z-position (Row index)
          // We center 0 at the ATM strike visually
          const z = (i - (visibleCalls.length / 2)) * (BAR_DEPTH + GAP);

          // CALLS (Left)
          const callHeight = Math.max(10, (call.openInterest / maxOI) * MAX_HEIGHT);
          // Density: Map volume to particle count (0 to 20 particles per bar)
          const callDensity = Math.ceil((call.volume / maxVol) * 25);
          const callParticles: Particle[] = [];
          for(let k=0; k<callDensity; k++) {
              callParticles.push({
                  x: (Math.random() - 0.5) * (BAR_WIDTH * 0.8), // Internal distribution
                  y: Math.random() * callHeight,
                  z: (Math.random() - 0.5) * (BAR_DEPTH * 0.8),
                  speed: 0.5 + Math.random() * 1.5, // Variable speed based on "energy"
                  offset: Math.random() * 100,
                  brightness: 0.5 + Math.random() * 0.5
              });
          }

          s.push({
              particles: callParticles,
              height: callHeight,
              contract: call,
              type: 'call',
              xBase: -40 - BAR_WIDTH, // Left offset
              zBase: z,
              colorBase: '180, 100%, 50%' // Cyan
          });

          // PUTS (Right)
          const putHeight = Math.max(10, (put.openInterest / maxOI) * MAX_HEIGHT);
          const putDensity = Math.ceil((put.volume / maxVol) * 25);
          const putParticles: Particle[] = [];
          for(let k=0; k<putDensity; k++) {
              putParticles.push({
                  x: (Math.random() - 0.5) * (BAR_WIDTH * 0.8),
                  y: Math.random() * putHeight,
                  z: (Math.random() - 0.5) * (BAR_DEPTH * 0.8),
                  speed: 0.5 + Math.random() * 1.5,
                  offset: Math.random() * 100,
                  brightness: 0.5 + Math.random() * 0.5
              });
          }

          s.push({
              particles: putParticles,
              height: putHeight,
              contract: put,
              type: 'put',
              xBase: 40, // Right offset
              zBase: z,
              colorBase: '330, 100%, 50%' // Rose
          });
