      // --- Background Grid (Floor) ---
      // Simple perspective lines to give depth context
      ctx.strokeStyle = 'rgba(255, 255, 255, 0.05)';
      ctx.lineWidth = 1;

      const gridRange = 400;
      const gridStep = 40;

