          // --- 1. Draw OI Structure (The Glass Pillar) ---
          // Front-Left Corner
          const p1 = project(stream.xBase, 0, stream.zBase, centerX, centerY);
          const p2 = project(stream.xBase + BAR_WIDTH, 0, stream.zBase, centerX, centerY);
          const p3 = project(stream.xBase + BAR_WIDTH, 0, stream.zBase + BAR_DEPTH, centerX, centerY);
          const p4 = project(stream.xBase, 0, stream.zBase + BAR_DEPTH, centerX, centerY);

          // Tops
          const t1 = project(stream.xBase, stream.height, stream.zBase, centerX, centerY);
          const t2 = project(stream.xBase + BAR_WIDTH, stream.height, stream.zBase, centerX, centerY);
          const t3 = project(stream.xBase + BAR_WIDTH, stream.height, stream.zBase + BAR_DEPTH, centerX, centerY);
