          ctx.moveTo(t1.x, t1.y); ctx.lineTo(t2.x, t2.y); ctx.lineTo(t3.x, t3.y); ctx.lineTo(t4.x, t4.y); ctx.closePath();
          ctx.fillStyle = `hsla(${stream.colorBase}, 0.2)`;
          ctx.fill();
          ctx.stroke();

