          ctx.moveTo(p2.x, p2.y); ctx.lineTo(t2.x, t2.y);
          ctx.moveTo(p3.x, p3.y); ctx.lineTo(t3.x, t3.y);
          ctx.moveTo(p4.x, p4.y); ctx.lineTo(t4.x, t4.y);
