              if (yNorm < 0.1) alpha = yNorm * 10;
              if (yNorm > 0.8) alpha = (1 - yNorm) * 5;

              const pp = project(stream.xBase + BAR_WIDTH/2 + p.x, yPos, stream.zBase + BAR_DEPTH/2 + p.z, centerX, centerY);

              const particleSize = 1.5 * p.brightness;
              ctx.fillStyle = `hsla(${stream.colorBase}, ${alpha})`;
              ctx.beginPath();
              ctx.arc(pp.x, pp.y, particleSize, 0, Math.PI * 2);
              ctx.fill();
          });

          // --- 3. Strike Label (Center) ---
          // Draw this only once per row (e.g. if it's the Call stream, draw the label to its right)
          if (stream.type === 'call') {
              const labelPos = project(0, 0, stream.zBase + BAR_DEPTH/2, centerX, centerY);
              const isAtm = Math.abs(stream.contract.strike - chain.currentPrice) < (chain.currentPrice * 0.005);

              ctx.textAlign = 'center';
              ctx.textBaseline = 'middle';

              if (isAtm) {
                  ctx.fillStyle = '#fbbf24';
                  ctx.font = 'bold 12px monospace';
                  ctx.shadowColor = '#fbbf24';
                  ctx.shadowBlur = 10;
              } else {
                  ctx.fillStyle = '#64748b';
                  ctx.font = '10px monospace';
                  ctx.shadowBlur = 0;
              }

              ctx.fillText(stream.contract.strike.toString(), labelPos.x, labelPos.y);
              ctx.shadowBlur = 0;
          }
      });

      // Save hit regions to canvas element for event handler
      (canvas as any).hitRegions = regions;
  };

  const loop = () => {
      timeRef.current += 1;
      draw();
      animationRef.current = requestAnimationFrame(loop);
  };

  useEffect(() => {
      const canvas = canvasRef.current;
      if (canvas) {
          const rect = canvas.getBoundingClientRect();
          const dpr = window.devicePixelRatio || 1;
          canvas.width = rect.width * dpr;
          canvas.height = rect.height * dpr;
          const ctx = canvas.getContext('2d');
          if (ctx) ctx.scale(dpr, dpr);
      }

      animationRef.current = requestAnimationFrame(loop);
      return () => cancelAnimationFrame(animationRef.current);
  }, [streams, hoverData]); // Re-render when hover changes to highlight

  // Interaction
  const handleMouseMove = (e: React.MouseEvent) => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const rect = canvas.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;

      const regions = (canvas as any).hitRegions || [];
      let found = null;

      // Simple distance check to projected centers
      let minDist = 40; 

      for (const r of regions) {
          // We stored 'center' in region data during draw
          // Since bars are vertical, we check roughly if mouse is "above" the base within height
          const dx = x - r.center.x;
          // In screen space, Y goes down. Top is lower Y.
          // Check if mouse Y is between base Y and top Y (roughly)
          const dy = Math.abs(y - (r.center.y - r.h/2)); // Very rough approx

          const dist = Math.sqrt(dx*dx + dy*dy);
          if (dist < minDist) {
              minDist = dist;
              found = r;
          }
      }

      if (found) {
          setHoverData({ contract: found.contract, type: found.type });
      } else {
          setHoverData(null);
      }
  };

  const handleClick = () => {
      if (hoverData && onSelectContract) {
          onSelectContract(hoverData.contract);
      }
  };

  return (
    <div className="relative w-full h-full bg-slate-950 rounded-xl overflow-hidden cursor-crosshair group">
        <canvas 
            ref={canvasRef} 
            className="w-full h-full block"
            onMouseMove={handleMouseMove}
            onMouseLeave={() => setHoverData(null)}
            onClick={handleClick}
        />

        {/* Fixed Info Card (Inspector) */}
        <div className="absolute top-4 right-4 w-60 bg-slate-900/90 backdrop-blur-xl border border-white/10 p-4 rounded-xl shadow-2xl pointer-events-none transition-all duration-200 min-h-[160px] flex flex-col justify-center">
            {hoverData ? (
                <>
                    <div className="flex items-center justify-between mb-3 border-b border-white/10 pb-2 animate-fade-in">
