import React, { useRef, useEffect, useState, useMemo } from 'react';
import { OptionContract, OptionsChain } from '../types';
import { MousePointer2, Maximize, Zap, Layers, Activity, Calendar } from 'lucide-react';

interface VisualizerProps {
  chain: OptionsChain;
  onSelectContract?: (contract: OptionContract) => void;
}

interface Particle {
  x: number;
  y: number;
  z: number;
  speed: number;
  offset: number; // Random starting pos
  brightness: number;
}

interface StreamData {
    particles: Particle[];
    height: number;
    contract: OptionContract;
    type: 'call' | 'put';
    xBase: number;
    zBase: number;
    colorBase: string; // hsl string base
    index: number;
}

const OptionsChainVisualizer: React.FC<VisualizerProps> = ({ chain, onSelectContract }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [hoverData, setHoverData] = useState<{ contract: OptionContract, type: 'call' | 'put' } | null>(null);
  const animationRef = useRef<number>(0);
  const timeRef = useRef<number>(0);

  // --- Configuration ---
  const MAX_HEIGHT = 200;
  const BAR_WIDTH = 14; // Thinner for density
  const BAR_DEPTH = 30; // Thicker depth for visibility
  const GAP = 6;
  const ROW_GAP = 20; // Gap between Call and Put rows
  const ANGLE_X = 0.5; // Pitch
  const ANGLE_Z = 0.0; // Yaw (0 for straight on, slight angle for 3D)

  // Custom Projector for Horizontal Layout
  // We want strikes along X, Height along Y, Calls/Puts separated by Z depth
  const project = (x: number, y: number, z: number, centerX: number, centerY: number) => {
      // Simple perspective projection with slight isometric tilt
      const perspective = 800;
      const scale = perspective / (perspective + z);

      // Tilt camera down slightly
      const tilt = 0.3; 
      const yTilted = y * Math.cos(tilt) - z * Math.sin(tilt);
      const zTilted = y * Math.sin(tilt) + z * Math.cos(tilt);

      return { 
          x: centerX + x * scale, 
          y: centerY - yTilted * scale,
          scale: scale 
      };
  };

  // --- Data Preparation ---
  const streams = useMemo(() => {
      const s: StreamData[] = [];
      if (!chain) return s;

      // Scaling Factors
      let maxOI = 0;
      let maxVol = 0;

      chain.calls.forEach(c => { maxOI = Math.max(maxOI, c.openInterest); maxVol = Math.max(maxVol, c.volume); });
      chain.puts.forEach(p => { maxOI = Math.max(maxOI, p.openInterest); maxVol = Math.max(maxVol, p.volume); });

      if (maxOI === 0) maxOI = 1;
      if (maxVol === 0) maxVol = 1;

      // Dynamic Range based on typical screen width
      // Show ~40 strikes (+/- 20)
      const atmIndex = chain.calls.findIndex(c => c.strike >= chain.currentPrice);
      const visibleCount = 40;
      const halfCount = Math.floor(visibleCount / 2);
      const startIndex = Math.max(0, atmIndex - halfCount);
      const endIndex = Math.min(chain.calls.length, startIndex + visibleCount);

      const visibleCalls = chain.calls.slice(startIndex, endIndex);
      const visiblePuts = chain.puts.slice(startIndex, endIndex);

      // Generate Streams
      visibleCalls.forEach((call, i) => {
          const put = visiblePuts[i];
          if (!call || !put) return;

          // X-position (Horizontal distribution)
          const x = (i - (visibleCalls.length / 2)) * (BAR_WIDTH + GAP);

          // CALLS (Back Row)
          // Z-position: Pushed back
          const zCall = ROW_GAP; 

          const callHeight = Math.max(5, (call.openInterest / maxOI) * MAX_HEIGHT);
          const callDensity = Math.ceil((call.volume / maxVol) * 20); // 0-20 particles
          const callParticles: Particle[] = [];
          for(let k=0; k<callDensity; k++) {
              callParticles.push({
                  x: (Math.random() - 0.5) * (BAR_WIDTH * 0.8),
                  y: Math.random() * callHeight,
                  z: (Math.random() - 0.5) * (BAR_DEPTH * 0.8),
                  speed: 0.5 + Math.random() * 2.0,
                  offset: Math.random() * 100,
                  brightness: 0.5 + Math.random() * 0.5
              });
          }

          s.push({
              particles: callParticles,
              height: callHeight,
              contract: call,
              type: 'call',
              xBase: x,
              zBase: zCall,
              colorBase: '180, 100%, 50%', // Cyan
              index: i
          });

          // PUTS (Front Row)
          // Z-position: Pulled forward
          const zPut = -ROW_GAP - BAR_DEPTH;

          const putHeight = Math.max(5, (put.openInterest / maxOI) * MAX_HEIGHT);
          const putDensity = Math.ceil((put.volume / maxVol) * 20);
          const putParticles: Particle[] = [];
          for(let k=0; k<putDensity; k++) {
              putParticles.push({
                  x: (Math.random() - 0.5) * (BAR_WIDTH * 0.8),
                  y: Math.random() * putHeight,
                  z: (Math.random() - 0.5) * (BAR_DEPTH * 0.8),
                  speed: 0.5 + Math.random() * 2.0,
                  offset: Math.random() * 100,
                  brightness: 0.5 + Math.random() * 0.5
              });
          }

          s.push({
              particles: putParticles,
              height: putHeight,
              contract: put,
              type: 'put',
              xBase: x,
              zBase: zPut,
              colorBase: '330, 100%, 50%', // Rose
              index: i
          });
      });

      return s;
  }, [chain]);


  const draw = () => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      const width = canvas.width;
      const height = canvas.height;
      const centerX = width / 2;
      const centerY = height / 2 + 50; 

      ctx.clearRect(0, 0, width, height);

      // --- Background Grid ---
      ctx.strokeStyle = 'rgba(255, 255, 255, 0.05)';
      ctx.lineWidth = 1;

      // Draw Horizon Line
      const pStart = project(-1000, 0, 0, centerX, centerY);
      const pEnd = project(1000, 0, 0, centerX, centerY);
      ctx.beginPath();
      ctx.moveTo(pStart.x, pStart.y);
      ctx.lineTo(pEnd.x, pEnd.y);
      ctx.stroke();

      const regions: any[] = [];

      // Sort by Z (Painters Algo: Draw Back to Front)
      // High Z is further away in our coordinate system
      const sortedStreams = [...streams].sort((a, b) => b.zBase - a.zBase);

      sortedStreams.forEach(stream => {
          const isHovered = hoverData && hoverData.contract.strike === stream.contract.strike && hoverData.type === stream.type;

          // Vertices
          // Base
          const b1 = project(stream.xBase, 0, stream.zBase, centerX, centerY);
          const b2 = project(stream.xBase + BAR_WIDTH, 0, stream.zBase, centerX, centerY);
          const b3 = project(stream.xBase + BAR_WIDTH, 0, stream.zBase + BAR_DEPTH, centerX, centerY);
          const b4 = project(stream.xBase, 0, stream.zBase + BAR_DEPTH, centerX, centerY);

          // Top
          const t1 = project(stream.xBase, stream.height, stream.zBase, centerX, centerY);
          const t2 = project(stream.xBase + BAR_WIDTH, stream.height, stream.zBase, centerX, centerY);
          const t3 = project(stream.xBase + BAR_WIDTH, stream.height, stream.zBase + BAR_DEPTH, centerX, centerY);
          const t4 = project(stream.xBase, stream.height, stream.zBase + BAR_DEPTH, centerX, centerY);

          // Draw Order: Back Face -> Side Faces -> Top Face -> Front Face
          // Actually just filling with opacity creates volume look

          const baseColor = isHovered ? `hsla(${stream.colorBase}, 0.8)` : `hsla(${stream.colorBase}, 0.15)`;
          const strokeColor = isHovered ? `hsla(${stream.colorBase}, 1.0)` : `hsla(${stream.colorBase}, 0.3)`;

          // Top
          ctx.beginPath();
          ctx.moveTo(t1.x, t1.y); ctx.lineTo(t2.x, t2.y); ctx.lineTo(t3.x, t3.y); ctx.lineTo(t4.x, t4.y); ctx.closePath();
          ctx.fillStyle = isHovered ? `hsla(${stream.colorBase}, 0.4)` : `hsla(${stream.colorBase}, 0.2)`;
          ctx.fill();
          ctx.strokeStyle = strokeColor;
          ctx.stroke();

          // Front (b1-b2-t2-t1) if facing camera?
          // Since we tilt down, we see Top, Front, and maybe Side.
          // Front Face
          ctx.beginPath();
          ctx.moveTo(b1.x, b1.y); ctx.lineTo(b2.x, b2.y); ctx.lineTo(t2.x, t2.y); ctx.lineTo(t1.x, t1.y); ctx.closePath();
          ctx.fillStyle = baseColor;
          ctx.fill();
          ctx.stroke();

          // Right Side (b2-b3-t3-t2)
          ctx.beginPath();
          ctx.moveTo(b2.x, b2.y); ctx.lineTo(b3.x, b3.y); ctx.lineTo(t3.x, t3.y); ctx.lineTo(t2.x, t2.y); ctx.closePath();
          ctx.fillStyle = `hsla(${stream.colorBase}, 0.1)`;
          ctx.fill();
          ctx.stroke();

          // Hit Region (Use Front Face bounds approx)
          regions.push({
              x: t1.x, y: t1.y,
              w: Math.abs(t2.x - t1.x) + 5, // add padding
              h: Math.abs(b1.y - t1.y) + 5,
              center: { x: (t1.x + t2.x)/2, y: (t1.y + b1.y)/2 },
              contract: stream.contract,
              type: stream.type
          });

          // Particles
          stream.particles.forEach(p => {
              // Age and reset
              const age = (timeRef.current * p.speed + p.offset) % 100;
              const yNorm = age / 100;

              // Fade in/out
              let alpha = p.brightness;
              if (yNorm < 0.1) alpha *= yNorm * 10;
              if (yNorm > 0.8) alpha *= (1 - yNorm) * 5;

              const pp = project(
                  stream.xBase + BAR_WIDTH/2 + p.x, 
                  yNorm * stream.height, 
                  stream.zBase + BAR_DEPTH/2 + p.z, 
                  centerX, centerY
              );

              ctx.beginPath();
              ctx.fillStyle = `hsla(${stream.colorBase}, ${alpha})`;
              ctx.arc(pp.x, pp.y, 1.5 * pp.scale, 0, Math.PI * 2);
              ctx.fill();
          });

          // Strike Labels (Draw once per column)
          if (stream.type === 'put') { // Put is front row
              const pLabel = project(stream.xBase + BAR_WIDTH/2, -10, 0, centerX, centerY);
              const isAtm = Math.abs(stream.contract.strike - chain.currentPrice) < (chain.currentPrice * 0.005);

              if (isAtm || stream.index % 5 === 0) { // Only every 5th strike to avoid clutter
                  ctx.textAlign = 'center';
                  ctx.fillStyle = isAtm ? '#fbbf24' : '#64748b';
                  ctx.font = isAtm ? 'bold 12px monospace' : '10px monospace';
                  ctx.fillText(stream.contract.strike.toString(), pLabel.x, pLabel.y + 20);

                  if (isAtm) {
                      ctx.shadowBlur = 10;
                      ctx.shadowColor = '#fbbf24';
                      ctx.beginPath();
                      ctx.arc(pLabel.x, pLabel.y, 3, 0, Math.PI * 2);
                      ctx.fill();
                      ctx.shadowBlur = 0;
                  }
              }
          }
      });

      (canvas as any).hitRegions = regions;
  };

  const loop = () => {
      timeRef.current += 1;
      draw();
      animationRef.current = requestAnimationFrame(loop);
  };

  useEffect(() => {
      const canvas = canvasRef.current;
      if (canvas) {
          const rect = canvas.getBoundingClientRect();
          const dpr = window.devicePixelRatio || 1;
          canvas.width = rect.width * dpr;
          canvas.height = rect.height * dpr;
          const ctx = canvas.getContext('2d');
          if (ctx) ctx.scale(dpr, dpr);
      }

      animationRef.current = requestAnimationFrame(loop);
      return () => cancelAnimationFrame(animationRef.current);
  }, [streams, hoverData]);

  // Interaction
  const handleMouseMove = (e: React.MouseEvent) => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const rect = canvas.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;

      const regions = (canvas as any).hitRegions || [];
      let found = null;
      let minDist = 1000;

      // Improved hit testing for 2D projection
      for (const r of regions) {
          // Check roughly bounds first
          if (x > r.x && x < r.x + r.w && y > r.y && y < r.y + r.h) {
              const dist = Math.abs(x - r.center.x); // Prioritize closer X center
              if (dist < minDist) {
                  minDist = dist;
                  found = r;
              }
          }
      }

      if (found) {
          setHoverData({ contract: found.contract, type: found.type });
      } else {
          setHoverData(null);
      }
  };

  const handleClick = () => {
      if (hoverData && onSelectContract) {
          onSelectContract(hoverData.contract);
      }
  };

  return (
    <div className="relative w-full h-full bg-slate-950 rounded-xl overflow-hidden cursor-crosshair group">
        <canvas 
            ref={canvasRef} 
            className="w-full h-full block"
            onMouseMove={handleMouseMove}
            onMouseLeave={() => setHoverData(null)}
            onClick={handleClick}
        />

        {/* Fixed Info Card (Inspector) */}
        <div className="absolute top-4 right-4 w-60 bg-slate-900/90 backdrop-blur-xl border border-white/10 p-4 rounded-xl shadow-2xl pointer-events-none transition-all duration-200 min-h-[160px] flex flex-col justify-center">
            {hoverData ? (
                <>
                    <div className="flex items-center justify-between mb-3 border-b border-white/10 pb-2 animate-fade-in">
                        <span className={`text-xs font-bold uppercase px-2 py-0.5 rounded ${hoverData.type === 'call' ? 'bg-cyan-500/20 text-cyan-400' : 'bg-rose-500/20 text-rose-400'}`}>
                            {hoverData.type}
                        </span>
                        <span className="text-xl font-mono font-bold text-white tracking-tight">${hoverData.contract.strike}</span>
                    </div>

                    <div className="space-y-3 animate-fade-in">
                        <div className="flex items-center justify-between gap-4">
                            <span className="text-xs text-slate-400 uppercase font-bold flex items-center gap-2">
                                <Zap className="w-3 h-3 text-white" /> Volume
                            </span>
                            <span className="text-white font-mono font-bold">{hoverData.contract.volume.toLocaleString()}</span>
                        </div>

                        <div className="flex items-center justify-between gap-4">
                            <span className="text-xs text-slate-400 uppercase font-bold flex items-center gap-2">
                                <Layers className="w-3 h-3 text-slate-500" /> Open Int
                            </span>
                            <span className={`font-mono font-bold ${hoverData.type === 'call' ? 'text-cyan-400' : 'text-rose-400'}`}>
                                {hoverData.contract.openInterest.toLocaleString()}
                            </span>
                        </div>

                        <div className="pt-2 border-t border-white/5 flex justify-between items-center">
                            <span className="text-[10px] text-slate-500 uppercase tracking-wider font-semibold">Premium</span>
                            <span className="text-emerald-400 font-mono text-base font-bold">${hoverData.contract.lastPrice.toFixed(2)}</span>
                        </div>
                    </div>
                </>
            ) : (
                <div className="flex flex-col items-center justify-center text-slate-600 gap-2 opacity-60">
                    <Activity className="w-8 h-8 opacity-50" />
                    <span className="text-[10px] font-bold uppercase tracking-widest">Hover to Inspect</span>
                </div>
            )}
        </div>

        {/* Legend Overlay */}
        <div className="absolute top-4 left-4 pointer-events-none flex flex-col gap-2 bg-black/40 p-2 rounded-lg border border-white/5 backdrop-blur-sm">
            <div className="flex items-center gap-2">
                <div className="w-3 h-3 bg-cyan-500/20 border border-cyan-500"></div>
                <span className="text-[10px] uppercase font-bold text-cyan-400">Calls (Back Row)</span>
            </div>
            <div className="flex items-center gap-2">
                <div className="w-3 h-3 bg-rose-500/20 border border-rose-500"></div>
                <span className="text-[10px] uppercase font-bold text-rose-400">Puts (Front Row)</span>
            </div>
            {chain && (
                <div className="mt-2 pt-2 border-t border-white/10">
                    <div className="flex items-center gap-1.5 text-slate-300">
                        <Calendar className="w-3 h-3 text-indigo-400" />
                        <span className="text-[10px] font-mono font-bold">{chain.selectedExpiration}</span>
                    </div>
                </div>
            )}
        </div>

        <div className="absolute bottom-4 left-1/2 -translate-x-1/2 text-[10px] text-slate-500 uppercase font-bold tracking-widest flex items-center gap-2 pointer-events-none opacity-50 group-hover:opacity-100 transition-opacity">
            <Maximize className="w-3 h-3" /> Liquidity Horizon
        </div>
    </div>
  );
};

export default OptionsChainVisualizer;

import React, { useRef, useEffect, useState, useMemo } from 'react';
import { OptionContract, OptionsChain } from '../types';
import { MousePointer2, Maximize, Zap, Layers, Activity, Calendar } from 'lucide-react';

interface VisualizerProps {
  chain: OptionsChain;
  onSelectContract?: (contract: OptionContract) => void;
}

interface Particle {
  x: number;
  y: number;
  z: number;
  speed: number;
  offset: number; // Random starting pos
  brightness: number;
}

interface StreamData {
    particles: Particle[];
    height: number;
    contract: OptionContract;
    type: 'call' | 'put';
    xBase: number;
    zBase: number;
    colorBase: string; // hsl string base
    index: number;
}

const OptionsChainVisualizer: React.FC<VisualizerProps> = ({ chain, onSelectContract }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [hoverData, setHoverData] = useState<{ contract: OptionContract, type: 'call' | 'put' } | null>(null);
  const animationRef = useRef<number>(0);
  const timeRef = useRef<number>(0);

  // --- Configuration ---
  const MAX_HEIGHT = 280;
  const BAR_WIDTH = 34; // Wider buildings
  const BAR_DEPTH = 34; // Deeper to match
  const GAP = 12;
  const ROW_GAP = 60; // Separation between Call/Put rows

  // Camera Angles
  const PITCH = 0.55; // Look down angle (radians)
  const YAW = -0.15;   // Slight rotation to show depth (radians)

  // Custom Projector for 3D Scene
  const project = (x: number, y: number, z: number, centerX: number, centerY: number) => {
      // 1. Rotate Y (Yaw)
      const x1 = x * Math.cos(YAW) - z * Math.sin(YAW);
      const z1 = x * Math.sin(YAW) + z * Math.cos(YAW);

      // 2. Rotate X (Pitch)
      const y2 = y * Math.cos(PITCH) - z1 * Math.sin(PITCH);
      const z2 = y * Math.sin(PITCH) + z1 * Math.cos(PITCH);

      // 3. Perspective
      const perspective = 1200;
      const scale = perspective / (perspective + z2);

      return { 
          x: centerX + x1 * scale, 
          y: centerY - y2 * scale,
          scale: scale,
          z: z2 // Depth for sorting
      };
  };

  // --- Data Preparation ---
  const streams = useMemo(() => {
      const s: StreamData[] = [];
      if (!chain) return s;

      // Scaling Factors
      let maxOI = 0;
      let maxVol = 0;

      chain.calls.forEach(c => { maxOI = Math.max(maxOI, c.openInterest); maxVol = Math.max(maxVol, c.volume); });
      chain.puts.forEach(p => { maxOI = Math.max(maxOI, p.openInterest); maxVol = Math.max(maxVol, p.volume); });

      if (maxOI === 0) maxOI = 1;
      if (maxVol === 0) maxVol = 1;

      // Dynamic Range based on typical screen width
      // Show ~40-50 strikes to fill wide screens
      const atmIndex = chain.calls.findIndex(c => c.strike >= chain.currentPrice);
      const visibleCount = 46;
      const halfCount = Math.floor(visibleCount / 2);
      const startIndex = Math.max(0, atmIndex - halfCount);
      const endIndex = Math.min(chain.calls.length, startIndex + visibleCount);

      const visibleCalls = chain.calls.slice(startIndex, endIndex);
      const visiblePuts = chain.puts.slice(startIndex, endIndex);

      // Generate Streams
      visibleCalls.forEach((call, i) => {
          const put = visiblePuts[i];
          if (!call || !put) return;

          // X-position (Horizontal distribution)
          const x = (i - (visibleCalls.length / 2)) * (BAR_WIDTH + GAP);

          // CALLS (Back Row)
          const zCall = ROW_GAP; 

          const callHeight = Math.max(5, (call.openInterest / maxOI) * MAX_HEIGHT);
          const callDensity = Math.ceil((call.volume / maxVol) * 25);
          const callParticles: Particle[] = [];
          for(let k=0; k<callDensity; k++) {
              callParticles.push({
                  x: (Math.random() - 0.5) * (BAR_WIDTH * 0.8),
                  y: Math.random() * callHeight,
                  z: (Math.random() - 0.5) * (BAR_DEPTH * 0.8),
                  speed: 0.5 + Math.random() * 2.5,
                  offset: Math.random() * 100,
                  brightness: 0.5 + Math.random() * 0.5
              });
          }

          s.push({
              particles: callParticles,
              height: callHeight,
              contract: call,
              type: 'call',
              xBase: x,
              zBase: zCall,
              colorBase: '180, 100%, 50%', // Cyan
              index: i
          });

          // PUTS (Front Row)
          const zPut = -ROW_GAP - BAR_DEPTH;

          const putHeight = Math.max(5, (put.openInterest / maxOI) * MAX_HEIGHT);
          const putDensity = Math.ceil((put.volume / maxVol) * 25);
          const putParticles: Particle[] = [];
          for(let k=0; k<putDensity; k++) {
              putParticles.push({
                  x: (Math.random() - 0.5) * (BAR_WIDTH * 0.8),
                  y: Math.random() * putHeight,
                  z: (Math.random() - 0.5) * (BAR_DEPTH * 0.8),
                  speed: 0.5 + Math.random() * 2.5,
                  offset: Math.random() * 100,
                  brightness: 0.5 + Math.random() * 0.5
              });
          }

          s.push({
              particles: putParticles,
              height: putHeight,
              contract: put,
              type: 'put',
              xBase: x,
              zBase: zPut,
              colorBase: '330, 100%, 50%', // Rose
              index: i
          });
      });

      return s;
  }, [chain]);


  const draw = () => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      const width = canvas.width;
      const height = canvas.height;
      const centerX = width / 2;
      const centerY = height / 2 + 80; 

      ctx.clearRect(0, 0, width, height);

      // --- Background Grid ---
      ctx.strokeStyle = 'rgba(255, 255, 255, 0.03)';
      ctx.lineWidth = 1;

      // Draw Horizon Lines
      const floorY = -5;
      const range = 2000;

      // Center Axis
      const pStart = project(-range, floorY, 0, centerX, centerY);
      const pEnd = project(range, floorY, 0, centerX, centerY);
      ctx.beginPath(); ctx.moveTo(pStart.x, pStart.y); ctx.lineTo(pEnd.x, pEnd.y); ctx.stroke();

      const regions: any[] = [];

      // Sort by depth (High Z is further away)
      // Since we rotate, we need to sort by the projected Z or distance
      // We calculate projected Z for the base of each stream for accurate sorting
      const sortedStreams = streams.map(s => {
          const proj = project(s.xBase, 0, s.zBase, centerX, centerY);
          return { ...s, projZ: proj.z };
      }).sort((a, b) => b.projZ - a.projZ);

      sortedStreams.forEach(stream => {
          const isHovered = hoverData && hoverData.contract.strike === stream.contract.strike && hoverData.type === stream.type;

          // Vertices
          const x = stream.xBase;
          const z = stream.zBase;
          const w = BAR_WIDTH;
          const d = BAR_DEPTH;
          const h = stream.height;

          // 8 Corners of the cube
          // Bottom
          const b1 = project(x, 0, z, centerX, centerY);
          const b2 = project(x + w, 0, z, centerX, centerY);
          const b3 = project(x + w, 0, z + d, centerX, centerY);
          const b4 = project(x, 0, z + d, centerX, centerY);

          // Top
          const t1 = project(x, h, z, centerX, centerY);
          const t2 = project(x + w, h, z, centerX, centerY);
          const t3 = project(x + w, h, z + d, centerX, centerY);
          const t4 = project(x, h, z + d, centerX, centerY);

          const baseColor = isHovered ? `hsla(${stream.colorBase}, 0.8)` : `hsla(${stream.colorBase}, 0.1)`;
          const strokeColor = isHovered ? `hsla(${stream.colorBase}, 1.0)` : `hsla(${stream.colorBase}, 0.25)`;
          const topColor = isHovered ? `hsla(${stream.colorBase}, 0.5)` : `hsla(${stream.colorBase}, 0.15)`;

          // Draw Logic: Painter's algorithm handles back-to-front
          // We draw the visible faces based on our fixed camera angle (Looking Down + Slightly Right/Left)
          // Yaw is negative (-0.15), so we see the Left side and Front/Back depending.
          // Actually, let's just draw Top, Front, Side to be safe, opacity handles the rest.

          // Back Face (b1-b2-t2-t1) - usually hidden by front, but transparent
          /*
          ctx.beginPath();
          ctx.moveTo(b1.x, b1.y); ctx.lineTo(b2.x, b2.y); ctx.lineTo(t2.x, t2.y); ctx.lineTo(t1.x, t1.y); ctx.closePath();
          ctx.fillStyle = `hsla(${stream.colorBase}, 0.05)`;
          ctx.fill();
          */

          // Front Face (b4-b3-t3-t4)
          ctx.beginPath();
          ctx.moveTo(b4.x, b4.y); ctx.lineTo(b3.x, b3.y); ctx.lineTo(t3.x, t3.y); ctx.lineTo(t4.x, t4.y); ctx.closePath();
          ctx.fillStyle = baseColor;
          ctx.fill();
          ctx.strokeStyle = strokeColor;
          ctx.stroke();

          // Left Side (b1-b4-t4-t1) - Visible due to negative Yaw
          ctx.beginPath();
          ctx.moveTo(b1.x, b1.y); ctx.lineTo(b4.x, b4.y); ctx.lineTo(t4.x, t4.y); ctx.lineTo(t1.x, t1.y); ctx.closePath();
          ctx.fillStyle = `hsla(${stream.colorBase}, 0.08)`;
          ctx.fill();
          ctx.stroke();

          // Right Side (b2-b3-t3-t2) - Visible if Yaw positive
          ctx.beginPath();
          ctx.moveTo(b2.x, b2.y); ctx.lineTo(b3.x, b3.y); ctx.lineTo(t3.x, t3.y); ctx.lineTo(t2.x, t2.y); ctx.closePath();
          ctx.fillStyle = `hsla(${stream.colorBase}, 0.08)`;
          ctx.fill();
          ctx.stroke();

          // Top Face
          ctx.beginPath();
          ctx.moveTo(t1.x, t1.y); ctx.lineTo(t2.x, t2.y); ctx.lineTo(t3.x, t3.y); ctx.lineTo(t4.x, t4.y); ctx.closePath();
          ctx.fillStyle = topColor;
          ctx.fill();
          ctx.stroke();

          // Hit Region (Use a generous bounding box of the top/front)
          // We project a simplified quad for hit testing
          regions.push({
              path: [t1, t2, t3, t4, b3, b4], // Polygon points for point-in-poly check
              contract: stream.contract,
              type: stream.type,
              center: t1 // approx for distance
          });

          // Particles
          stream.particles.forEach(p => {
              // Update Logic
              const age = (timeRef.current * p.speed + p.offset) % 100;
              const yNorm = age / 100;

              let alpha = p.brightness;
              if (yNorm < 0.1) alpha *= yNorm * 10;
              if (yNorm > 0.8) alpha *= (1 - yNorm) * 5;

              const pp = project(
                  stream.xBase + BAR_WIDTH/2 + p.x, 
                  yNorm * stream.height, 
                  stream.zBase + BAR_DEPTH/2 + p.z, 
                  centerX, centerY
              );

              ctx.beginPath();
              ctx.fillStyle = `hsla(${stream.colorBase}, ${alpha})`;
              ctx.arc(pp.x, pp.y, 1.2 * pp.scale, 0, Math.PI * 2);
              ctx.fill();
          });

          // Strike Labels (Front Row - Puts)
          if (stream.type === 'put') { 
              const labelPos = project(stream.xBase + BAR_WIDTH/2, -10, stream.zBase + BAR_DEPTH + 10, centerX, centerY);
              const isAtm = Math.abs(stream.contract.strike - chain.currentPrice) < (chain.currentPrice * 0.005);

              if (isAtm || stream.index % 4 === 0) { 
                  ctx.textAlign = 'center';
                  ctx.fillStyle = isAtm ? '#fbbf24' : '#64748b';
                  ctx.font = isAtm ? 'bold 12px monospace' : '10px monospace';
                  ctx.fillText(stream.contract.strike.toString(), labelPos.x, labelPos.y + 20);

                  if (isAtm) {
                      ctx.shadowBlur = 10;
                      ctx.shadowColor = '#fbbf24';
                      ctx.beginPath();
                      ctx.arc(labelPos.x, labelPos.y, 3, 0, Math.PI * 2);
                      ctx.fill();
                      ctx.shadowBlur = 0;
                  }
              }
          }
      });

      (canvas as any).hitRegions = regions;
  };

  const loop = () => {
      timeRef.current += 1;
      draw();
      animationRef.current = requestAnimationFrame(loop);
  };

  useEffect(() => {
      const canvas = canvasRef.current;
      if (canvas) {
          const rect = canvas.getBoundingClientRect();
          const dpr = window.devicePixelRatio || 1;
          canvas.width = rect.width * dpr;
          canvas.height = rect.height * dpr;
          const ctx = canvas.getContext('2d');
          if (ctx) ctx.scale(dpr, dpr);
      }

      animationRef.current = requestAnimationFrame(loop);
      return () => cancelAnimationFrame(animationRef.current);
  }, [streams, hoverData]);

  // Point in Polygon Utility
  const isPointInPoly = (x: number, y: number, poly: {x:number, y:number}[]) => {
      let inside = false;
      for (let i = 0, j = poly.length - 1; i < poly.length; j = i++) {
          const xi = poly[i].x, yi = poly[i].y;
          const xj = poly[j].x, yj = poly[j].y;
          const intersect = ((yi > y) !== (yj > y)) && (x < (xj - xi) * (y - yi) / (yj - yi) + xi);
          if (intersect) inside = !inside;
      }
      return inside;
  };

  // Interaction
  const handleMouseMove = (e: React.MouseEvent) => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const rect = canvas.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;

      const regions = (canvas as any).hitRegions || [];
      let found = null;

      // Check hit regions
      // Reverse iterate to hit frontmost first
      for (let i = regions.length - 1; i >= 0; i--) {
          const r = regions[i];
          if (isPointInPoly(x, y, r.path)) {
              found = r;
              break;
          }
      }

      if (found) {
          setHoverData({ contract: found.contract, type: found.type });
      } else {
          setHoverData(null);
      }
  };

  const handleClick = () => {
      if (hoverData && onSelectContract) {
          onSelectContract(hoverData.contract);
      }
  };

  return (
    <div className="relative w-full h-full bg-slate-950 rounded-xl overflow-hidden cursor-crosshair group">
        <canvas 
            ref={canvasRef} 
            className="w-full h-full block"
            onMouseMove={handleMouseMove}
            onMouseLeave={() => setHoverData(null)}
            onClick={handleClick}
        />

        {/* Fixed Info Card (Inspector) */}
        <div className="absolute top-4 right-4 w-60 bg-slate-900/90 backdrop-blur-xl border border-white/10 p-4 rounded-xl shadow-2xl pointer-events-none transition-all duration-200 min-h-[160px] flex flex-col justify-center">
            {hoverData ? (
                <>
                    <div className="flex items-center justify-between mb-3 border-b border-white/10 pb-2 animate-fade-in">
                        <span className={`text-xs font-bold uppercase px-2 py-0.5 rounded ${hoverData.type === 'call' ? 'bg-cyan-500/20 text-cyan-400' : 'bg-rose-500/20 text-rose-400'}`}>
                            {hoverData.type}
                        </span>
                        <span className="text-xl font-mono font-bold text-white tracking-tight">${hoverData.contract.strike}</span>
                    </div>

                    <div className="space-y-3 animate-fade-in">
                        <div className="flex items-center justify-between gap-4">
                            <span className="text-xs text-slate-400 uppercase font-bold flex items-center gap-2">
                                <Zap className="w-3 h-3 text-white" /> Volume
                            </span>
                            <span className="text-white font-mono font-bold">{hoverData.contract.volume.toLocaleString()}</span>
                        </div>

                        <div className="flex items-center justify-between gap-4">
                            <span className="text-xs text-slate-400 uppercase font-bold flex items-center gap-2">
                                <Layers className="w-3 h-3 text-slate-500" /> Open Int
                            </span>
                            <span className={`font-mono font-bold ${hoverData.type === 'call' ? 'text-cyan-400' : 'text-rose-400'}`}>
                                {hoverData.contract.openInterest.toLocaleString()}
                            </span>
                        </div>

                        <div className="pt-2 border-t border-white/5 flex justify-between items-center">
                            <span className="text-[10px] text-slate-500 uppercase tracking-wider font-semibold">Premium</span>
                            <span className="text-emerald-400 font-mono text-base font-bold">${hoverData.contract.lastPrice.toFixed(2)}</span>
                        </div>
                    </div>
                </>
            ) : (
                <div className="flex flex-col items-center justify-center text-slate-600 gap-2 opacity-60">
                    <Activity className="w-8 h-8 opacity-50" />
                    <span className="text-[10px] font-bold uppercase tracking-widest">Hover to Inspect</span>
                </div>
            )}
        </div>

        {/* Legend Overlay */}
        <div className="absolute top-4 left-4 pointer-events-none flex flex-col gap-2 bg-black/40 p-2 rounded-lg border border-white/5 backdrop-blur-sm">
            <div className="flex items-center gap-2">
                <div className="w-3 h-3 bg-cyan-500/20 border border-cyan-500"></div>
                <span className="text-[10px] uppercase font-bold text-cyan-400">Calls (Back Row)</span>
            </div>
            <div className="flex items-center gap-2">
                <div className="w-3 h-3 bg-rose-500/20 border border-rose-500"></div>
                <span className="text-[10px] uppercase font-bold text-rose-400">Puts (Front Row)</span>
            </div>
            {chain && (
                <div className="mt-2 pt-2 border-t border-white/10">
                    <div className="flex items-center gap-1.5 text-slate-300">
                        <Calendar className="w-3 h-3 text-indigo-400" />
                        <span className="text-[10px] font-mono font-bold">{chain.selectedExpiration}</span>
                    </div>
                </div>
            )}
        </div>

        <div className="absolute bottom-4 left-1/2 -translate-x-1/2 text-[10px] text-slate-500 uppercase font-bold tracking-widest flex items-center gap-2 pointer-events-none opacity-50 group-hover:opacity-100 transition-opacity">
            <Maximize className="w-3 h-3" /> Liquidity Horizon
        </div>
    </div>
  );
};

export default OptionsChainVisualizer;

import React, { useRef, useEffect, useState, useMemo } from 'react';
import { calculateBlackScholes, calculateHestonPrice } from '../services/marketDataService';
import { Maximize, Eye, Info, DollarSign, Target, Pause, Play, ScanLine, Crosshair, Settings2, Move3d, MousePointer2, Grid3X3, Clock, TrendingUp } from 'lucide-react';

interface Point3D {
  x: number;
  y: number;
  z: number;
  price: number;
  spot: number;
  time: number;
}

interface Particle {
    x: number;
    y: number;
    z: number;
    speed: number;
    size: number;
    alpha: number;
}

interface SurfaceProps {
  volatility: number;
  riskFreeRate: number;
  isCall: boolean;
  strikePrice?: number;
}

const VolatilitySurface: React.FC<SurfaceProps> = ({ volatility, riskFreeRate, isCall, strikePrice = 100 }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // Camera & Interaction State
  const [camera, setCamera] = useState({ yaw: 0.6, pitch: 0.5 });
  const [isDragging, setIsDragging] = useState(false);
  const [lastMouse, setLastMouse] = useState({ x: 0, y: 0 });
  const [interactionMode, setInteractionMode] = useState<'ORBIT' | 'SCAN'>('ORBIT');

  // Animation State
  const [isScanning, setIsScanning] = useState(true);
  const [scanPos, setScanPos] = useState({ x: 0.5, z: 0.5 }); 

  // View Modes
  const [showPnL, setShowPnL] = useState(false);
  const [showGuides, setShowGuides] = useState(true);
  const [pricingModel, setPricingModel] = useState<'BS' | 'HESTON'>('BS');

  // Heston Parameters
  const [hestonParams, setHestonParams] = useState({
      v0: volatility * volatility,
      theta: volatility * volatility,
      kappa: 1.5,
      xi: 0.3,
      rho: -0.3
  });

  // Data for HUD
  const [hudData, setHudData] = useState<{price: number, pnl: number, spot: number, daysLeft: number} | null>(null);

  const animationRef = useRef<number>(0);
  const timeRef = useRef<number>(0);
  const particlesRef = useRef<Particle[]>([]);

  // Initialize Particles
  useEffect(() => {
      const p: Particle[] = [];
      for(let i=0; i<80; i++) {
          p.push({
              x: (Math.random() - 0.5) * 5,
              y: (Math.random() - 0.5) * 4 - 1, // Bias downwards slightly
              z: (Math.random() - 0.5) * 5,
              speed: 0.001 + Math.random() * 0.004,
              size: Math.random() * 2.0,
              alpha: Math.random() * 0.4
          });
      }
      particlesRef.current = p;
  }, []);

  // Sync Params
  useEffect(() => {
     if (pricingModel === 'BS') {
         setHestonParams(prev => ({
             ...prev,
             v0: volatility * volatility,
             theta: volatility * volatility
         }));
     }
  }, [volatility, pricingModel]);

  // Constants
  const GRID_RES = 30; 
  const SPOT_RANGE = { min: strikePrice * 0.6, max: strikePrice * 1.4 };
  const TIME_RANGE = { min: 0.02, max: 1.0 }; 

  // --- MEMOIZED MESH GENERATION ---
  const mesh = useMemo(() => {
      const m: Point3D[][] = [];
      const heightScale = strikePrice * 0.4; 

      for (let i = 0; i <= GRID_RES; i++) {
        const row: Point3D[] = [];
        const tNorm = i / GRID_RES;
        const t = TIME_RANGE.min + (TIME_RANGE.max - TIME_RANGE.min) * tNorm;

        for (let j = 0; j <= GRID_RES; j++) {
          const sNorm = j / GRID_RES;
          const s = SPOT_RANGE.min + (SPOT_RANGE.max - SPOT_RANGE.min) * sNorm;

          let price = 0;
          if (pricingModel === 'BS') {
              price = calculateBlackScholes(isCall ? 'call' : 'put', s, strikePrice, t, riskFreeRate, volatility);
          } else {
              price = calculateHestonPrice(isCall ? 'call' : 'put', s, strikePrice, t, riskFreeRate, hestonParams.v0, hestonParams.theta, hestonParams.kappa, hestonParams.xi, hestonParams.rho);
          }

          row.push({
              x: (sNorm - 0.5) * 2.5, 
              y: (price / heightScale) - 0.5,
              z: (tNorm - 0.5) * 2.5,
              price,
              spot: s,
              time: t
          });
        }
        m.push(row);
      }
      return m;
  }, [pricingModel, volatility, riskFreeRate, isCall, strikePrice, hestonParams]);

  // Calculate Entry Price (Cost Basis) for PnL
  const entryPrice = useMemo(() => {
      if (pricingModel === 'BS') {
          return calculateBlackScholes(isCall ? 'call' : 'put', strikePrice, strikePrice, TIME_RANGE.max, riskFreeRate, volatility);
      } else {
          return calculateHestonPrice(isCall ? 'call' : 'put', strikePrice, strikePrice, TIME_RANGE.max, riskFreeRate, hestonParams.v0, hestonParams.theta, hestonParams.kappa, hestonParams.xi, hestonParams.rho);
      }
  }, [mesh, pricingModel]);

  // --- 3D Projection Engine ---
  const project = (p: Point3D, width: number, height: number, yaw: number, pitch: number) => {
    const cosYaw = Math.cos(yaw);
    const sinYaw = Math.sin(yaw);
    const cosPitch = Math.cos(pitch);
    const sinPitch = Math.sin(pitch);

    // Rotate Y (Yaw)
    const x1 = p.x * cosYaw - p.z * sinYaw;
    const z1 = p.x * sinYaw + p.z * cosYaw;

    // Rotate X (Pitch)
    const y2 = p.y * cosPitch - z1 * sinPitch;
    const z2 = p.y * sinPitch + z1 * cosPitch;

    // Perspective
    const fov = 700;
    const distance = 4.5;

    // Z-Clipping
    if (z2 + distance < 0.1) return null;

    const scale = fov / (distance + z2);
    const x2d = x1 * scale + width / 2;
    const y2d = -y2 * scale + height / 2; // Invert Y

    return { x: x2d, y: y2d, scale, z: z2 };
  };

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const width = canvas.width;
    const height = canvas.height;

    // Clear with slight fade for trails? No, standard clear for crispness
    ctx.clearRect(0, 0, width, height);

    // Background Gradient
    const bgGrad = ctx.createLinearGradient(0, 0, 0, height);
    bgGrad.addColorStop(0, '#020617');
    bgGrad.addColorStop(1, '#0f172a');
    ctx.fillStyle = bgGrad;
    ctx.fillRect(0, 0, width, height);

    // --- Draw Particles ---
    particlesRef.current.forEach(p => {
        const proj = project({ x: p.x, y: p.y, z: p.z, price: 0, spot: 0, time: 0 }, width, height, camera.yaw, camera.pitch);
        if (proj) {
            ctx.beginPath();
            ctx.fillStyle = `rgba(99, 102, 241, ${p.alpha})`; // Indigo
            ctx.arc(proj.x, proj.y, p.size * (proj.scale/100), 0, Math.PI * 2);
            ctx.fill();
        }
        // Animate
        p.y += p.speed;
        if (p.y > 2) p.y = -2;
    });

    // --- Draw Grid Floor ---
    const floorY = -0.55;
    if (showGuides) {
        ctx.lineWidth = 1;
        ctx.strokeStyle = 'rgba(255, 255, 255, 0.05)';
        const range = 2.0;
        const steps = 8;

        // Z-lines
        for(let i=-steps; i<=steps; i++) {
            const x = (i/steps) * range;
            const p1 = project({x, y: floorY, z: -range, price:0, spot:0, time:0}, width, height, camera.yaw, camera.pitch);
            const p2 = project({x, y: floorY, z: range, price:0, spot:0, time:0}, width, height, camera.yaw, camera.pitch);
            if(p1 && p2) {
                ctx.beginPath();
                ctx.moveTo(p1.x, p1.y);
                ctx.lineTo(p2.x, p2.y);
                ctx.stroke();
            }
        }
        // X-lines
        for(let i=-steps; i<=steps; i++) {
            const z = (i/steps) * range;
            const p1 = project({x: -range, y: floorY, z, price:0, spot:0, time:0}, width, height, camera.yaw, camera.pitch);
            const p2 = project({x: range, y: floorY, z, price:0, spot:0, time:0}, width, height, camera.yaw, camera.pitch);
            if(p1 && p2) {
                ctx.beginPath();
                ctx.moveTo(p1.x, p1.y);
                ctx.lineTo(p2.x, p2.y);
                ctx.stroke();
            }
        }
    }

    // --- Draw Surface Mesh ---
    ctx.shadowBlur = 15;
    ctx.lineJoin = 'round';

    for (let i = 0; i < mesh.length; i++) {
        for (let j = 0; j < mesh[i].length; j++) {
            const p = mesh[i][j];
            const pp = project(p, width, height, camera.yaw, camera.pitch);
            if (!pp) continue;

            // Determine Color
            let strokeStyle = '';
            let shadowColor = '';

            if (showPnL) {
                const pnl = p.price - entryPrice;
                if (pnl >= 0) {
                    strokeStyle = `rgba(16, 185, 129, 0.5)`;
                    shadowColor = '#10b981';
                } else {
                    strokeStyle = `rgba(244, 63, 94, 0.5)`;
                    shadowColor = '#f43f5e';
                }
            } else {
                // Neon Aesthetic
                const normalizedH = (p.y + 0.5); 
                const hue = 240 - (normalizedH * 60); // Blue to Cyan
                const light = 50 + (normalizedH * 40);
                strokeStyle = `hsla(${hue}, 80%, ${light}%, 0.4)`;
                shadowColor = `hsla(${hue}, 80%, 50%, 0.8)`;
            }

            ctx.shadowColor = shadowColor;
            ctx.strokeStyle = strokeStyle;
            ctx.lineWidth = 1.5;

            // Scanner Highlight
            const isScannedRow = i === Math.floor(scanPos.z * GRID_RES);
            const isScannedCol = j === Math.floor(scanPos.x * GRID_RES);

            if (isScannedRow || isScannedCol) {
                ctx.strokeStyle = '#ffffff';
                ctx.shadowColor = '#ffffff';
                ctx.lineWidth = 2;
                ctx.shadowBlur = 20;
            }

            // Draw X-segments
            if (j < mesh[i].length - 1) {
                const right = mesh[i][j+1];
                const pr = project(right, width, height, camera.yaw, camera.pitch);
                if (pr) {
                    ctx.beginPath();
                    ctx.moveTo(pp.x, pp.y);
                    ctx.lineTo(pr.x, pr.y);
                    ctx.stroke();
                }
            }
            // Draw Z-segments
            if (i < mesh.length - 1) {
                const bottom = mesh[i+1][j];
                const pb = project(bottom, width, height, camera.yaw, camera.pitch);
                if (pb) {
                    ctx.beginPath();
                    ctx.moveTo(pp.x, pp.y);
                    ctx.lineTo(pb.x, pb.y);
                    ctx.stroke();
                }
            }
        }
    }

    ctx.shadowBlur = 0;

    // --- Draw Scanner Target & Drop Lines ---
    const sZ = Math.floor(scanPos.z * GRID_RES);
    const sX = Math.floor(scanPos.x * GRID_RES);

    if (sZ < mesh.length && sX < mesh[0].length) {
        const scanPoint = mesh[sZ][sX];
        const projScan = project(scanPoint, width, height, camera.yaw, camera.pitch);

        if (projScan) {
            // Drop Line to Floor
            const projFloor = project({ ...scanPoint, y: floorY }, width, height, camera.yaw, camera.pitch);

            if (projFloor) {
                // Main Drop
                const grad = ctx.createLinearGradient(projScan.x, projScan.y, projFloor.x, projFloor.y);
                grad.addColorStop(0, 'rgba(255, 255, 255, 1)');
                grad.addColorStop(1, 'rgba(255, 255, 255, 0.1)');

                ctx.beginPath();
                ctx.moveTo(projScan.x, projScan.y);
                ctx.lineTo(projFloor.x, projFloor.y);
                ctx.strokeStyle = grad;
                ctx.lineWidth = 1.5;
                ctx.setLineDash([2, 2]);
                ctx.stroke();
                ctx.setLineDash([]);

                // --- AXIS DROP LINES (Visual Depth Cues) ---
                // 1. To Spot Axis (Z-Max edge: z=1.25)
                const zEdge = 1.25; 
                const projSpotAxis = project({ ...scanPoint, y: floorY, z: zEdge }, width, height, camera.yaw, camera.pitch);

                if (projSpotAxis) {
                    ctx.beginPath();
                    ctx.moveTo(projFloor.x, projFloor.y);
                    ctx.lineTo(projSpotAxis.x, projSpotAxis.y);
                    ctx.strokeStyle = 'rgba(251, 191, 36, 0.4)'; // Amber
                    ctx.stroke();

                    // Label Background
                    ctx.fillStyle = 'rgba(2, 6, 23, 0.8)';
                    ctx.fillRect(projSpotAxis.x - 20, projSpotAxis.y - 10, 40, 20);

                    // Spot Value
                    ctx.textAlign = 'center';
                    ctx.textBaseline = 'middle';
                    ctx.fillStyle = '#fbbf24';
                    ctx.font = 'bold 10px monospace';
                    ctx.fillText(`$${scanPoint.spot.toFixed(0)}`, projSpotAxis.x, projSpotAxis.y);
                }

                // 2. To Time Axis (X-Min edge: x=-1.25)
                const xEdge = -1.25;
                const projTimeAxis = project({ ...scanPoint, y: floorY, x: xEdge }, width, height, camera.yaw, camera.pitch);

                if (projTimeAxis) {
                    ctx.beginPath();
                    ctx.moveTo(projFloor.x, projFloor.y);
                    ctx.lineTo(projTimeAxis.x, projTimeAxis.y);
                    ctx.strokeStyle = 'rgba(34, 211, 238, 0.4)'; // Cyan
                    ctx.stroke();

                    // Label Background
                    ctx.fillStyle = 'rgba(2, 6, 23, 0.8)';
                    ctx.fillRect(projTimeAxis.x - 20, projTimeAxis.y - 10, 40, 20);

                    // Time Value
                    ctx.fillStyle = '#22d3ee';
                    ctx.font = 'bold 10px monospace';
                    ctx.fillText(`${(scanPoint.time * 365).toFixed(0)}d`, projTimeAxis.x, projTimeAxis.y);
                }

                // Floor Dot
                ctx.beginPath();
                ctx.arc(projFloor.x, projFloor.y, 3, 0, Math.PI * 2);
                ctx.fillStyle = '#ffffff';
                ctx.fill();
            }

            // Target Circle
            ctx.beginPath();
            ctx.arc(projScan.x, projScan.y, 5, 0, Math.PI * 2);
            ctx.fillStyle = '#ffffff';
            ctx.fill();

            // Pulse Ring
            const pulse = (Math.sin(timeRef.current * 8) + 1) * 0.5;
            ctx.beginPath();
            ctx.arc(projScan.x, projScan.y, 8 + pulse * 8, 0, Math.PI * 2);
            ctx.strokeStyle = `rgba(255, 255, 255, ${0.8 - pulse * 0.5})`;
            ctx.lineWidth = 1;
            ctx.stroke();

            // P/L Floating Label
            const pnl = scanPoint.price - entryPrice;
            const labelX = projScan.x + 30;
            const labelY = projScan.y - 30;

            // Connecting line
            ctx.beginPath();
            ctx.moveTo(projScan.x, projScan.y);
            ctx.lineTo(labelX, labelY + 12);
            ctx.strokeStyle = 'rgba(255, 255, 255, 0.3)';
            ctx.lineWidth = 1;
            ctx.stroke();

            // Label Box
            ctx.fillStyle = 'rgba(15, 23, 42, 0.9)';
            ctx.beginPath();
            ctx.roundRect(labelX, labelY - 20, 80, 40, 6);
            ctx.fill();
            ctx.strokeStyle = pnl >= 0 ? '#10b981' : '#f43f5e';
            ctx.lineWidth = 1.5;
            ctx.stroke();

            // Text
            ctx.textAlign = 'left';
            ctx.fillStyle = '#ffffff';
            ctx.font = 'bold 12px monospace';
            ctx.fillText(`$${scanPoint.price.toFixed(2)}`, labelX + 8, labelY - 2);

            ctx.font = '10px monospace';
            ctx.fillStyle = pnl >= 0 ? '#34d399' : '#fb7185';
            ctx.fillText(`P/L ${pnl >= 0 ? '+' : ''}${pnl.toFixed(2)}`, labelX + 8, labelY + 12);
        }
    }
  };

  // Interaction Handlers
  const handleMouseDown = (e: React.MouseEvent) => {
      setIsDragging(true);
      setLastMouse({ x: e.clientX, y: e.clientY });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
      const rect = canvasRef.current?.getBoundingClientRect();
      if (!rect) return;

      if (interactionMode === 'ORBIT' && isDragging) {
          const deltaX = e.clientX - lastMouse.x;
          const deltaY = e.clientY - lastMouse.y;
          setCamera(prev => ({
              yaw: prev.yaw + deltaX * 0.005,
              pitch: Math.max(0.1, Math.min(Math.PI / 2, prev.pitch + deltaY * 0.005))
          }));
          setLastMouse({ x: e.clientX, y: e.clientY });
      } else if (interactionMode === 'SCAN' && isDragging) {
          // Simple 2D to 3D Map for Scanner
          const x = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
          const y = Math.max(0, Math.min(1, (e.clientY - rect.top) / rect.height));

          // Map to grid coordinates (Inverted logic for intuitive feel)
          // Moving mouse Right -> Increase Spot (Scan X)
          // Moving mouse Down -> Increase Time (Scan Z) - roughly
          setScanPos({ x: x, z: y });
          setIsScanning(false);
          setLastMouse({ x: e.clientX, y: e.clientY });
      }
  };

  const handleMouseUp = () => setIsDragging(false);

  // Animation Loop
  useEffect(() => {
    const loop = () => {
        timeRef.current += 0.01;

        // Auto-Rotate if not dragging (slow orbit)
        if (!isDragging && interactionMode === 'ORBIT') {
            setCamera(prev => ({ ...prev, yaw: prev.yaw + 0.0005 }));
        }

        if (isScanning) {
            setScanPos({
                x: 0.5 + Math.sin(timeRef.current * 0.5) * 0.4, 
                z: 0.5 + Math.cos(timeRef.current * 0.3) * 0.4  
            });
        }
        draw();
        animationRef.current = requestAnimationFrame(loop);
    };
    loop();
    return () => cancelAnimationFrame(animationRef.current);
  }, [isScanning, mesh, showPnL, showGuides, camera, isDragging, interactionMode]); 

  // Sync HUD (Decoupled)
  useEffect(() => {
      if (!mesh || mesh.length === 0) return;
      const xIdx = Math.floor(scanPos.x * GRID_RES);
      const zIdx = Math.floor(scanPos.z * GRID_RES);
      if (zIdx < mesh.length && xIdx < mesh[0].length) {
          const p = mesh[zIdx][xIdx];
          setHudData({
              price: p.price,
              pnl: p.price - entryPrice,
              spot: p.spot,
              daysLeft: Math.floor(p.time * 365)
          });
      }
  }, [scanPos, mesh, entryPrice]);

  // Adjust canvas size for DPI
  useEffect(() => {
      const canvas = canvasRef.current;
      if (canvas) {
          const rect = canvas.getBoundingClientRect();
          const dpr = window.devicePixelRatio || 1;
          canvas.width = rect.width * dpr;
          canvas.height = rect.height * dpr;
          const ctx = canvas.getContext('2d');
          if (ctx) ctx.scale(dpr, dpr);
      }
  }, []);

  return (
    <div 
        className="relative w-full h-full bg-slate-950/80 rounded-xl overflow-hidden border border-white/5 shadow-inner group select-none"
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
    >
        <canvas 
            ref={canvasRef} 
            className={`w-full h-full object-cover ${isDragging ? 'cursor-grabbing' : 'cursor-grab'}`}
            style={{ width: '100%', height: '100%' }}
        />

        {/* Top-Right: Interaction Mode Toggle */}
        <div className="absolute top-4 right-4 flex gap-2 pointer-events-auto">
             <button 
                onClick={() => setInteractionMode('ORBIT')}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-lg border text-xs font-bold transition-all ${interactionMode === 'ORBIT' ? 'bg-indigo-600 border-indigo-500 text-white shadow-lg' : 'bg-black/40 border-white/10 text-slate-400 hover:text-white'}`}
             >
                 <Move3d className="w-3.5 h-3.5" /> Orbit
             </button>
             <button 
                onClick={() => setInteractionMode('SCAN')}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-lg border text-xs font-bold transition-all ${interactionMode === 'SCAN' ? 'bg-emerald-600 border-emerald-500 text-white shadow-lg' : 'bg-black/40 border-white/10 text-slate-400 hover:text-white'}`}
             >
                 <Crosshair className="w-3.5 h-3.5" /> Scan
             </button>
        </div>

        {/* Top-Left: Model Controls */}
        <div className="absolute top-4 left-4 flex flex-col gap-2 pointer-events-auto">
             <div className="bg-black/60 backdrop-blur-md p-3 rounded-xl border border-white/10 w-56 shadow-2xl">
                <div className="flex justify-between items-center mb-3">
                    <h4 className="text-white font-bold text-xs flex items-center gap-2">
                        <Settings2 className="w-3 h-3 text-indigo-400" /> Model
                    </h4>
                    <div className="flex bg-slate-900 rounded p-0.5 border border-white/10">
                        <button 
                            onClick={() => setPricingModel('BS')} 
                            className={`text-[9px] px-2 py-0.5 rounded font-bold transition-colors ${pricingModel === 'BS' ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:text-slate-300'}`}
                        >BS</button>
                        <button 
                            onClick={() => setPricingModel('HESTON')} 
                            className={`text-[9px] px-2 py-0.5 rounded font-bold transition-colors ${pricingModel === 'HESTON' ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:text-slate-300'}`}
                        >HESTON</button>
                    </div>
                </div>

                {pricingModel === 'HESTON' ? (
                    <div className="space-y-3 animate-fade-in">
                        <div className="space-y-1">
                            <div className="flex justify-between text-[9px] uppercase font-bold text-slate-500">
                                <span>Mean Reversion (κ)</span> <span className="text-indigo-300">{hestonParams.kappa.toFixed(1)}</span>
                            </div>
                            <input type="range" min="0.1" max="5" step="0.1" value={hestonParams.kappa} onChange={e => setHestonParams(p => ({...p, kappa: Number(e.target.value)}))} className="w-full h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-400" />
                        </div>
                        <div className="space-y-1">
                            <div className="flex justify-between text-[9px] uppercase font-bold text-slate-500">
                                <span>Vol of Vol (ξ)</span> <span className="text-rose-300">{hestonParams.xi.toFixed(2)}</span>
                            </div>
                            <input type="range" min="0.01" max="1" step="0.05" value={hestonParams.xi} onChange={e => setHestonParams(p => ({...p, xi: Number(e.target.value)}))} className="w-full h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-rose-400" />
                        </div>
                        <div className="space-y-1">
                            <div className="flex justify-between text-[9px] uppercase font-bold text-slate-500">
                                <span>Correlation (ρ)</span> <span className="text-amber-300">{hestonParams.rho.toFixed(2)}</span>
                            </div>
                            <input type="range" min="-0.99" max="0.99" step="0.05" value={hestonParams.rho} onChange={e => setHestonParams(p => ({...p, rho: Number(e.target.value)}))} className="w-full h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-amber-400" />
                        </div>
                    </div>
                ) : (
                     <div className="p-2 bg-slate-800/50 border border-white/5 rounded text-[9px] text-slate-400 leading-tight">
                        <div className="mb-1 text-slate-500 uppercase font-bold">Standard Model</div>
                        Constant Volatility: <span className="text-white font-mono font-bold">{(volatility * 100).toFixed(1)}%</span>
                     </div>
                )}
             </div>
        </div>

        {/* Bottom Toolbar */}
        <div className="absolute bottom-4 left-1/2 -translate-x-1/2 flex items-center gap-2 bg-black/60 backdrop-blur-md p-1.5 rounded-xl border border-white/10 shadow-lg pointer-events-auto">
            <button 
                onClick={() => setIsScanning(!isScanning)}
                className={`p-2 rounded-lg transition-colors ${isScanning ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-white hover:bg-white/10'}`}
                title={isScanning ? "Pause Auto-Scan" : "Play Auto-Scan"}
            >
                {isScanning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />}
            </button>
            <div className="w-px h-4 bg-white/10"></div>
            <button 
                onClick={() => setShowPnL(!showPnL)}
                className={`p-2 rounded-lg transition-colors ${showPnL ? 'bg-emerald-500/20 text-emerald-400 border border-emerald-500/30' : 'text-slate-400 hover:text-white hover:bg-white/10'}`}
                title="Toggle PnL Heatmap"
            >
                <DollarSign className="w-4 h-4" />
            </button>
            <button 
                onClick={() => setShowGuides(!showGuides)}
                className={`p-2 rounded-lg transition-colors ${showGuides ? 'bg-cyan-500/20 text-cyan-400 border border-cyan-500/30' : 'text-slate-400 hover:text-white hover:bg-white/10'}`}
                title="Toggle Grid Lines"
            >
                <Grid3X3 className="w-4 h-4" />
            </button>
        </div>

        {/* Status Text */}
        <div className="absolute bottom-4 right-4 text-[9px] text-slate-500 font-bold uppercase tracking-widest pointer-events-none opacity-50">
            {interactionMode === 'ORBIT' ? 'Drag to Rotate' : 'Drag to Scan'}
        </div>
    </div>
  );
};

