import React, { useRef, useEffect, useState, useMemo } from 'react';
import { WhisperData } from '../types';
import { MousePointer2, Move3d, Info } from 'lucide-react';

interface VisualizerProps {
  data: WhisperData;
}

interface Satellite {
  id: string;
  source: string;
  score: number;
  sentiment: string;
  trend: string;
  theta: number; // Orbit angle
  phi: number;   // Orbital plane tilt
  radius: number;
  speed: number;
  color: string;
  icon: string;
}

const Whisper3DVisualizer: React.FC<VisualizerProps> = ({ data }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // Camera State
  const [rotation, setRotation] = useState({ x: 0.2, y: 0.4 });
  const [isDragging, setIsDragging] = useState(false);
  const [lastMouse, setLastMouse] = useState({ x: 0, y: 0 });
  const [hoveredNode, setHoveredNode] = useState<Satellite | 'CORE' | null>(null);

  const animationRef = useRef<number>(0);
  const timeRef = useRef<number>(0);

  // --- Initialize Satellites ---
  const satellites = useMemo(() => {
      return data.sources.map((s, i) => {
          // Distribute orbits
          const radius = 180 + (i * 40); 
          const speed = 0.005 + (Math.random() * 0.01);

          let color = '#94a3b8';
          if (s.sentiment === 'Bullish') color = '#10b981'; // Emerald
          if (s.sentiment === 'Bearish') color = '#f43f5e'; // Rose
          if (s.sentiment === 'Neutral') color = '#fbbf24'; // Amber

          return {
              id: s.source,
              source: s.source,
              score: s.score,
              sentiment: s.sentiment,
              trend: s.trend,
              theta: (Math.PI * 2 / data.sources.length) * i,
              phi: (Math.random() - 0.5) * 0.5, // Slight tilt variation
              radius,
              speed: s.trend === 'up' ? speed * 1.5 : speed,
              color,
              icon: s.source[0]
          };
      });
  }, [data]);

  // --- 3D Projection Engine ---
  const project = (x: number, y: number, z: number, width: number, height: number) => {
      // Rotate Y (Yaw) - controlled by mouse X
      const x1 = x * Math.cos(rotation.y) - z * Math.sin(rotation.y);
      const z1 = x * Math.sin(rotation.y) + z * Math.cos(rotation.y);

      // Rotate X (Pitch) - controlled by mouse Y
      const y2 = y * Math.cos(rotation.x) - z1 * Math.sin(rotation.x);
      const z2 = y * Math.sin(rotation.x) + z1 * Math.cos(rotation.x);

      // Perspective
      const fov = 800;
      const distance = 1000;
      const scale = fov / (distance + z2);

      return {
          x: width / 2 + x1 * scale,
          y: height / 2 + y2 * scale,
          scale,
          z: z2
      };
  };

  const draw = () => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      const width = canvas.width;
      const height = canvas.height;

      ctx.clearRect(0, 0, width, height);

      // --- Background Starfield (Parallax?) ---
      // For now, simple static dots, maybe move them slowly
      /*
      ctx.fillStyle = '#ffffff';
      for(let i=0; i<50; i++) {
          const sx = (Math.sin(i * 132 + timeRef.current * 0.001) * width/2) + width/2;
          const sy = (Math.cos(i * 453 + timeRef.current * 0.001) * height/2) + height/2;
          ctx.globalAlpha = Math.random() * 0.5;
          ctx.fillRect(sx, sy, 1, 1);
      }
      ctx.globalAlpha = 1.0;
      */

      // --- Draw Core (The Sun) ---
      const coreColor = data.overallScore > 60 ? '#10b981' : data.overallScore < 40 ? '#f43f5e' : '#fbbf24';
      const coreProj = project(0, 0, 0, width, height);

      // Pulse Effect
      const pulse = Math.sin(timeRef.current * 0.05) * 5;
      const coreSize = (40 + (data.overallScore / 5)) * coreProj.scale + pulse;

      // Glow
      const gradient = ctx.createRadialGradient(coreProj.x, coreProj.y, coreSize * 0.2, coreProj.x, coreProj.y, coreSize * 2);
      gradient.addColorStop(0, coreColor);
      gradient.addColorStop(0.4, coreColor); // solid center
      gradient.addColorStop(1, 'transparent');

      ctx.beginPath();
      ctx.fillStyle = gradient;
      ctx.arc(coreProj.x, coreProj.y, coreSize * 2, 0, Math.PI * 2);
      ctx.fill();

      // Core Label
      ctx.fillStyle = '#ffffff';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.font = `bold ${24 * coreProj.scale}px monospace`;
      ctx.fillText(data.overallScore.toString(), coreProj.x, coreProj.y);

      ctx.font = `${10 * coreProj.scale}px sans-serif`;
      ctx.fillText(data.sentimentLabel.toUpperCase(), coreProj.x, coreProj.y + (30 * coreProj.scale));

      // --- Draw Orbit Rings (Faint) ---
      satellites.forEach(sat => {
          ctx.beginPath();
          ctx.strokeStyle = 'rgba(255, 255, 255, 0.05)';
          ctx.lineWidth = 1;

          // Draw ellipse approximation for orbit path
          for (let a = 0; a <= Math.PI * 2; a += 0.1) {
              const rx = sat.radius * Math.cos(a);
              const rz = sat.radius * Math.sin(a);
              const ry = rx * Math.sin(sat.phi); // Apply tilt

              const p = project(rx, ry, rz, width, height);
              if (a === 0) ctx.moveTo(p.x, p.y);
              else ctx.lineTo(p.x, p.y);
          }
          ctx.stroke();
      });

      // --- Draw Satellites ---
      // Sort by Z for proper occlusion with Core
      const renderList = [
          { type: 'CORE', z: coreProj.z, proj: coreProj }
      ];

      satellites.forEach(sat => {
          // Update position
          sat.theta += sat.speed;

          const x = sat.radius * Math.cos(sat.theta);
          const z = sat.radius * Math.sin(sat.theta);
          const y = x * Math.sin(sat.phi);

          const proj = project(x, y, z, width, height);
          renderList.push({ type: 'SAT', z: proj.z, proj, data: sat });
      });

      renderList.sort((a, b) => b.z - a.z); // Draw furthest first

      renderList.forEach(item => {
          if (item.type === 'CORE') {
              // Core is drawn separately above for glow layering, but strictly speaking 
              // for perfect Z-sort it should be here. 
              // However, since core is transparent glow, drawing it "under" satellites in front is fine.
              // We'll skip redrawing core here to keep the additive glow effect clean.
          } else {
              const s = item.data as Satellite;
              const p = item.proj;

              // Connector Beam (Data stream)
              // Only draw if behind core, or draw with opacity
              ctx.beginPath();
              const beamOpacity = (Math.sin(timeRef.current * 0.2 + s.theta * 5) + 1) * 0.15; // Pulse beam
              const beamGrad = ctx.createLinearGradient(p.x, p.y, coreProj.x, coreProj.y);
              beamGrad.addColorStop(0, s.color);
              beamGrad.addColorStop(1, 'transparent');
              ctx.strokeStyle = beamGrad;
              ctx.lineWidth = 2 * p.scale;
              ctx.globalAlpha = beamOpacity;
              ctx.moveTo(p.x, p.y);
              ctx.lineTo(coreProj.x, coreProj.y);
              ctx.stroke();
              ctx.globalAlpha = 1.0;

              // Satellite Body
              const size = 8 * p.scale;
              ctx.beginPath();
              ctx.fillStyle = '#0f172a'; // Slate 900
              ctx.arc(p.x, p.y, size, 0, Math.PI * 2);
              ctx.fill();

              ctx.beginPath();
              ctx.strokeStyle = s.color;
              ctx.lineWidth = 2 * p.scale;
              ctx.arc(p.x, p.y, size, 0, Math.PI * 2);
              ctx.stroke();

              // Icon / Letter
              ctx.fillStyle = s.color;
              ctx.font = `bold ${10 * p.scale}px sans-serif`;
              ctx.fillText(s.icon, p.x, p.y);

              // Label (if hovered or close to front)
              // Simple distance check: if z is small (negative z is towards camera in our proj)
              if (p.z < 0 || hoveredNode?.id === s.id) {
                  const labelY = p.y - (20 * p.scale);

                  ctx.font = `bold ${12 * p.scale}px monospace`;
                  ctx.fillStyle = '#ffffff';
                  ctx.fillText(s.source, p.x, labelY);

                  ctx.font = `${10 * p.scale}px monospace`;
                  ctx.fillStyle = s.color;
                  ctx.fillText(`${s.score}`, p.x, labelY + (12 * p.scale));
              }
          }
      });

      timeRef.current += 1;
      animationRef.current = requestAnimationFrame(draw);
  };

  useEffect(() => {
      animationRef.current = requestAnimationFrame(draw);
      return () => cancelAnimationFrame(animationRef.current);
  }, [satellites, rotation]);

  // Resize Handler
  useEffect(() => {
      const canvas = canvasRef.current;
      if (canvas) {
          const rect = canvas.getBoundingClientRect();
          const dpr = window.devicePixelRatio || 1;
          canvas.width = rect.width * dpr;
          canvas.height = rect.height * dpr;
          const ctx = canvas.getContext('2d');
          if (ctx) ctx.scale(dpr, dpr);
      }
  }, []);

  // Interaction
  const handleMouseDown = (e: React.MouseEvent) => {
      setIsDragging(true);
      setLastMouse({ x: e.clientX, y: e.clientY });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
      if (isDragging) {
          const dx = e.clientX - lastMouse.x;
          const dy = e.clientY - lastMouse.y;

          setRotation(prev => ({
              x: Math.max(-1, Math.min(1, prev.x + dy * 0.005)), // Clamp pitch
              y: prev.y + dx * 0.005
          }));

          setLastMouse({ x: e.clientX, y: e.clientY });
      }
  };

  const handleMouseUp = () => setIsDragging(false);

  return (
    <div className="relative w-full h-[600px] bg-slate-950 rounded-3xl overflow-hidden border border-white/10 shadow-2xl group cursor-move">
        {/* Background Gradient Mesh */}
        <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_center,_var(--tw-gradient-stops))] from-indigo-900/20 via-slate-950 to-slate-950 pointer-events-none"></div>

        <canvas 
            ref={canvasRef}
            className="w-full h-full block relative z-10"
            onMouseDown={handleMouseDown}
            onMouseMove={handleMouseMove}
            onMouseUp={handleMouseUp}
            onMouseLeave={handleMouseUp}
        />

        {/* Legend / Overlay */}
        <div className="absolute top-6 left-6 z-20 flex flex-col gap-2 pointer-events-none">
            <div className="bg-black/60 backdrop-blur-md px-4 py-2 rounded-xl border border-white/10">
                <div className="text-[10px] uppercase font-bold text-slate-500 tracking-wider mb-1">Target Ticker</div>
                <div className="text-2xl font-black text-white tracking-tight">{data.ticker}</div>
            </div>

            <div className="bg-black/60 backdrop-blur-md px-4 py-2 rounded-xl border border-white/10 space-y-2">
                <div className="flex items-center gap-2 text-xs">
                    <div className="w-2 h-2 rounded-full bg-emerald-500"></div>
                    <span className="text-slate-300">Bullish Source</span>
                </div>
                <div className="flex items-center gap-2 text-xs">
                    <div className="w-2 h-2 rounded-full bg-rose-500"></div>
                    <span className="text-slate-300">Bearish Source</span>
                </div>
                <div className="flex items-center gap-2 text-xs">
                    <div className="w-2 h-2 rounded-full bg-amber-500"></div>
                    <span className="text-slate-300">Neutral Source</span>
                </div>
            </div>
        </div>

        {/* Interaction Hint */}
        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-2 text-slate-500 text-[10px] uppercase font-bold tracking-widest opacity-60 pointer-events-none">
            <Move3d className="w-4 h-4" /> Drag to Rotate System
        </div>
    </div>
  );
};

