import React, { useRef, useEffect, useState } from 'react';
import { Play, RotateCcw, TrendingUp, TrendingDown, Trophy, AlertTriangle, Shield, Gauge } from 'lucide-react';

interface GameState {
  status: 'MENU' | 'PLAYING' | 'FINISHED';
  balance: number;
  currentPrice: number;
  entryPrice: number;
  strikePrice: number;
  position: 'CALL' | 'PUT' | null;
  timeLeft: number; // 0 to 100
  history: number[];
  pnl: number;
}

const OptionsRunnerGame: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>(0);

  // Game Logic State
  const [game, setGame] = useState<GameState>({
      status: 'MENU',
      balance: 10000,
      currentPrice: 100,
      entryPrice: 100,
      strikePrice: 100,
      position: null,
      timeLeft: 100,
      history: [],
      pnl: 0
  });

  const [difficulty, setDifficulty] = useState<'LOW' | 'MED' | 'HIGH'>('MED');

  // --- Engine Constants ---
  const VOLATILITY_MAP = { LOW: 0.3, MED: 0.8, HIGH: 1.5 };
  const TIME_DECAY_SPEED = 0.15;
  const HISTORY_LENGTH = 80; // How many points to keep in 3D buffer

  // --- 3D Projection Helper ---
  const project = (x: number, y: number, z: number, width: number, height: number) => {
      const fov = 400;
      const viewDist = 4;
      const scale = fov / (viewDist + z);
      const x2d = (x * scale) + width / 2;
      const y2d = (y * scale) + height / 2;
      return { x: x2d, y: y2d, scale, visible: z > -viewDist };
  };

  // --- Game Loop ---
  const update = () => {
      if (game.status !== 'PLAYING') return;

      setGame(prev => {
          // 1. Random Walk Price
          const vol = VOLATILITY_MAP[difficulty];
          const change = (Math.random() - 0.5) * vol;
          const newPrice = Math.max(1, prev.currentPrice + change);

          // 2. Update Time
          const newTime = prev.timeLeft - TIME_DECAY_SPEED;

          // 3. Calculate PnL (Intrinsic Only for simplicity in visualizer)
          // Scale PnL for game feel (x100 for contracts)
          let intrinsic = 0;
          if (prev.position === 'CALL') intrinsic = Math.max(0, newPrice - prev.strikePrice);
          if (prev.position === 'PUT') intrinsic = Math.max(0, prev.strikePrice - newPrice);

          // Cost basis (Simulated Premium paid)
          // Simplified: We assume we paid $5.00 premium
          const premiumPaid = 5; 
          const currentVal = intrinsic;
          const pnl = (currentVal - premiumPaid) * 100;

          // 4. Update History
          const newHistory = [...prev.history, newPrice];
          if (newHistory.length > HISTORY_LENGTH) newHistory.shift();

          // 5. Check End Condition
          if (newTime <= 0) {
              return {
                  ...prev,
                  currentPrice: newPrice,
                  history: newHistory,
                  timeLeft: 0,
                  pnl,
                  balance: prev.balance + pnl, // Settle
                  status: 'FINISHED'
              };
          }

          return {
              ...prev,
              currentPrice: newPrice,
              history: newHistory,
              timeLeft: newTime,
              pnl
          };
      });
  };

  // --- Render Loop ---
  const draw = () => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      const width = canvas.width;
      const height = canvas.height;

      // Clear
      const bgGrad = ctx.createLinearGradient(0, 0, 0, height);
      bgGrad.addColorStop(0, '#020617'); // Slate 950
      bgGrad.addColorStop(1, '#1e1b4b'); // Indigo 950
      ctx.fillStyle = bgGrad;
      ctx.fillRect(0, 0, width, height);

      if (game.status === 'MENU') return;

      // --- 3D World ---
      // We render a scrolling "tunnel".
      // Price is Y axis. Time is Z axis (moving towards camera).

      const centerY = height / 2;

      // 1. Draw Strike Plane (The "Water Level")
      // Normalize price: Start Price is center screen (Y=0 in 3D)
      // Strike Price is fixed at Start Price in this simplified game
      const pixelPerDollar = 2; // Vertical scaling

      const strikeY3D = (game.entryPrice - game.strikePrice) * pixelPerDollar; // Usually 0 if ATM

      ctx.beginPath();
      // Draw a grid for the strike plane
      ctx.strokeStyle = game.position === 'CALL' ? 'rgba(255, 255, 255, 0.1)' : 'rgba(255, 255, 255, 0.1)';
      ctx.lineWidth = 1;

      // Perspective Grid Lines (Floor/Ceiling)
      for (let i = -5; i <= 5; i++) {
          const x = i * 2;
          const p1 = project(x, 2, 0, width, height); // Far
          const p2 = project(x * 3, 2, 5, width, height); // Near
          if (p1.visible) {
              ctx.moveTo(p1.x, p1.y);
              ctx.lineTo(p2.x, p2.y);
          }
      }
      ctx.stroke();

      // 2. Draw Price Path
      // Recent history is close to camera (Z=0), older is far (Z=5)
      ctx.beginPath();
      ctx.lineWidth = 4;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';

      // Determine Line Color based on ITM/OTM
      const isITM = game.pnl > 0;
      const lineColor = isITM ? '#10b981' : '#f43f5e';
      ctx.strokeStyle = lineColor;
      ctx.shadowBlur = 15;
      ctx.shadowColor = lineColor;

      const zStep = 5 / HISTORY_LENGTH;

      for (let i = 0; i < game.history.length; i++) {
          const price = game.history[game.history.length - 1 - i];
          const y = -(price - game.entryPrice) * 0.5; // Invert Y for canvas, scale
          const z = i * zStep; // 0 is closest

          const p = project(0, y, z, width, height);

          if (i === 0) ctx.moveTo(p.x, p.y);
          else ctx.lineTo(p.x, p.y);
      }
      ctx.stroke();
      ctx.shadowBlur = 0;

      // 3. Draw "Current Price" Head
      const currentY = -(game.currentPrice - game.entryPrice) * 0.5;
      const headPos = project(0, currentY, 0, width, height);

      ctx.beginPath();
      ctx.fillStyle = '#ffffff';
      ctx.arc(headPos.x, headPos.y, 6, 0, Math.PI * 2);
      ctx.fill();

      // Pulse Effect
      const pulse = Math.sin(Date.now() / 100) * 5;
      ctx.beginPath();
      ctx.strokeStyle = `rgba(255,255,255,0.5)`;
      ctx.lineWidth = 2;
      ctx.arc(headPos.x, headPos.y, 10 + pulse, 0, Math.PI * 2);
      ctx.stroke();

      // 4. Draw Strike Line (Reference)
      // Visual bar showing where you need to be
      const strikePos = project(0, 0, 0, width, height);
      ctx.beginPath();
      ctx.strokeStyle = 'rgba(255, 255, 255, 0.3)';
      ctx.setLineDash([5, 5]);
      ctx.moveTo(0, strikePos.y);
      ctx.lineTo(width, strikePos.y);
      ctx.stroke();
      ctx.setLineDash([]);

      ctx.fillStyle = 'rgba(255,255,255,0.5)';
      ctx.font = '10px monospace';
      ctx.fillText(`STRIKE $${game.strikePrice}`, width - 80, strikePos.y - 5);

      // 5. Particles (Speed lines)
      const speed = 0.2;
      const timeOffset = (Date.now() / 50) % 10;
      ctx.fillStyle = 'rgba(255,255,255,0.1)';
      for(let i=0; i<20; i++) {
          const x = (Math.random() - 0.5) * 20;
          const y = (Math.random() - 0.5) * 10;
          const z = (i + timeOffset) % 5;
          const p = project(x, y, z, width, height);
          if(p.visible) {
              ctx.beginPath();
              ctx.arc(p.x, p.y, p.scale * 0.5, 0, Math.PI*2);
              ctx.fill();
          }
      }
  };

  useEffect(() => {
      const loop = () => {
          update();
          draw();
          requestRef.current = requestAnimationFrame(loop);
      };
      requestRef.current = requestAnimationFrame(loop);
      return () => cancelAnimationFrame(requestRef.current);
  }, [game]); // Re-bind when game state changes to capture latest values in closure? No, utilize ref or setGame function form.
  // Actually, standard react hook pattern for game loop:
  // Using setGame(prev => ...) inside update() handles state.
  // Drawing needs access to latest state. 
  // To fix closure staleness in draw(), we can use a ref to store game state for the renderer.

  const gameStateRef = useRef(game);
  useEffect(() => { gameStateRef.current = game; }, [game]);

  // Override render to use Ref for smoothness without re-binding loop constantly
  useEffect(() => {
      const loop = () => {
          // Logic update is handled by separate interval or inside RAF?
          // Let's put logic in RAF but throttle it if needed. 
          // For simplicity in React, calling setGame in RAF is okay for simple games, 
          // but better to use Ref for game state and only trigger React renders for UI overlay.
          // However, we want React UI to update (PnL, Time). 
          // We will stick to the update() calling setGame pattern, but we need to ensure 'draw' sees it.
          // Since 'draw' is defined in the component body, it closes over 'game'.
          // We need 'draw' to be called on animation frame, but we need to ensure the effect creating the loop depends on 'game' 
          // OR use a Ref for the state that draw reads.

          // Let's use the Ref strategy for the Canvas Draw only.
          // Logic loop (update) will run via setGame which triggers re-render.
          // Canvas draw will run via useEffect[game]? No, that's slow.
          // Hybrid:
          // 1. Game State in React State (for UI).
          // 2. Canvas draws purely based on props passed or ref.
          // Actually, simply putting draw() in a useEffect([game]) works fine for 60fps if logic is light.
          if (gameStateRef.current.status !== 'MENU') {
             // We just rely on the main RAF loop defined above which calls draw()
             // But draw() needs to read from gameStateRef to avoid closure staleness if we don't rebind.
          }
      };
      // The previous useEffect handles the loop. We just need draw() to use the Ref.
  }, []);

  // Patch draw to use ref
  const drawRef = () => {
      const state = gameStateRef.current;
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      const width = canvas.width;
      const height = canvas.height;

      // Clear
      const bgGrad = ctx.createLinearGradient(0, 0, 0, height);
      bgGrad.addColorStop(0, '#020617'); 
      bgGrad.addColorStop(1, '#172554'); 
      ctx.fillStyle = bgGrad;
      ctx.fillRect(0, 0, width, height);

      if (state.status === 'MENU') return;

      const centerY = height / 2;
      const pixelPerDollar = 3; 
      const strikePos = project(0, 0, 0, width, height);

      // Grid
      ctx.strokeStyle = 'rgba(255,255,255,0.05)';
      ctx.lineWidth = 1;
      // Floor lines
      for (let z = 0; z < 5; z+=0.5) {
          const zPos = (z + (Date.now() * 0.002)) % 5;
          const p1 = project(-5, 2, zPos, width, height);
          const p2 = project(5, 2, zPos, width, height);
          if (p1.visible) { ctx.beginPath(); ctx.moveTo(p1.x, p1.y); ctx.lineTo(p2.x, p2.y); ctx.stroke(); }
      }

      // Draw Path
      ctx.beginPath();
      ctx.lineWidth = 4;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      const isITM = state.pnl > 0;
      const lineColor = isITM ? '#10b981' : '#f43f5e';
      ctx.strokeStyle = lineColor;
      ctx.shadowBlur = 15;
      ctx.shadowColor = lineColor;

      const zStep = 4 / HISTORY_LENGTH;

      for (let i = 0; i < state.history.length; i++) {
          const price = state.history[state.history.length - 1 - i];
          const y = -(price - state.entryPrice) * 0.2; // Scaling
          const z = i * zStep; 

          const p = project(0, y, z, width, height);

          if (i === 0) ctx.moveTo(p.x, p.y);
          else ctx.lineTo(p.x, p.y);
      }
      ctx.stroke();
      ctx.shadowBlur = 0;

      // Draw Head
      const currentY = -(state.currentPrice - state.entryPrice) * 0.2;
      const headPos = project(0, currentY, 0, width, height);

      ctx.beginPath();
      ctx.fillStyle = '#ffffff';
      ctx.arc(headPos.x, headPos.y, 6, 0, Math.PI * 2);
      ctx.fill();

      // Draw Strike Line
      ctx.beginPath();
      ctx.strokeStyle = state.position === 'CALL' ? 'rgba(16, 185, 129, 0.3)' : 'rgba(244, 63, 94, 0.3)';
      ctx.lineWidth = 2;
      ctx.setLineDash([10, 10]);
      ctx.moveTo(0, strikePos.y);
      ctx.lineTo(width, strikePos.y);
      ctx.stroke();
      ctx.setLineDash([]);
  };

  // Main Loop Effect
  useEffect(() => {
      let frameId: number;
      const loop = () => {
          if (gameStateRef.current.status === 'PLAYING') {
              update(); // Updates state, which updates Ref via the other effect
          }
          drawRef();
          frameId = requestAnimationFrame(loop);
      };
      frameId = requestAnimationFrame(loop);
      return () => cancelAnimationFrame(frameId);
  }, []);

  const startGame = (type: 'CALL' | 'PUT') => {
      setGame({
          status: 'PLAYING',
          balance: game.balance,
          currentPrice: 100,
          entryPrice: 100,
          strikePrice: 100,
          position: type,
          timeLeft: 100,
          history: [100],
          pnl: -500 // Start with premium loss
      });
  };

  const resetGame = () => {
      setGame(prev => ({ ...prev, status: 'MENU', history: [], pnl: 0 }));
  };

  return (
    <div className="relative w-full h-[600px] bg-slate-950 rounded-2xl overflow-hidden border border-white/10 shadow-2xl">
        <canvas 
            ref={canvasRef} 
            className="w-full h-full block"
            width={800}
            height={600}
        />

        {/* UI Overlay */}
        <div className="absolute inset-0 pointer-events-none p-6 flex flex-col justify-between">
            {/* HUD */}
            <div className="flex justify-between items-start">
                <div className="bg-black/60 backdrop-blur-md p-3 rounded-xl border border-white/10 text-white">
                    <div className="text-[10px] uppercase font-bold text-slate-400">Account Balance</div>
                    <div className="text-xl font-mono font-bold">${Math.floor(game.balance).toLocaleString()}</div>
                </div>

                {game.status !== 'MENU' && (
                    <div className="flex gap-4">
                        <div className="bg-black/60 backdrop-blur-md p-3 rounded-xl border border-white/10 text-white text-center min-w-[100px]">
                            <div className="text-[10px] uppercase font-bold text-slate-400">Profit / Loss</div>
                            <div className={`text-xl font-mono font-bold ${game.pnl >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                                {game.pnl >= 0 ? '+' : ''}{game.pnl.toFixed(0)}
                            </div>
                        </div>
                        <div className="bg-black/60 backdrop-blur-md p-3 rounded-xl border border-white/10 text-white text-center min-w-[100px]">
                            <div className="text-[10px] uppercase font-bold text-slate-400">Time Left</div>
                            <div className="text-xl font-mono font-bold text-amber-400">{Math.floor(game.timeLeft)}%</div>
                        </div>
                    </div>
                )}
            </div>

            {/* Menu Screen */}
            {game.status === 'MENU' && (
                <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/80 backdrop-blur-sm pointer-events-auto z-20">
                    <Trophy className="w-16 h-16 text-indigo-500 mb-4 animate-bounce" />
                    <h1 className="text-4xl font-black text-white mb-2 tracking-tight">THETA RUNNER</h1>
                    <p className="text-slate-400 mb-8 max-w-md text-center">
                        Master the Greeks in this high-speed simulation. Buy options, survive volatility, and beat the time decay clock.
                    </p>

                    <div className="flex gap-4 mb-8">
                        {(['LOW', 'MED', 'HIGH'] as const).map(d => (
                            <button 
                                key={d}
