                                className={`px-4 py-2 rounded-lg text-xs font-bold border transition-all ${difficulty === d ? 'bg-indigo-600 border-indigo-500 text-white' : 'bg-slate-900 border-white/10 text-slate-500 hover:text-white'}`}
                            >
                                {d} VOL
                            </button>
                        ))}
                    </div>

                    <div className="flex gap-6">
                        <button 
                            onClick={() => startGame('CALL')}
                            className="group relative px-8 py-4 bg-emerald-600 hover:bg-emerald-500 rounded-xl font-bold text-white shadow-lg shadow-emerald-900/20 transition-all active:scale-95 flex flex-col items-center gap-1 border border-emerald-400/20"
                        >
                            <span className="flex items-center gap-2 text-lg"><TrendingUp className="w-5 h-5" /> BUY CALL</span>
                            <span className="text-[10px] uppercase opacity-70 font-mono">Profit if Market Rises</span>
                        </button>

                        <button 
                            onClick={() => startGame('PUT')}
                            className="group relative px-8 py-4 bg-rose-600 hover:bg-rose-500 rounded-xl font-bold text-white shadow-lg shadow-rose-900/20 transition-all active:scale-95 flex flex-col items-center gap-1 border border-rose-400/20"
                        >
                            <span className="flex items-center gap-2 text-lg"><TrendingDown className="w-5 h-5" /> BUY PUT</span>
                            <span className="text-[10px] uppercase opacity-70 font-mono">Profit if Market Falls</span>
                        </button>
                    </div>
                </div>
            )}

            {/* Game Over Screen */}
            {game.status === 'FINISHED' && (
                <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/80 backdrop-blur-sm pointer-events-auto z-20">
                    <div className="bg-slate-900 border border-white/10 p-8 rounded-3xl shadow-2xl text-center max-w-sm w-full relative overflow-hidden">
                        <div className={`absolute top-0 left-0 w-full h-2 ${game.pnl > 0 ? 'bg-emerald-500' : 'bg-rose-500'}`}></div>

                        <div className="mb-4 flex justify-center">
                            {game.pnl > 0 ? (
                                <div className="w-16 h-16 bg-emerald-500/20 rounded-full flex items-center justify-center">
                                    <Trophy className="w-8 h-8 text-emerald-400" />
