                                <div className="w-16 h-16 bg-rose-500/20 rounded-full flex items-center justify-center">
                                    <AlertTriangle className="w-8 h-8 text-rose-400" />
                                </div>
                            )}
                        </div>

                        <h2 className="text-2xl font-bold text-white mb-1">
                            {game.pnl > 0 ? 'OPTION EXERCISED' : 'EXPIRED WORTHLESS'}
                        </h2>
                        <p className="text-slate-400 text-sm mb-6">
                            {game.pnl > 0 ? 'Congratulations, you secured a profit.' : 'Time decay eroded your premium.'}
                        </p>

                        <div className="bg-black/40 rounded-xl p-4 mb-6 border border-white/5">
                            <div className="flex justify-between items-center text-sm mb-2">
                                <span className="text-slate-500">Strike Price</span>
                                <span className="font-mono text-white">${game.strikePrice}</span>
                            </div>
                            <div className="flex justify-between items-center text-sm mb-2">
