      { id: '3', name: 'EARNINGS MISS', impact: 'CRASH', duration: 100 },
      { id: '4', name: 'SHORT SQUEEZE', impact: 'MOON', duration: 80 },
      { id: '5', name: 'MARKET CHOP', impact: 'CHOP', duration: 200 },
    ];
    const evt = events[Math.floor(Math.random() * events.length)];
    state.current.activeEvent = evt;
    state.current.eventTimer = evt.duration;
    state.current.cameraShake = 20; // Initial shock
  };

  const updatePhysics = () => {
    const s = state.current;
    if (!s.isPlaying) return;

    s.tick++;

    // 1. Handle Events & Trend
    if (s.activeEvent) {
      s.eventTimer--;
      if (s.eventTimer <= 0) s.activeEvent = null;

      if (s.activeEvent?.impact === 'CRASH') s.velocity -= 0.05;
      if (s.activeEvent?.impact === 'MOON') s.velocity += 0.05;
      if (s.activeEvent?.impact === 'CHOP') s.velocity += (Math.random() - 0.5) * 0.5;
    } else {
      // Random drift if no event
      if (Math.random() > 0.98) s.trend = (Math.random() - 0.5) * 0.1;
      s.velocity += s.trend;

      // Mean reversion
      s.velocity *= 0.95;

      // Random walk
      s.velocity += (Math.random() - 0.5) * s.volatility;
    }

    // 2. Update Price
    s.price += s.velocity;
    if (s.price < 10) s.price = 10; // Floor

    // 3. Move World (Z-Axis Scroll)
    // We add new point at front, remove old
    s.history.unshift({ y: s.price, z: 0, event: s.activeEvent ? s.activeEvent.id : undefined });
    if (s.history.length > HISTORY_SIZE) s.history.pop();

    // Move existing points back
    s.history.forEach(p => p.z += SPEED);

    // 4. Calculate PnL
    if (s.position) {
      const diff = s.price - s.position.avgEntry;
      const direction = s.position.type === 'CALL' ? 1 : -1;
      // Multiplier: 100 shares per contract
      s.unrealizedPnL = diff * direction * s.position.count * 100;
    } else {
      s.unrealizedPnL = 0;
    }

    // 5. Stress Mechanics (Shake screen on big moves or losses)
    if (Math.abs(s.velocity) > 1.5 || s.unrealizedPnL < -500) {
       s.cameraShake = Math.min(s.cameraShake + 1, 10);
    } else {
       s.cameraShake *= 0.9;
    }

    // 6. Random Event Trigger
    if (!s.activeEvent && Math.random() > 0.995) {
      triggerEvent();
    }

    // Sync React State (Throttled for performance in real app, but 60fps here is fine for simple stats)
    if (s.tick % 5 === 0) {
      setUiState({
        cash: s.cash,
        pnl: s.unrealizedPnL,
        price: s.price,
        position: s.position ? { ...s.position } : null,
        event: s.activeEvent ? s.activeEvent.name : null,
        isPlaying: s.isPlaying
      });
    }
  };

  // --- Render Engine ---
  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const width = canvas.width;
    const height = canvas.height;
    const s = state.current;

    // Apply Shake
    const shakeX = (Math.random() - 0.5) * s.cameraShake;
    const shakeY = (Math.random() - 0.5) * s.cameraShake;

    // Clear
    ctx.fillStyle = '#020617'; // Slate 950
    ctx.fillRect(0, 0, width, height);

    // 3D Projection Helper
    const project = (x: number, y: number, z: number) => {
        const scale = VIEW_DEPTH / (VIEW_DEPTH + z);
        const x2d = (x * scale) + width / 2;
        const y2d = (y * scale) + height / 2;
        return { x: x2d + shakeX, y: y2d + shakeY, scale };
    };

    // --- Draw Grid (Retro Wave) ---
    ctx.strokeStyle = 'rgba(99, 102, 241, 0.2)'; // Indigo low
    ctx.lineWidth = 1;

    // Moving horizontal grid lines (Floor)
    const floorY = 150;
    const gridOffset = (s.tick * SPEED) % 100;
    for(let z = 0; z < VIEW_DEPTH; z += 100) {
        const zPos = z - gridOffset;
        if (zPos < 0) continue;
        const p1 = project(-1000, floorY, zPos);
        const p2 = project(1000, floorY, zPos);

        ctx.beginPath();
        ctx.moveTo(p1.x, p1.y);
        ctx.lineTo(p2.x, p2.y);
        ctx.stroke();
    }
    // Perspective lines
    for(let x = -400; x <= 400; x += 100) {
        const p1 = project(x, floorY, 0);
        const p2 = project(x * 4, floorY, VIEW_DEPTH * 2); // Vanishing point spread
        ctx.beginPath();
        ctx.moveTo(p1.x, p1.y);
        ctx.lineTo(p2.x, p2.y);
        ctx.stroke();
    }

    // --- Draw Price Ribbon ---
    if (s.history.length > 1) {
        ctx.beginPath();

        // Dynamic Color based on trend
        const isCrash = s.activeEvent?.impact === 'CRASH';
        const isMoon = s.activeEvent?.impact === 'MOON';

        let color = '#38bdf8'; // Sky blue default
        if (isCrash) color = '#f43f5e'; // Rose
        if (isMoon) color = '#10b981'; // Emerald

        ctx.strokeStyle = color;
        ctx.lineWidth = 4;
        ctx.lineJoin = 'round';
        ctx.shadowBlur = 15;
        ctx.shadowColor = color;

        // Draw the line
        for (let i = 0; i < s.history.length - 1; i++) {
            const p1 = s.history[i];
            const p2 = s.history[i+1];

            // Map Price Y to Screen Y relative to start
            // Center is current price roughly
            const y1 = -(p1.y - s.price) * 2; 
            const y2 = -(p2.y - s.price) * 2;

            const proj1 = project(0, y1, p1.z);
            const proj2 = project(0, y2, p2.z);

            if (i === 0) ctx.moveTo(proj1.x, proj1.y);
            ctx.lineTo(proj2.x, proj2.y);
        }
        ctx.stroke();
        ctx.shadowBlur = 0; // Reset

        // Draw "Area" under the line for retro look
        ctx.lineTo(project(0, 200, s.history[s.history.length-1].z).x, project(0, 200, s.history[s.history.length-1].z).y);
        ctx.lineTo(project(0, 200, 0).x, project(0, 200, 0).y);
        ctx.fillStyle = isCrash ? 'rgba(244, 63, 94, 0.1)' : 'rgba(56, 189, 248, 0.1)';
        ctx.fill();
    }

    // --- Draw Player "Head" (Current Price) ---
    const headProj = project(0, 0, 0);
    ctx.beginPath();
    ctx.arc(headProj.x, headProj.y, 6, 0, Math.PI * 2);
    ctx.fillStyle = '#ffffff';
    ctx.fill();

    // Entry Price Line (If position active)
    if (s.position) {
        const entryY = -(s.position.avgEntry - s.price) * 2;
        const entryProj = project(0, entryY, 0);

        ctx.beginPath();
        ctx.strokeStyle = s.position.type === 'CALL' ? '#10b981' : '#f43f5e';
        ctx.setLineDash([5, 5]);
        ctx.moveTo(0, entryProj.y);
        ctx.lineTo(width, entryProj.y);
        ctx.stroke();
        ctx.setLineDash([]);

        ctx.fillStyle = s.position.type === 'CALL' ? '#10b981' : '#f43f5e';
        ctx.font = 'bold 12px monospace';
        ctx.fillText(`${s.position.type} ENTRY $${s.position.avgEntry.toFixed(2)}`, width - 120, entryProj.y - 5);
    }
  };

  // --- React Controls ---

  const buyOption = (type: 'CALL' | 'PUT') => {
      const s = state.current;
      if (!s.isPlaying) return;

      const cost = 200; // Simulated premium per contract
      if (s.cash < cost) return; // NSF

      s.cash -= cost;

      if (s.position && s.position.type === type) {
          // Average Down/Up
          const totalCost = (s.position.avgEntry * s.position.count) + s.price;
          const newCount = s.position.count + 1;
          s.position.count = newCount;
          s.position.avgEntry = totalCost / newCount;
      } else if (s.position && s.position.type !== type) {
          // Flip Position (Close old, open new)
          closePosition();
          s.position = { type, count: 1, avgEntry: s.price };
      } else {
          // New Position
          s.position = { type, count: 1, avgEntry: s.price };
      }
  };

  const closePosition = () => {
      const s = state.current;
      if (s.position) {
          s.cash += s.unrealizedPnL + (s.position.count * 200); // Return principal + PnL
          s.position = null;
          s.unrealizedPnL = 0;
      }
  };

  const toggleGame = () => {
      state.current.isPlaying = !state.current.isPlaying;
      setUiState(prev => ({ ...prev, isPlaying: state.current.isPlaying }));
  };

  // Loop Effect
  useEffect(() => {
      let frameId: number;
      const loop = () => {
          updatePhysics();
          draw();
          frameId = requestAnimationFrame(loop);
      };
      frameId = requestAnimationFrame(loop);
      return () => cancelAnimationFrame(frameId);
  }, []);

  // Resize
  useEffect(() => {
      const canvas = canvasRef.current;
      const container = containerRef.current;
      if (canvas && container) {
          canvas.width = container.clientWidth;
          canvas.height = container.clientHeight;
      }
  }, []);

  return (
    <div ref={containerRef} className="relative w-full h-[600px] bg-slate-950 rounded-3xl overflow-hidden border border-white/10 shadow-2xl group">
        <canvas ref={canvasRef} className="w-full h-full block" />

        {/* --- HUD LAYER --- */}

        {/* Top Status Bar */}
        <div className="absolute top-0 left-0 w-full p-4 flex justify-between items-start pointer-events-none">
            <div className="flex gap-4">
                <div className="bg-black/60 backdrop-blur-md p-3 rounded-xl border border-white/10 text-white min-w-[140px]">
                    <div className="text-[10px] uppercase font-bold text-slate-400 flex items-center gap-2">
                        <Wallet className="w-3 h-3" /> Liquid Cash
                    </div>
                    <div className="text-xl font-mono font-bold tracking-tight">${Math.floor(uiState.cash).toLocaleString()}</div>
                </div>
                <div className={`bg-black/60 backdrop-blur-md p-3 rounded-xl border min-w-[140px] ${uiState.pnl >= 0 ? 'border-emerald-500/30' : 'border-rose-500/30'}`}>
                    <div className="text-[10px] uppercase font-bold text-slate-400 flex items-center gap-2">
                        <Activity className="w-3 h-3" /> Open P/L
                    </div>
                    <div className={`text-xl font-mono font-bold tracking-tight ${uiState.pnl >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                        {uiState.pnl >= 0 ? '+' : ''}{Math.floor(uiState.pnl).toLocaleString()}
                    </div>
                </div>
            </div>

            <div className="text-right">
                <div className="text-4xl font-black text-white font-mono tracking-tighter drop-shadow-lg">
                    {uiState.price.toFixed(2)}
                </div>
                <div className="text-xs font-bold uppercase text-slate-500 tracking-widest mt-1">Live Index</div>
            </div>
        </div>

        {/* Event Banner */}
        {uiState.event && (
            <div className="absolute top-24 left-1/2 -translate-x-1/2 animate-bounce-slight pointer-events-none">
                <div className="bg-rose-600 text-white px-6 py-2 rounded-full font-bold uppercase tracking-widest shadow-[0_0_30px_rgba(225,29,72,0.6)] flex items-center gap-2 border border-white/20">
                    <AlertTriangle className="w-5 h-5 animate-pulse" />
                    Warning: {uiState.event}
                </div>
            </div>
        )}

        {/* Center Start Screen */}
        {!uiState.isPlaying && (
            <div className="absolute inset-0 flex items-center justify-center bg-black/80 backdrop-blur-sm z-20">
                <div className="text-center space-y-6 max-w-md p-8">
                    <div className="inline-flex p-4 bg-indigo-600/20 rounded-full mb-2 ring-1 ring-indigo-500/50">
                        <Zap className="w-12 h-12 text-indigo-400" />
                    </div>
                    <h1 className="text-5xl font-black text-white tracking-tighter">VOLT RUNNER</h1>
                    <p className="text-slate-400 font-medium">
                        High-frequency trading simulation. Ride the volatility.
                        <br/>
                        <span className="text-indigo-400">Buy Calls</span> when trending up. <span className="text-rose-400">Buy Puts</span> when crashing.
                    </p>
                    <button 
                        onClick={toggleGame}
                        className="px-10 py-4 bg-white text-black font-bold rounded-full text-lg hover:scale-105 transition-transform shadow-[0_0_40px_rgba(255,255,255,0.3)] flex items-center gap-2 mx-auto"
                    >
                        <Play className="w-5 h-5 fill-current" /> INITIALIZE
                    </button>
                </div>
            </div>
        )}

        {/* Bottom Control Deck */}
        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-end gap-4 pointer-events-auto">

            {/* CALL BUTTON */}
            <button 
                onClick={() => buyOption('CALL')}
                className="group relative flex flex-col items-center gap-1"
            >
                <div className="w-24 h-24 bg-emerald-600/20 hover:bg-emerald-600/40 border-2 border-emerald-500/50 hover:border-emerald-400 rounded-2xl flex flex-col items-center justify-center backdrop-blur-md transition-all active:scale-95 shadow-[0_0_20px_rgba(16,185,129,0.2)]">
                    <TrendingUp className="w-8 h-8 text-emerald-400 mb-1" />
                    <span className="text-xs font-black text-emerald-100 uppercase tracking-wider">Buy Call</span>
                </div>
                {uiState.position?.type === 'CALL' && (
                    <div className="absolute -top-3 -right-3 bg-emerald-500 text-white text-xs font-bold w-6 h-6 rounded-full flex items-center justify-center border-2 border-slate-900">
                        {uiState.position.count}
                    </div>
                )}
            </button>

            {/* CLOSE BUTTON */}
            <button 
                onClick={closePosition}
                className="mb-2 w-20 h-20 bg-slate-800/80 hover:bg-slate-700 border-2 border-white/10 hover:border-white/30 rounded-full flex flex-col items-center justify-center backdrop-blur-md transition-all active:scale-95 group shadow-lg"
            >
                <ShieldAlert className={`w-6 h-6 mb-1 transition-colors ${uiState.position ? 'text-amber-400 animate-pulse' : 'text-slate-500'}`} />
                <span className="text-[9px] font-bold text-slate-300 uppercase">Cash Out</span>
            </button>

            {/* PUT BUTTON */}
            <button 
                onClick={() => buyOption('PUT')}
                className="group relative flex flex-col items-center gap-1"
            >
                <div className="w-24 h-24 bg-rose-600/20 hover:bg-rose-600/40 border-2 border-rose-500/50 hover:border-rose-400 rounded-2xl flex flex-col items-center justify-center backdrop-blur-md transition-all active:scale-95 shadow-[0_0_20px_rgba(244,63,94,0.2)]">
                    <TrendingDown className="w-8 h-8 text-rose-400 mb-1" />
                    <span className="text-xs font-black text-rose-100 uppercase tracking-wider">Buy Put</span>
                </div>
                {uiState.position?.type === 'PUT' && (
                    <div className="absolute -top-3 -right-3 bg-rose-500 text-white text-xs font-bold w-6 h-6 rounded-full flex items-center justify-center border-2 border-slate-900">
                        {uiState.position.count}
                    </div>
                )}
            </button>

        </div>

    </div>
  );
};

