import React, { useRef, useEffect, useState } from 'react';
import { TrendingUp, TrendingDown, Play, RotateCcw, X, DollarSign, Clock, Newspaper, Briefcase, Activity } from 'lucide-react';

interface Position {
  type: 'CALL' | 'PUT';
  contracts: number;
  avgEntry: number;
}

interface NewsEvent {
  time: number; // Minutes from 9:30
  headline: string;
  impact: number; // Price velocity impulse
  volatility: number; // Volatility multiplier
}

const OptionsRunnerGame: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Game Configuration
  const MARKET_OPEN_MINUTES = 0; // 9:30 AM is 0
  const MARKET_CLOSE_MINUTES = 390; // 4:00 PM is 390 (6.5 hours)
  const TIME_SPEED = 0.8; // Game speed (minutes per frame)

  // Simulation State (Refs for loop performance)
  const state = useRef({
    isPlaying: false,
    isFinished: false,
    marketTime: 0, // Minutes elapsed since open
    price: 150.00, // Starting SPY/Stock price
    velocity: 0,
    volatility: 0.15,
    trendBias: 0,

    // Data Buffers
    history: [] as { x: number, y: number, time: number }[], // x is unused in 3d proj, z mapped to time
    events: [] as { time: number, text: string, y: number }[],

    // Trading
    cash: 25000, // Day Trading Buying Power
    position: null as Position | null,
    realizedPnL: 0,
    unrealizedPnL: 0,

    // Camera
    cameraShake: 0
  });

  // React UI State (Synced periodically)
  const [ui, setUi] = useState({
    time: "09:30",
    price: 150.00,
    cash: 25000,
    pnl: 0,
    totalPnL: 0,
    position: null as Position | null,
    isPlaying: false,
    isFinished: false,
    lastEvent: ""
  });

  // --- Engine Logic ---

  const generateEvents = () => {
      // Pre-generate a script for the day or generate on the fly
      // Here we generate random events for the day
      const evts: NewsEvent[] = [];
      const numEvents = 4 + Math.floor(Math.random() * 3);

      for(let i=0; i<numEvents; i++) {
          const t = Math.floor(Math.random() * (MARKET_CLOSE_MINUTES - 60)) + 30; // Random time
          const types = [
              { h: "FED SPEAKER HAWKISH", i: -0.8, v: 2.0 },
              { h: "TECH SECTOR BREAKOUT", i: 0.8, v: 1.5 },
              { h: "JOBLESS CLAIMS MISS", i: -0.5, v: 1.8 },
              { h: "ALGO BUY PROGRAM", i: 0.6, v: 1.0 },
              { h: "INSTITUTIONAL SELLING", i: -0.6, v: 1.2 },
              { h: "OPEC PRODUCTION CUT", i: 0.4, v: 1.5 },
              { h: "CPI DATA HOT", i: -1.0, v: 2.5 }
          ];
          const type = types[Math.floor(Math.random() * types.length)];
          evts.push({ time: t, headline: type.h, impact: type.i, volatility: type.v });
      }
      return evts.sort((a,b) => a.time - b.time);
  };

  const dayEvents = useRef<NewsEvent[]>([]);

  const startGame = () => {
      state.current = {
          isPlaying: true,
          isFinished: false,
          marketTime: 0,
          price: 150.00,
          velocity: 0,
          volatility: 0.15,
          trendBias: 0,
          history: [],
          events: [],
          cash: 25000,
          position: null,
          realizedPnL: 0,
          unrealizedPnL: 0,
          cameraShake: 0
      };
      dayEvents.current = generateEvents();
      // Seed history
      for(let i=-50; i<0; i++) {
          state.current.history.push({ x: 0, y: 150, time: i });
      }
      setUi(prev => ({ ...prev, isPlaying: true, isFinished: false, cash: 25000, pnl: 0, totalPnL: 0, position: null }));
  };

  const updatePhysics = () => {
      const s = state.current;
      if (!s.isPlaying || s.isFinished) return;

      // 1. Advance Time
      s.marketTime += TIME_SPEED;

      if (s.marketTime >= MARKET_CLOSE_MINUTES) {
          s.isPlaying = false;
          s.isFinished = true;
          // Force close positions
          if (s.position) closePosition();
          setUi(prev => ({ ...prev, isPlaying: false, isFinished: true }));
          return;
      }

      // 2. Check Events
      const activeEvent = dayEvents.current.find(e => Math.abs(e.time - s.marketTime) < TIME_SPEED);
      if (activeEvent) {
          s.velocity += activeEvent.impact;
          s.volatility = 0.15 * activeEvent.volatility; // Spike vol
          s.events.push({ time: s.marketTime, text: activeEvent.headline, y: s.price });
          s.cameraShake = 15;
          setUi(prev => ({ ...prev, lastEvent: activeEvent.headline }));
      }

      // 3. Price Physics (Random Walk with Drift)
      // Mean reversion for velocity
      s.velocity *= 0.95; 
      // Trend bias recovery
      s.velocity += (Math.random() - 0.5) * s.volatility;

      s.price += s.velocity;
      if (s.price < 10) s.price = 10;

      // 4. Update History
      // Only push new point every integer minute to save memory/draw calls if needed, 
      // but for smooth 3D line we want every frame? No, history should be time-based.
      // Let's push every frame but cap size.
      s.history.push({ x: 0, y: s.price, time: s.marketTime });
      // Keep only last N points relative to view depth? 
      // Actually we want the full day chart usually, but for 3D runner we cull behind camera.
      // Camera moves with time.

      // 5. Update PnL
      if (s.position) {
          const diff = s.price - s.position.avgEntry;
          const dir = s.position.type === 'CALL' ? 1 : -1;
          // 1 contract = 100 shares delta roughly (simplified for game)
          s.unrealizedPnL = diff * dir * s.position.contracts * 100; 
      } else {
          s.unrealizedPnL = 0;
      }

      // 6. Shake Decay
      s.cameraShake *= 0.9;

      // Sync UI (throttled)
      // Format time
      const totalMin = 570 + s.marketTime; // 9:30 = 570 min
      const h = Math.floor(totalMin / 60);
      const m = Math.floor(totalMin % 60);
      const timeStr = `${h}:${m.toString().padStart(2, '0')}`;

      setUi(prev => ({
          ...prev,
          time: timeStr,
          price: s.price,
          pnl: s.unrealizedPnL,
          position: s.position ? {...s.position} : null,
          totalPnL: s.realizedPnL + s.unrealizedPnL
      }));
  };

  // --- Drawing ---
  const project = (time: number, y: number, width: number, height: number, currentTime: number, currentPrice: number) => {
      // World Coordinates:
      // X = 0 (we run straight)
      // Y = Price (relative to current price center)
      // Z = Time (relative to current time)

      const camZ = currentTime + 20; // Camera is ahead looking back? Or behind looking forward?
      // "Runner" style: Camera is at currentTime - offset, looking at currentTime + horizon
      // Actually, standard: Camera at T-10, looking at T+50.

      // Let's make "Right" be future/now, "Left" be past. Like a 2D chart but 3D.
      // Or "Into Screen" is future.
      // Let's go with: Price Line moves towards camera (Z decreases). 
      // Current Time is at Z=0. Past is Z > 0 (behind/further). Future is Z < 0.
      // Wait, standard 3D runner: Objects come towards camera.

      const zRel = (currentTime - time) * 10; // Scale time to space distance

      // If point is behind camera (too old)
      // Let's keep 100 minutes of history visible
      if (zRel < -50 || zRel > 800) return null;

      const yRel = (y - currentPrice) * 3; // Scale price height

      const fov = 600;
      const dist = 300; // Camera distance
      const scale = fov / (dist + zRel);

      // X skew for perspective?
      // Let's just do straight tunnel.
      const x2d = width / 2; 
      const y2d = height / 2 - yRel * scale;

      // To make it look like a chart, we need X-axis to be Time.
      // Let's rotate 90 deg.
      // New Mapping:
      // X = Time (Left/Right)
      // Y = Price (Up/Down)
      // Z = Depth (Tilt)

      // Let's do a "Tilted Table" view.
      // Current Time is Far Right.
      // Past is Left.

      // Normalized X on screen (0 to 1) based on time window
      // View Window: [CurrentTime - 60, CurrentTime]
      // This is a 2D chart. The user asked for "Creative 3D".

      // Revert to "Tunnel" idea.
      // We fly ALONG the line.
      // Current Time is "Player Position".
      // We look slightly ahead and see the past trailing behind?
      // No, usually you look forward into the unknown.
      // But we can only draw history.

      // Best 3D Chart View: Isometric Side View.
      // Time flows into the screen (Z).
      // Current Price is closest to viewer (Z=0).
      // Past is deep in Z.

      const z = (currentTime - time) * 8; // Past is positive Z (into screen)
      const scaleIso = fov / (400 + z);

      const x2 = width/2 + (0) * scaleIso; // Centered horizontally? 
      // Add some parallax/curve to X to make it look cool?
      const xOffset = Math.sin(time * 0.05) * 50; 

      const xFinal = width/2 + xOffset * scaleIso; // Wiggle path
      const yFinal = height/2 - ((y - currentPrice) * 4) * scaleIso;

      return { x: xFinal, y: yFinal, scale: scaleIso, z };
  };

  const draw = () => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      const width = canvas.width;
      const height = canvas.height;
      const s = state.current;

      // Shake
      const sx = (Math.random() - 0.5) * s.cameraShake;
      const sy = (Math.random() - 0.5) * s.cameraShake;

      // Clear
      const bg = ctx.createLinearGradient(0,0,0,height);
      bg.addColorStop(0, '#0f172a');
      bg.addColorStop(1, '#020617');
      ctx.fillStyle = bg;
      ctx.fillRect(0, 0, width, height);

      // --- Draw Grid (Floor/Ceiling) ---
      // We simulate a tunnel of time
      ctx.strokeStyle = 'rgba(255,255,255,0.05)';
      ctx.lineWidth = 1;

      // Vertical lines (Time markers)
      // We draw lines at every 10 minutes relative to current time
      const startGrid = Math.floor((s.marketTime - 60) / 10) * 10;
      for(let t = startGrid; t < s.marketTime + 10; t+=10) {
          // Project top and bottom points
          const pTop = project(t, s.price + 20, width, height, s.marketTime, s.price);
          const pBot = project(t, s.price - 20, width, height, s.marketTime, s.price);

          if (pTop && pBot) {
              ctx.beginPath();
              ctx.moveTo(pTop.x + sx, pTop.y + sy);
              ctx.lineTo(pBot.x + sx, pBot.y + sy);
              ctx.stroke();

              // Time Label
              if (t % 30 === 0 && t <= s.marketTime) {
                  const labelTime = 570 + t; // 9:30 start
                  const h = Math.floor(labelTime/60);
                  const m = labelTime%60;
                  ctx.fillStyle = 'rgba(255,255,255,0.3)';
                  ctx.font = '10px monospace';
                  ctx.textAlign = 'right';
                  ctx.fillText(`${h}:${m===0?'00':m}`, pBot.x - 10 + sx, pBot.y + sy);
              }
          }
      }

      // --- Draw Price Line ---
      // Draw from History
      if (s.history.length > 1) {
          ctx.beginPath();
          ctx.lineWidth = 4;
          ctx.lineJoin = 'round';
          ctx.shadowBlur = 15;
          ctx.shadowColor = s.velocity > 0 ? '#10b981' : '#f43f5e';
          ctx.strokeStyle = s.velocity > 0 ? '#10b981' : '#f43f5e';

          // We draw backwards from current (closest) to past (farthest)
          // Optimization: skip points based on Z depth
          let started = false;
          for (let i = s.history.length - 1; i >= 0; i-=2) { // Skip every 2nd point for perf
              const point = s.history[i];
              const p = project(point.time, point.y, width, height, s.marketTime, s.price);

              if (p) {
                  if (!started) {
                      ctx.moveTo(p.x + sx, p.y + sy);
                      started = true;
                  } else {
                      ctx.lineTo(p.x + sx, p.y + sy);
                  }
              }
          }
          ctx.stroke();
          ctx.shadowBlur = 0;
      }

      // --- Draw Event Markers (Billboards) ---
      s.events.forEach(evt => {
          const p = project(evt.time, evt.y, width, height, s.marketTime, s.price);
          if (p && p.z > 0 && p.z < 600) {
              // Draw a vertical line from price to label
              ctx.beginPath();
              ctx.moveTo(p.x + sx, p.y + sy);
              ctx.lineTo(p.x + sx, p.y - 40 * p.scale + sy);
              ctx.strokeStyle = 'rgba(255,255,255,0.5)';
              ctx.lineWidth = 1;
              ctx.stroke();

              // Draw Billboard
              const w = 120 * p.scale;
              const h = 40 * p.scale;
              const bx = p.x - w/2 + sx;
              const by = p.y - 40 * p.scale - h + sy;

              ctx.fillStyle = 'rgba(30, 41, 59, 0.9)'; // Slate 800
              ctx.fillRect(bx, by, w, h);
              ctx.strokeStyle = '#ffffff';
              ctx.strokeRect(bx, by, w, h);

              ctx.fillStyle = '#ffffff';
              ctx.textAlign = 'center';
              ctx.font = `bold ${10 * p.scale}px sans-serif`;
              ctx.fillText("NEWS ALERT", p.x + sx, by + 12 * p.scale);

              ctx.fillStyle = '#94a3b8';
              ctx.font = `${8 * p.scale}px monospace`;
              ctx.fillText(evt.text.substring(0, 15), p.x + sx, by + 25 * p.scale);
          }
      });

      // --- Draw HUD Elements in World Space ---
      // Current Price "Head"
      const head = project(s.marketTime, s.price, width, height, s.marketTime, s.price);
      if (head) {
          ctx.beginPath();
          ctx.arc(head.x + sx, head.y + sy, 6, 0, Math.PI * 2);
          ctx.fillStyle = '#fff';
          ctx.fill();

          // Pulse
          ctx.beginPath();
          ctx.arc(head.x + sx, head.y + sy, 15, 0, Math.PI * 2);
          ctx.strokeStyle = 'rgba(255,255,255,0.3)';
          ctx.stroke();
      }

      // Position Entry Line
      if (s.position) {
          const entryP = project(s.marketTime, s.position.avgEntry, width, height, s.marketTime, s.price);
          // Just draw a horizontal line at that Y relative to head
          if (head) {
              const yDiff = (s.position.avgEntry - s.price) * 3 * head.scale; // Approx scale at Z=0
              const yLine = head.y - yDiff; // Inverted Y logic in project

              // Actually re-project properly to get depth scaling right if we drew a plane
              // But for a HUD line, screen space relative to head is safer visual

              ctx.beginPath();
              ctx.strokeStyle = s.position.type === 'CALL' ? '#10b981' : '#f43f5e';
              ctx.setLineDash([5, 5]);
              ctx.moveTo(0, yLine + sy);
              ctx.lineTo(width, yLine + sy);
              ctx.stroke();
              ctx.setLineDash([]);

              ctx.fillStyle = s.position.type === 'CALL' ? '#10b981' : '#f43f5e';
              ctx.font = 'bold 12px monospace';
              ctx.fillText(`${s.position.type} AVG`, width - 60, yLine - 5 + sy);
          }
      }
  };

  // --- Actions ---
  const handleBuy = (type: 'CALL' | 'PUT') => {
      const s = state.current;
      const premium = 2.50; // Simplified contract price ($250)
      const cost = premium * 100;

      if (s.cash >= cost) {
          s.cash -= cost;
          if (s.position && s.position.type === type) {
              // Add
              const totalVal = (s.position.avgEntry * s.position.contracts) + s.price; // Simplified avg entry logic based on underlying
              // Wait, avg entry for options should be premium. 
              // But for this game, we track underlying entry price to calc PnL delta easily.
              // Let's stick to Underlying Entry Price approach for visual simplicity.
              const totalUnderlying = (s.position.avgEntry * s.position.contracts) + s.price;
              s.position.contracts += 1;
              s.position.avgEntry = totalUnderlying / s.position.contracts;
          } else {
              if (s.position) closePosition(); // Auto-flip
              s.position = { type, contracts: 1, avgEntry: s.price };
          }
      }
  };

  const closePosition = () => {
      const s = state.current;
      if (s.position) {
          s.realizedPnL += s.unrealizedPnL;
          s.cash += (250 * s.position.contracts) + s.unrealizedPnL; // Return principal roughly + PnL
          s.position = null;
          s.unrealizedPnL = 0;
      }
  };

  // Loop
  useEffect(() => {
      let frameId: number;
      const loop = () => {
          updatePhysics();
          draw();
          frameId = requestAnimationFrame(loop);
      };
      frameId = requestAnimationFrame(loop);
      return () => cancelAnimationFrame(frameId);
  }, []);

  // Resize
  useEffect(() => {
      if (canvasRef.current && containerRef.current) {
          canvasRef.current.width = containerRef.current.clientWidth;
          canvasRef.current.height = containerRef.current.clientHeight;
      }
  }, []);

  return (
    <div ref={containerRef} className="relative w-full h-[600px] bg-slate-950 rounded-3xl overflow-hidden border border-white/10 shadow-2xl group select-none">
        <canvas ref={canvasRef} className="w-full h-full block" />

        {/* --- START SCREEN --- */}
        {!ui.isPlaying && !ui.isFinished && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/80 backdrop-blur-md z-50">
                <div className="text-center space-y-6 max-w-lg">
                    <h1 className="text-5xl font-black text-white tracking-tighter mb-2">DAY TRADER SIM</h1>
                    <div className="grid grid-cols-2 gap-4 text-left bg-slate-900/50 p-6 rounded-2xl border border-white/10">
                        <div className="space-y-2">
                            <div className="flex items-center gap-2 text-slate-400 text-sm font-bold uppercase"><Clock className="w-4 h-4"/> Time</div>
                            <div className="text-white font-mono">09:30 - 16:00</div>
                        </div>
                        <div className="space-y-2">
                            <div className="flex items-center gap-2 text-slate-400 text-sm font-bold uppercase"><Wallet className="w-4 h-4"/> Capital</div>
                            <div className="text-white font-mono">$25,000</div>
                        </div>
                        <div className="col-span-2 text-xs text-slate-500 mt-2 border-t border-white/5 pt-2">
                            React to breaking news events. Manage volatility. Do not blow up the account.
                        </div>
                    </div>
                    <button 
                        onClick={startGame}
                        className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-xl text-lg tracking-widest shadow-[0_0_30px_rgba(79,70,229,0.4)] transition-all hover:scale-[1.02]"
                    >
                        OPEN MARKET
                    </button>
                </div>
            </div>
        )}

        {/* --- GAME OVER SCREEN --- */}
        {ui.isFinished && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/90 backdrop-blur-md z-50">
                <div className="bg-slate-900 border border-white/10 p-8 rounded-3xl text-center max-w-md w-full shadow-2xl">
                    <h2 className="text-3xl font-black text-white mb-6">MARKET CLOSED</h2>

                    <div className="space-y-4 mb-8">
                        <div className="flex justify-between items-center text-slate-400 text-sm">
                            <span>Final P&L</span>
                            <span className={`font-mono text-xl font-bold ${ui.totalPnL >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                                {ui.totalPnL >= 0 ? '+' : ''}${Math.floor(ui.totalPnL).toLocaleString()}
                            </span>
                        </div>
                        <div className="flex justify-between items-center text-slate-400 text-sm">
                            <span>Ending Balance</span>
                            <span className="font-mono text-white font-bold">${Math.floor(ui.cash + ui.totalPnL).toLocaleString()}</span>
                        </div>
                    </div>

                    <button 
                        onClick={startGame}
                        className="w-full py-3 bg-white text-black font-bold rounded-xl flex items-center justify-center gap-2 hover:bg-slate-200 transition-colors"
                    >
                        <RotateCcw className="w-4 h-4" /> Next Trading Day
                    </button>
                </div>
            </div>
        )}

        {/* --- HUD --- */}
        {/* Top Bar: Time & Ticker */}
        <div className="absolute top-0 left-0 w-full p-6 flex justify-between items-start pointer-events-none">
            <div className="bg-slate-900/80 backdrop-blur border border-white/10 px-4 py-2 rounded-xl flex items-center gap-4">
                <div className="flex items-center gap-2">
                    <Clock className="w-4 h-4 text-indigo-400" />
                    <span className="font-mono font-bold text-xl text-white tracking-widest">{ui.time}</span>
                </div>
                <div className="h-6 w-px bg-white/10"></div>
                <div className="flex items-center gap-2">
                    <span className="text-slate-400 font-bold">SPY</span>
                    <span className="font-mono font-bold text-white">${ui.price.toFixed(2)}</span>
                </div>
            </div>

            {/* PnL Display */}
            <div className={`bg-slate-900/80 backdrop-blur border px-6 py-2 rounded-xl flex flex-col items-end ${ui.totalPnL >= 0 ? 'border-emerald-500/30' : 'border-rose-500/30'}`}>
                <span className="text-[10px] text-slate-500 uppercase font-bold tracking-wider">Session P&L</span>
                <span className={`font-mono text-2xl font-black ${ui.totalPnL >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                    {ui.totalPnL >= 0 ? '+' : ''}${Math.floor(ui.totalPnL).toLocaleString()}
                </span>
            </div>
        </div>

        {/* Dynamic News Ticker (Floating) */}
        {ui.lastEvent && (
            <div className="absolute top-24 left-1/2 -translate-x-1/2 animate-bounce-slight pointer-events-none">
                <div className="bg-slate-800/90 text-white px-4 py-2 rounded-lg border border-white/10 shadow-xl flex items-center gap-3">
                    <span className="relative flex h-2 w-2">
                      <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-rose-400 opacity-75"></span>
                      <span className="relative inline-flex rounded-full h-2 w-2 bg-rose-500"></span>
                    </span>
                    <span className="font-bold text-sm tracking-wide">{ui.lastEvent}</span>
                </div>
            </div>
        )}

        {/* Bottom Trading Desk */}
        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-end gap-3 pointer-events-auto">

            {/* CALL */}
            <button 
                onClick={() => handleBuy('CALL')}
                className="group w-28 h-24 bg-emerald-600/10 hover:bg-emerald-600/20 border border-emerald-500/30 hover:border-emerald-400 rounded-xl backdrop-blur-md flex flex-col items-center justify-center transition-all active:scale-95"
            >
                <TrendingUp className="w-6 h-6 text-emerald-400 mb-1 group-hover:scale-110 transition-transform" />
                <span className="text-xs font-bold text-emerald-100">BUY CALL</span>
                <span className="text-[9px] text-emerald-500/70 mt-1">Bullish</span>

                {ui.position?.type === 'CALL' && (
                    <div className="absolute -top-2 -right-2 bg-emerald-500 text-slate-900 w-6 h-6 rounded-full flex items-center justify-center font-bold text-xs shadow-lg">
                        {ui.position.contracts}
                    </div>
                )}
            </button>

            {/* CLOSE POSITION (Contextual) */}
            <div className="w-32 h-24 flex items-center justify-center">
                {ui.position ? (
                    <button 
                        onClick={closePosition}
                        className="w-full h-16 bg-slate-800 hover:bg-slate-700 border border-white/20 hover:border-white/40 rounded-xl flex flex-col items-center justify-center shadow-lg transition-all active:scale-95"
                    >
                        <span className="text-[10px] text-slate-400 font-bold uppercase mb-1">Unrealized</span>
                        <span className={`font-mono text-lg font-bold ${ui.pnl >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                            {ui.pnl >= 0 ? '+' : ''}${Math.floor(ui.pnl)}
                        </span>
                        <span className="text-[9px] text-slate-500 mt-1">CLICK TO CLOSE</span>
                    </button>
                ) : (
                    <div className="text-center opacity-30">
                        <Briefcase className="w-6 h-6 mx-auto mb-1" />
                        <span className="text-[10px] font-bold uppercase">No Position</span>
                    </div>
                )}
            </div>

            {/* PUT */}
            <button 
                onClick={() => handleBuy('PUT')}
                className="group w-28 h-24 bg-rose-600/10 hover:bg-rose-600/20 border border-rose-500/30 hover:border-rose-400 rounded-xl backdrop-blur-md flex flex-col items-center justify-center transition-all active:scale-95"
            >
                <TrendingDown className="w-6 h-6 text-rose-400 mb-1 group-hover:scale-110 transition-transform" />
                <span className="text-xs font-bold text-rose-100">BUY PUT</span>
                <span className="text-[9px] text-rose-500/70 mt-1">Bearish</span>

                {ui.position?.type === 'PUT' && (
                    <div className="absolute -top-2 -right-2 bg-rose-500 text-slate-900 w-6 h-6 rounded-full flex items-center justify-center font-bold text-xs shadow-lg">
                        {ui.position.contracts}
                    </div>
                )}
            </button>

        </div>

    </div>
  );
};

export default OptionsRunnerGame;

import React, { useRef, useEffect, useState } from 'react';
import { TrendingUp, TrendingDown, Play, RotateCcw, X, DollarSign, Clock, Newspaper, Briefcase, Activity, Wallet } from 'lucide-react';

interface Position {
  type: 'CALL' | 'PUT';
  contracts: number;
  avgEntry: number;
}

interface NewsEvent {
  time: number; // Minutes from 9:30
  headline: string;
  impact: number; // Price velocity impulse
  volatility: number; // Volatility multiplier
}

const OptionsRunnerGame: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Game Configuration
  const MARKET_OPEN_MINUTES = 0; // 9:30 AM is 0
  const MARKET_CLOSE_MINUTES = 390; // 4:00 PM is 390 (6.5 hours)
  const TIME_SPEED = 0.8; // Game speed (minutes per frame)

  // Simulation State (Refs for loop performance)
  const state = useRef({
    isPlaying: false,
    isFinished: false,
    marketTime: 0, // Minutes elapsed since open
    price: 150.00, // Starting SPY/Stock price
    velocity: 0,
    volatility: 0.15,
    trendBias: 0,

    // Data Buffers
    history: [] as { x: number, y: number, time: number }[], // x is unused in 3d proj, z mapped to time
    events: [] as { time: number, text: string, y: number }[],

    // Trading
    cash: 25000, // Day Trading Buying Power
    position: null as Position | null,
    realizedPnL: 0,
    unrealizedPnL: 0,

    // Camera
    cameraShake: 0
  });

  // React UI State (Synced periodically)
  const [ui, setUi] = useState({
    time: "09:30",
    price: 150.00,
    cash: 25000,
    pnl: 0,
    totalPnL: 0,
    position: null as Position | null,
    isPlaying: false,
    isFinished: false,
    lastEvent: ""
  });

  // --- Engine Logic ---

  const generateEvents = () => {
      // Pre-generate a script for the day or generate on the fly
      // Here we generate random events for the day
      const evts: NewsEvent[] = [];
      const numEvents = 4 + Math.floor(Math.random() * 3);

      for(let i=0; i<numEvents; i++) {
          const t = Math.floor(Math.random() * (MARKET_CLOSE_MINUTES - 60)) + 30; // Random time
          const types = [
              { h: "FED SPEAKER HAWKISH", i: -0.8, v: 2.0 },
              { h: "TECH SECTOR BREAKOUT", i: 0.8, v: 1.5 },
              { h: "JOBLESS CLAIMS MISS", i: -0.5, v: 1.8 },
              { h: "ALGO BUY PROGRAM", i: 0.6, v: 1.0 },
              { h: "INSTITUTIONAL SELLING", i: -0.6, v: 1.2 },
              { h: "OPEC PRODUCTION CUT", i: 0.4, v: 1.5 },
              { h: "CPI DATA HOT", i: -1.0, v: 2.5 }
          ];
          const type = types[Math.floor(Math.random() * types.length)];
          evts.push({ time: t, headline: type.h, impact: type.i, volatility: type.v });
      }
      return evts.sort((a,b) => a.time - b.time);
  };

  const dayEvents = useRef<NewsEvent[]>([]);

  const startGame = () => {
      state.current = {
          isPlaying: true,
          isFinished: false,
          marketTime: 0,
          price: 150.00,
          velocity: 0,
          volatility: 0.15,
          trendBias: 0,
          history: [],
          events: [],
          cash: 25000,
          position: null,
          realizedPnL: 0,
          unrealizedPnL: 0,
          cameraShake: 0
      };
      dayEvents.current = generateEvents();
      // Seed history
      for(let i=-50; i<0; i++) {
          state.current.history.push({ x: 0, y: 150, time: i });
      }
      setUi(prev => ({ ...prev, isPlaying: true, isFinished: false, cash: 25000, pnl: 0, totalPnL: 0, position: null }));
  };

  const updatePhysics = () => {
      const s = state.current;
      if (!s.isPlaying || s.isFinished) return;

      // 1. Advance Time
      s.marketTime += TIME_SPEED;

      if (s.marketTime >= MARKET_CLOSE_MINUTES) {
          s.isPlaying = false;
          s.isFinished = true;
          // Force close positions
          if (s.position) closePosition();
          setUi(prev => ({ ...prev, isPlaying: false, isFinished: true }));
          return;
      }

      // 2. Check Events
      const activeEvent = dayEvents.current.find(e => Math.abs(e.time - s.marketTime) < TIME_SPEED);
      if (activeEvent) {
          s.velocity += activeEvent.impact;
          s.volatility = 0.15 * activeEvent.volatility; // Spike vol
          s.events.push({ time: s.marketTime, text: activeEvent.headline, y: s.price });
          s.cameraShake = 15;
          setUi(prev => ({ ...prev, lastEvent: activeEvent.headline }));
      }

      // 3. Price Physics (Random Walk with Drift)
      // Mean reversion for velocity
      s.velocity *= 0.95; 
      // Trend bias recovery
      s.velocity += (Math.random() - 0.5) * s.volatility;

      s.price += s.velocity;
      if (s.price < 10) s.price = 10;

      // 4. Update History
      // Only push new point every integer minute to save memory/draw calls if needed, 
      // but for smooth 3D line we want every frame? No, history should be time-based.
      // Let's push every frame but cap size.
      s.history.push({ x: 0, y: s.price, time: s.marketTime });
      // Keep only last N points relative to view depth? 
      // Actually we want the full day chart usually, but for 3D runner we cull behind camera.
      // Camera moves with time.

      // 5. Update PnL
      if (s.position) {
          const diff = s.price - s.position.avgEntry;
          const dir = s.position.type === 'CALL' ? 1 : -1;
          // 1 contract = 100 shares delta roughly (simplified for game)
          s.unrealizedPnL = diff * dir * s.position.contracts * 100; 
      } else {
          s.unrealizedPnL = 0;
      }

      // 6. Shake Decay
      s.cameraShake *= 0.9;

      // Sync UI (throttled)
      // Format time
      const totalMin = 570 + s.marketTime; // 9:30 = 570 min
      const h = Math.floor(totalMin / 60);
      const m = Math.floor(totalMin % 60);
      const timeStr = `${h}:${m.toString().padStart(2, '0')}`;

      setUi(prev => ({
          ...prev,
          time: timeStr,
          price: s.price,
          pnl: s.unrealizedPnL,
          position: s.position ? {...s.position} : null,
          totalPnL: s.realizedPnL + s.unrealizedPnL
      }));
  };

  // --- Drawing ---
  const project = (time: number, y: number, width: number, height: number, currentTime: number, currentPrice: number) => {
      // World Coordinates:
      // X = 0 (we run straight)
      // Y = Price (relative to current price center)
      // Z = Time (relative to current time)

      const camZ = currentTime + 20; // Camera is ahead looking back? Or behind looking forward?
      // "Runner" style: Camera is at currentTime - offset, looking at currentTime + horizon
      // Actually, standard: Camera at T-10, looking at T+50.

      // Let's make "Right" be future/now, "Left" be past. Like a 2D chart but 3D.
      // Or "Into Screen" is future.
      // Let's go with: Price Line moves towards camera (Z decreases). 
      // Current Time is at Z=0. Past is Z > 0 (behind/further). Future is Z < 0.
      // Wait, standard 3D runner: Objects come towards camera.

      const zRel = (currentTime - time) * 10; // Scale time to space distance

      // If point is behind camera (too old)
      // Let's keep 100 minutes of history visible
      if (zRel < -50 || zRel > 800) return null;

      const yRel = (y - currentPrice) * 3; // Scale price height

      const fov = 600;
      const dist = 300; // Camera distance
      const scale = fov / (dist + zRel);

      // X skew for perspective?
      // Let's just do straight tunnel.
      const x2d = width / 2; 
      const y2d = height / 2 - yRel * scale;

      // To make it look like a chart, we need X-axis to be Time.
      // Let's rotate 90 deg.
      // New Mapping:
      // X = Time (Left/Right)
      // Y = Price (Up/Down)
      // Z = Depth (Tilt)

      // Let's do a "Tilted Table" view.
      // Current Time is Far Right.
      // Past is Left.

      // Normalized X on screen (0 to 1) based on time window
      // View Window: [CurrentTime - 60, CurrentTime]
      // This is a 2D chart. The user asked for "Creative 3D".

      // Revert to "Tunnel" idea.
      // We fly ALONG the line.
      // Current Time is "Player Position".
      // We look slightly ahead and see the past trailing behind?
      // No, usually you look forward into the unknown.
      // But we can only draw history.

      // Best 3D Chart View: Isometric Side View.
      // Time flows into the screen (Z).
      // Current Price is closest to viewer (Z=0).
      // Past is deep in Z.

      const z = (currentTime - time) * 8; // Past is positive Z (into screen)
      const scaleIso = fov / (400 + z);

      const x2 = width/2 + (0) * scaleIso; // Centered horizontally? 
      // Add some parallax/curve to X to make it look cool?
      const xOffset = Math.sin(time * 0.05) * 50; 

      const xFinal = width/2 + xOffset * scaleIso; // Wiggle path
      const yFinal = height/2 - ((y - currentPrice) * 4) * scaleIso;

      return { x: xFinal, y: yFinal, scale: scaleIso, z };
  };

  const draw = () => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      const width = canvas.width;
      const height = canvas.height;
      const s = state.current;

      // Shake
      const sx = (Math.random() - 0.5) * s.cameraShake;
      const sy = (Math.random() - 0.5) * s.cameraShake;

      // Clear
      const bg = ctx.createLinearGradient(0,0,0,height);
      bg.addColorStop(0, '#0f172a');
      bg.addColorStop(1, '#020617');
      ctx.fillStyle = bg;
      ctx.fillRect(0, 0, width, height);

      // --- Draw Grid (Floor/Ceiling) ---
      // We simulate a tunnel of time
      ctx.strokeStyle = 'rgba(255,255,255,0.05)';
      ctx.lineWidth = 1;

      // Vertical lines (Time markers)
      // We draw lines at every 10 minutes relative to current time
      const startGrid = Math.floor((s.marketTime - 60) / 10) * 10;
      for(let t = startGrid; t < s.marketTime + 10; t+=10) {
          // Project top and bottom points
          const pTop = project(t, s.price + 20, width, height, s.marketTime, s.price);
          const pBot = project(t, s.price - 20, width, height, s.marketTime, s.price);

          if (pTop && pBot) {
              ctx.beginPath();
              ctx.moveTo(pTop.x + sx, pTop.y + sy);
              ctx.lineTo(pBot.x + sx, pBot.y + sy);
              ctx.stroke();

              // Time Label
              if (t % 30 === 0 && t <= s.marketTime) {
                  const labelTime = 570 + t; // 9:30 start
                  const h = Math.floor(labelTime/60);
                  const m = labelTime%60;
                  ctx.fillStyle = 'rgba(255,255,255,0.3)';
                  ctx.font = '10px monospace';
                  ctx.textAlign = 'right';
                  ctx.fillText(`${h}:${m===0?'00':m}`, pBot.x - 10 + sx, pBot.y + sy);
              }
          }
      }

      // --- Draw Price Line ---
      // Draw from History
      if (s.history.length > 1) {
          ctx.beginPath();
          ctx.lineWidth = 4;
          ctx.lineJoin = 'round';
          ctx.shadowBlur = 15;
          ctx.shadowColor = s.velocity > 0 ? '#10b981' : '#f43f5e';
          ctx.strokeStyle = s.velocity > 0 ? '#10b981' : '#f43f5e';

          // We draw backwards from current (closest) to past (farthest)
          // Optimization: skip points based on Z depth
          let started = false;
          for (let i = s.history.length - 1; i >= 0; i-=2) { // Skip every 2nd point for perf
              const point = s.history[i];
              const p = project(point.time, point.y, width, height, s.marketTime, s.price);

              if (p) {
                  if (!started) {
                      ctx.moveTo(p.x + sx, p.y + sy);
                      started = true;
                  } else {
                      ctx.lineTo(p.x + sx, p.y + sy);
                  }
              }
          }
          ctx.stroke();
          ctx.shadowBlur = 0;
      }

      // --- Draw Event Markers (Billboards) ---
      s.events.forEach(evt => {
          const p = project(evt.time, evt.y, width, height, s.marketTime, s.price);
          if (p && p.z > 0 && p.z < 600) {
              // Draw a vertical line from price to label
              ctx.beginPath();
              ctx.moveTo(p.x + sx, p.y + sy);
              ctx.lineTo(p.x + sx, p.y - 40 * p.scale + sy);
              ctx.strokeStyle = 'rgba(255,255,255,0.5)';
              ctx.lineWidth = 1;
              ctx.stroke();

              // Draw Billboard
              const w = 120 * p.scale;
              const h = 40 * p.scale;
              const bx = p.x - w/2 + sx;
              const by = p.y - 40 * p.scale - h + sy;

              ctx.fillStyle = 'rgba(30, 41, 59, 0.9)'; // Slate 800
              ctx.fillRect(bx, by, w, h);
              ctx.strokeStyle = '#ffffff';
              ctx.strokeRect(bx, by, w, h);

              ctx.fillStyle = '#ffffff';
              ctx.textAlign = 'center';
              ctx.font = `bold ${10 * p.scale}px sans-serif`;
              ctx.fillText("NEWS ALERT", p.x + sx, by + 12 * p.scale);

              ctx.fillStyle = '#94a3b8';
              ctx.font = `${8 * p.scale}px monospace`;
              ctx.fillText(evt.text.substring(0, 15), p.x + sx, by + 25 * p.scale);
          }
      });

      // --- Draw HUD Elements in World Space ---
      // Current Price "Head"
      const head = project(s.marketTime, s.price, width, height, s.marketTime, s.price);
      if (head) {
          ctx.beginPath();
          ctx.arc(head.x + sx, head.y + sy, 6, 0, Math.PI * 2);
          ctx.fillStyle = '#fff';
          ctx.fill();

          // Pulse
          ctx.beginPath();
          ctx.arc(head.x + sx, head.y + sy, 15, 0, Math.PI * 2);
          ctx.strokeStyle = 'rgba(255,255,255,0.3)';
          ctx.stroke();
      }

      // Position Entry Line
      if (s.position) {
          const entryP = project(s.marketTime, s.position.avgEntry, width, height, s.marketTime, s.price);
          // Just draw a horizontal line at that Y relative to head
          if (head) {
              const yDiff = (s.position.avgEntry - s.price) * 3 * head.scale; // Approx scale at Z=0
              const yLine = head.y - yDiff; // Inverted Y logic in project

              // Actually re-project properly to get depth scaling right if we drew a plane
              // But for a HUD line, screen space relative to head is safer visual

              ctx.beginPath();
              ctx.strokeStyle = s.position.type === 'CALL' ? '#10b981' : '#f43f5e';
              ctx.setLineDash([5, 5]);
              ctx.moveTo(0, yLine + sy);
              ctx.lineTo(width, yLine + sy);
              ctx.stroke();
              ctx.setLineDash([]);

              ctx.fillStyle = s.position.type === 'CALL' ? '#10b981' : '#f43f5e';
              ctx.font = 'bold 12px monospace';
              ctx.fillText(`${s.position.type} AVG`, width - 60, yLine - 5 + sy);
          }
      }
  };

  // --- Actions ---
  const handleBuy = (type: 'CALL' | 'PUT') => {
      const s = state.current;
      const premium = 2.50; // Simplified contract price ($250)
      const cost = premium * 100;

      if (s.cash >= cost) {
          s.cash -= cost;
          if (s.position && s.position.type === type) {
              // Add
              const totalVal = (s.position.avgEntry * s.position.contracts) + s.price; // Simplified avg entry logic based on underlying
              // Wait, avg entry for options should be premium. 
              // But for this game, we track underlying entry price to calc PnL delta easily.
              // Let's stick to Underlying Entry Price approach for visual simplicity.
              const totalUnderlying = (s.position.avgEntry * s.position.contracts) + s.price;
              s.position.contracts += 1;
              s.position.avgEntry = totalUnderlying / s.position.contracts;
          } else {
              if (s.position) closePosition(); // Auto-flip
              s.position = { type, contracts: 1, avgEntry: s.price };
          }
      }
  };

  const closePosition = () => {
      const s = state.current;
      if (s.position) {
          s.realizedPnL += s.unrealizedPnL;
          s.cash += (250 * s.position.contracts) + s.unrealizedPnL; // Return principal roughly + PnL
          s.position = null;
          s.unrealizedPnL = 0;
      }
  };

  // Loop
  useEffect(() => {
      let frameId: number;
      const loop = () => {
          updatePhysics();
          draw();
          frameId = requestAnimationFrame(loop);
      };
      frameId = requestAnimationFrame(loop);
      return () => cancelAnimationFrame(frameId);
  }, []);

  // Resize
  useEffect(() => {
      if (canvasRef.current && containerRef.current) {
          canvasRef.current.width = containerRef.current.clientWidth;
          canvasRef.current.height = containerRef.current.clientHeight;
      }
  }, []);

  return (
    <div ref={containerRef} className="relative w-full h-[600px] bg-slate-950 rounded-3xl overflow-hidden border border-white/10 shadow-2xl group select-none">
        <canvas ref={canvasRef} className="w-full h-full block" />

        {/* --- START SCREEN --- */}
        {!ui.isPlaying && !ui.isFinished && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/80 backdrop-blur-md z-50">
                <div className="text-center space-y-6 max-w-lg">
                    <h1 className="text-5xl font-black text-white tracking-tighter mb-2">DAY TRADER SIM</h1>
                    <div className="grid grid-cols-2 gap-4 text-left bg-slate-900/50 p-6 rounded-2xl border border-white/10">
                        <div className="space-y-2">
                            <div className="flex items-center gap-2 text-slate-400 text-sm font-bold uppercase"><Clock className="w-4 h-4"/> Time</div>
                            <div className="text-white font-mono">09:30 - 16:00</div>
                        </div>
                        <div className="space-y-2">
                            <div className="flex items-center gap-2 text-slate-400 text-sm font-bold uppercase"><Wallet className="w-4 h-4"/> Capital</div>
                            <div className="text-white font-mono">$25,000</div>
                        </div>
                        <div className="col-span-2 text-xs text-slate-500 mt-2 border-t border-white/5 pt-2">
                            React to breaking news events. Manage volatility. Do not blow up the account.
                        </div>
                    </div>
                    <button 
                        onClick={startGame}
                        className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-xl text-lg tracking-widest shadow-[0_0_30px_rgba(79,70,229,0.4)] transition-all hover:scale-[1.02]"
                    >
                        OPEN MARKET
                    </button>
                </div>
            </div>
        )}

        {/* --- GAME OVER SCREEN --- */}
        {ui.isFinished && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/90 backdrop-blur-md z-50">
                <div className="bg-slate-900 border border-white/10 p-8 rounded-3xl text-center max-w-md w-full shadow-2xl">
                    <h2 className="text-3xl font-black text-white mb-6">MARKET CLOSED</h2>

                    <div className="space-y-4 mb-8">
                        <div className="flex justify-between items-center text-slate-400 text-sm">
                            <span>Final P&L</span>
                            <span className={`font-mono text-xl font-bold ${ui.totalPnL >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                                {ui.totalPnL >= 0 ? '+' : ''}${Math.floor(ui.totalPnL).toLocaleString()}
                            </span>
                        </div>
                        <div className="flex justify-between items-center text-slate-400 text-sm">
                            <span>Ending Balance</span>
                            <span className="font-mono text-white font-bold">${Math.floor(ui.cash + ui.totalPnL).toLocaleString()}</span>
                        </div>
                    </div>

                    <button 
                        onClick={startGame}
                        className="w-full py-3 bg-white text-black font-bold rounded-xl flex items-center justify-center gap-2 hover:bg-slate-200 transition-colors"
                    >
                        <RotateCcw className="w-4 h-4" /> Next Trading Day
                    </button>
                </div>
            </div>
        )}

        {/* --- HUD --- */}
        {/* Top Bar: Time & Ticker */}
        <div className="absolute top-0 left-0 w-full p-6 flex justify-between items-start pointer-events-none">
            <div className="bg-slate-900/80 backdrop-blur border border-white/10 px-4 py-2 rounded-xl flex items-center gap-4">
                <div className="flex items-center gap-2">
                    <Clock className="w-4 h-4 text-indigo-400" />
                    <span className="font-mono font-bold text-xl text-white tracking-widest">{ui.time}</span>
                </div>
                <div className="h-6 w-px bg-white/10"></div>
                <div className="flex items-center gap-2">
                    <span className="text-slate-400 font-bold">SPY</span>
                    <span className="font-mono font-bold text-white">${ui.price.toFixed(2)}</span>
                </div>
            </div>

            {/* PnL Display */}
            <div className={`bg-slate-900/80 backdrop-blur border px-6 py-2 rounded-xl flex flex-col items-end ${ui.totalPnL >= 0 ? 'border-emerald-500/30' : 'border-rose-500/30'}`}>
                <span className="text-[10px] text-slate-500 uppercase font-bold tracking-wider">Session P&L</span>
                <span className={`font-mono text-2xl font-black ${ui.totalPnL >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                    {ui.totalPnL >= 0 ? '+' : ''}${Math.floor(ui.totalPnL).toLocaleString()}
                </span>
            </div>
        </div>

        {/* Dynamic News Ticker (Floating) */}
        {ui.lastEvent && (
            <div className="absolute top-24 left-1/2 -translate-x-1/2 animate-bounce-slight pointer-events-none">
                <div className="bg-slate-800/90 text-white px-4 py-2 rounded-lg border border-white/10 shadow-xl flex items-center gap-3">
                    <span className="relative flex h-2 w-2">
                      <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-rose-400 opacity-75"></span>
                      <span className="relative inline-flex rounded-full h-2 w-2 bg-rose-500"></span>
                    </span>
                    <span className="font-bold text-sm tracking-wide">{ui.lastEvent}</span>
                </div>
            </div>
        )}

        {/* Bottom Trading Desk */}
        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-end gap-3 pointer-events-auto">

            {/* CALL */}
            <button 
                onClick={() => handleBuy('CALL')}
                className="group w-28 h-24 bg-emerald-600/10 hover:bg-emerald-600/20 border border-emerald-500/30 hover:border-emerald-400 rounded-xl backdrop-blur-md flex flex-col items-center justify-center transition-all active:scale-95"
            >
                <TrendingUp className="w-6 h-6 text-emerald-400 mb-1 group-hover:scale-110 transition-transform" />
                <span className="text-xs font-bold text-emerald-100">BUY CALL</span>
                <span className="text-[9px] text-emerald-500/70 mt-1">Bullish</span>

                {ui.position?.type === 'CALL' && (
                    <div className="absolute -top-2 -right-2 bg-emerald-500 text-slate-900 w-6 h-6 rounded-full flex items-center justify-center font-bold text-xs shadow-lg">
                        {ui.position.contracts}
                    </div>
                )}
            </button>

            {/* CLOSE POSITION (Contextual) */}
            <div className="w-32 h-24 flex items-center justify-center">
                {ui.position ? (
                    <button 
                        onClick={closePosition}
                        className="w-full h-16 bg-slate-800 hover:bg-slate-700 border border-white/20 hover:border-white/40 rounded-xl flex flex-col items-center justify-center shadow-lg transition-all active:scale-95"
                    >
                        <span className="text-[10px] text-slate-400 font-bold uppercase mb-1">Unrealized</span>
                        <span className={`font-mono text-lg font-bold ${ui.pnl >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                            {ui.pnl >= 0 ? '+' : ''}${Math.floor(ui.pnl)}
                        </span>
                        <span className="text-[9px] text-slate-500 mt-1">CLICK TO CLOSE</span>
                    </button>
                ) : (
                    <div className="text-center opacity-30">
                        <Briefcase className="w-6 h-6 mx-auto mb-1" />
                        <span className="text-[10px] font-bold uppercase">No Position</span>
                    </div>
                )}
            </div>

            {/* PUT */}
            <button 
                onClick={() => handleBuy('PUT')}
                className="group w-28 h-24 bg-rose-600/10 hover:bg-rose-600/20 border border-rose-500/30 hover:border-rose-400 rounded-xl backdrop-blur-md flex flex-col items-center justify-center transition-all active:scale-95"
            >
                <TrendingDown className="w-6 h-6 text-rose-400 mb-1 group-hover:scale-110 transition-transform" />
                <span className="text-xs font-bold text-rose-100">BUY PUT</span>
                <span className="text-[9px] text-rose-500/70 mt-1">Bearish</span>

                {ui.position?.type === 'PUT' && (
                    <div className="absolute -top-2 -right-2 bg-rose-500 text-slate-900 w-6 h-6 rounded-full flex items-center justify-center font-bold text-xs shadow-lg">
                        {ui.position.contracts}
                    </div>
                )}
            </button>

        </div>

    </div>
  );
};

export default OptionsRunnerGame;

import React, { useRef, useEffect, useState } from 'react';
import { TrendingUp, TrendingDown, Play, RotateCcw, X, DollarSign, Clock, Newspaper, Briefcase, Activity, Wallet } from 'lucide-react';

interface Position {
  type: 'CALL' | 'PUT';
  contracts: number;
  avgEntry: number;
}

interface NewsEvent {
  time: number; // Minutes from 9:30
  headline: string;
  impact: number; // Price velocity impulse
  volatility: number; // Volatility multiplier
}

const OptionsRunnerGame: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Game Configuration
  const MARKET_OPEN_MINUTES = 0; // 9:30 AM is 0
  const MARKET_CLOSE_MINUTES = 390; // 4:00 PM is 390 (6.5 hours)
  const TIME_SPEED = 0.2; // Game speed (minutes per frame) - Slower pace for realism

  // Simulation State (Refs for loop performance)
  const state = useRef({
    isPlaying: false,
    isFinished: false,
    marketTime: 0, // Minutes elapsed since open
    price: 150.00, // Starting SPY/Stock price
    cameraY: 150.00, // Smooth camera tracking
    velocity: 0,
    volatility: 0.15,
    trendBias: 0,

    // Data Buffers
    history: [] as { x: number, y: number, time: number }[], 
    events: [] as { time: number, text: string, y: number }[],

    // Trading
    cash: 25000, // Day Trading Buying Power
    position: null as Position | null,
    realizedPnL: 0,
    unrealizedPnL: 0,

    // Camera
    cameraShake: 0
  });

  // React UI State (Synced periodically)
  const [ui, setUi] = useState({
    time: "09:30",
    price: 150.00,
    cash: 25000,
    pnl: 0,
    totalPnL: 0,
    position: null as Position | null,
    isPlaying: false,
    isFinished: false,
    lastEvent: ""
  });

  // --- Engine Logic ---

  const generateEvents = () => {
      const evts: NewsEvent[] = [];
      const numEvents = 3 + Math.floor(Math.random() * 3); // Fewer events for cleaner gameplay

      for(let i=0; i<numEvents; i++) {
          const t = Math.floor(Math.random() * (MARKET_CLOSE_MINUTES - 60)) + 30; 
          const types = [
              { h: "FED SPEAKER HAWKISH", i: -0.4, v: 2.0 },
              { h: "TECH SECTOR BREAKOUT", i: 0.5, v: 1.5 },
              { h: "JOBLESS CLAIMS MISS", i: -0.3, v: 1.8 },
              { h: "ALGO BUY PROGRAM", i: 0.4, v: 1.0 },
              { h: "INSTITUTIONAL SELLING", i: -0.4, v: 1.2 },
              { h: "OPEC PRODUCTION CUT", i: 0.3, v: 1.5 },
              { h: "CPI DATA HOT", i: -0.6, v: 2.5 }
          ];
          const type = types[Math.floor(Math.random() * types.length)];
          evts.push({ time: t, headline: type.h, impact: type.i, volatility: type.v });
      }
      return evts.sort((a,b) => a.time - b.time);
  };

  const dayEvents = useRef<NewsEvent[]>([]);

  const startGame = () => {
      state.current = {
          isPlaying: true,
          isFinished: false,
          marketTime: 0,
          price: 150.00,
          cameraY: 150.00,
          velocity: 0,
          volatility: 0.15,
          trendBias: 0,
          history: [],
          events: [],
          cash: 25000,
          position: null,
          realizedPnL: 0,
          unrealizedPnL: 0,
          cameraShake: 0
      };
      dayEvents.current = generateEvents();
      // Seed history
      for(let i=-50; i<0; i++) {
          state.current.history.push({ x: 0, y: 150, time: i });
      }
      setUi(prev => ({ ...prev, isPlaying: true, isFinished: false, cash: 25000, pnl: 0, totalPnL: 0, position: null }));
  };

  const updatePhysics = () => {
      const s = state.current;
      if (!s.isPlaying || s.isFinished) return;

      // 1. Advance Time
      s.marketTime += TIME_SPEED;

      if (s.marketTime >= MARKET_CLOSE_MINUTES) {
          s.isPlaying = false;
          s.isFinished = true;
          if (s.position) closePosition();
          setUi(prev => ({ ...prev, isPlaying: false, isFinished: true }));
          return;
      }

      // 2. Check Events
      const activeEvent = dayEvents.current.find(e => Math.abs(e.time - s.marketTime) < TIME_SPEED);
      if (activeEvent) {
          s.velocity += activeEvent.impact;
          s.volatility = 0.15 * activeEvent.volatility; 
          s.events.push({ time: s.marketTime, text: activeEvent.headline, y: s.price });
          s.cameraShake = 10;
          setUi(prev => ({ ...prev, lastEvent: activeEvent.headline }));
      }

      // 3. Price Physics (Smoother Random Walk)
      s.velocity *= 0.99; // Higher momentum conservation
      // Scaled random walk for slower frame rate to avoid jaggedness
      s.velocity += (Math.random() - 0.5) * (s.volatility * 0.4); 

      s.price += s.velocity;
      if (s.price < 10) s.price = 10;

      // 4. Camera Physics (Smooth Follow)
      // The camera lags slightly behind the price to show "movement"
      s.cameraY += (s.price - s.cameraY) * 0.05;

      // 5. Update History
      // Push every frame for smoothness
      s.history.push({ x: 0, y: s.price, time: s.marketTime });

      // 6. Update PnL
      if (s.position) {
          const diff = s.price - s.position.avgEntry;
          const dir = s.position.type === 'CALL' ? 1 : -1;
          s.unrealizedPnL = diff * dir * s.position.contracts * 100; 
      } else {
          s.unrealizedPnL = 0;
      }

      // 7. Shake Decay
      s.cameraShake *= 0.9;

      // Sync UI (throttled visually by react batching, but we update state every ~10 frames or so would be better optim, 
      // but strictly every frame is fine for this complexity)
      if (Math.floor(s.marketTime / TIME_SPEED) % 5 === 0) {
          const totalMin = 570 + s.marketTime; // 9:30 = 570 min
          const h = Math.floor(totalMin / 60);
          const m = Math.floor(totalMin % 60);
          const timeStr = `${h}:${m.toString().padStart(2, '0')}`;

          setUi(prev => ({
              ...prev,
              time: timeStr,
              price: s.price,
              pnl: s.unrealizedPnL,
              position: s.position ? {...s.position} : null,
              totalPnL: s.realizedPnL + s.unrealizedPnL
          }));
      }
  };

  // --- Drawing ---
  const project = (time: number, y: number, width: number, height: number, currentTime: number, cameraY: number) => {
      // 3D Chart View
      // Time flows into the screen (Z).
      // Current Time is Z=0.
      // Past is Z > 0.

      const z = (currentTime - time) * 15; // Stretch Z for slower feel

      // If point is too far or behind camera
      if (z < -20 || z > 1200) return null;

      const fov = 600;
      const scaleIso = fov / (400 + z);

      // Y is relative to cameraY (smooth track) instead of hard s.price
      const yRel = (y - cameraY) * 4; 

      // Add slight parallax to X based on time to give it a "curved monitor" feel
      const xOffset = Math.sin(time * 0.02) * 20; 

      const xFinal = width/2 + xOffset * scaleIso; 
      const yFinal = height/2 - (yRel * scaleIso);

      return { x: xFinal, y: yFinal, scale: scaleIso, z };
  };

  const draw = () => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      const width = canvas.width;
      const height = canvas.height;
      const s = state.current;

      // Shake
      const sx = (Math.random() - 0.5) * s.cameraShake;
      const sy = (Math.random() - 0.5) * s.cameraShake;

      // Clear
      const bg = ctx.createLinearGradient(0,0,0,height);
      bg.addColorStop(0, '#0f172a');
      bg.addColorStop(1, '#020617');
      ctx.fillStyle = bg;
      ctx.fillRect(0, 0, width, height);

      // Use s.cameraY for projection reference to smooth out the view
      const camY = s.cameraY;

      // --- Draw Grid ---
      ctx.strokeStyle = 'rgba(255,255,255,0.03)';
      ctx.lineWidth = 1;

      // Vertical lines (Time markers)
      // Draw grid relative to market time, stationary in world
      const startGrid = Math.floor((s.marketTime - 100) / 10) * 10;
      for(let t = startGrid; t < s.marketTime + 20; t+=10) {
          // Horizontal level lines at increments of $5 relative to camera
          const basePrice = Math.floor(camY / 5) * 5;
          for(let p = basePrice - 20; p <= basePrice + 20; p+=5) {
             // Just dots for grid intersections
             const point = project(t, p, width, height, s.marketTime, camY);
             if (point) {
                 ctx.beginPath();
                 ctx.fillStyle = 'rgba(255,255,255,0.1)';
                 ctx.arc(point.x + sx, point.y + sy, 1, 0, Math.PI*2);
                 ctx.fill();
             }
          }

          // Vertical Time Lines
          const pTop = project(t, camY + 20, width, height, s.marketTime, camY);
          const pBot = project(t, camY - 20, width, height, s.marketTime, camY);

          if (pTop && pBot) {
              ctx.beginPath();
              ctx.moveTo(pTop.x + sx, pTop.y + sy);
              ctx.lineTo(pBot.x + sx, pBot.y + sy);
              ctx.stroke();

              if (t % 30 === 0 && t <= s.marketTime) {
                  const labelTime = 570 + t; 
                  const h = Math.floor(labelTime/60);
                  const m = labelTime%60;
                  ctx.fillStyle = 'rgba(255,255,255,0.2)';
                  ctx.font = '10px monospace';
                  ctx.textAlign = 'right';
                  ctx.fillText(`${h}:${m===0?'00':m}`, pBot.x - 5 + sx, pBot.y + sy);
              }
          }
      }

      // --- Draw Price Line ---
      if (s.history.length > 1) {
          ctx.beginPath();
          ctx.lineWidth = 3;
          ctx.lineJoin = 'round';
          ctx.lineCap = 'round';
          // Color based on daily trend
          const isUp = s.price > s.history[0].y; // Compare to start or moving average? 
          // Let's use instant momentum for color
          ctx.shadowBlur = 10;
          ctx.shadowColor = s.velocity > 0 ? '#10b981' : '#f43f5e';
          ctx.strokeStyle = s.velocity > 0 ? '#10b981' : '#f43f5e';

          let started = false;
          // Optim: Skip every N points for performance, but at low speed we want detail
          const step = 2; 
          for (let i = s.history.length - 1; i >= 0; i-=step) {
              const point = s.history[i];
              const p = project(point.time, point.y, width, height, s.marketTime, camY);

              if (p) {
                  if (!started) {
                      ctx.moveTo(p.x + sx, p.y + sy);
                      started = true;
                  } else {
                      ctx.lineTo(p.x + sx, p.y + sy);
                  }
              }
          }
          ctx.stroke();
          ctx.shadowBlur = 0;
      }

      // --- Draw Event Markers ---
      s.events.forEach(evt => {
          const p = project(evt.time, evt.y, width, height, s.marketTime, camY);
          if (p && p.z > 0 && p.z < 800) {
              // Line
              ctx.beginPath();
              ctx.moveTo(p.x + sx, p.y + sy);
              ctx.lineTo(p.x + sx, p.y - 30 * p.scale + sy);
              ctx.strokeStyle = 'rgba(255,255,255,0.5)';
              ctx.lineWidth = 1;
              ctx.stroke();

              // Box
              const w = 100 * p.scale;
              const h = 30 * p.scale;
              const bx = p.x - w/2 + sx;
              const by = p.y - 30 * p.scale - h + sy;

              ctx.fillStyle = 'rgba(30, 41, 59, 0.9)';
              ctx.fillRect(bx, by, w, h);
              ctx.strokeStyle = '#fff';
              ctx.lineWidth = 1;
              ctx.strokeRect(bx, by, w, h);

              ctx.fillStyle = '#fff';
              ctx.textAlign = 'center';
              ctx.font = `${9 * p.scale}px sans-serif`;
              ctx.fillText("NEWS", p.x + sx, by + 12 * p.scale);
          }
      });

      // --- Draw Head (Current Price) ---
      const head = project(s.marketTime, s.price, width, height, s.marketTime, camY);
      if (head) {
          // Glow
          const grad = ctx.createRadialGradient(head.x + sx, head.y + sy, 2, head.x + sx, head.y + sy, 15);
          grad.addColorStop(0, '#fff');
          grad.addColorStop(0.5, 'rgba(99, 102, 241, 0.5)');
          grad.addColorStop(1, 'transparent');

          ctx.fillStyle = grad;
          ctx.beginPath();
          ctx.arc(head.x + sx, head.y + sy, 15, 0, Math.PI * 2);
          ctx.fill();

          ctx.fillStyle = '#fff';
          ctx.beginPath();
          ctx.arc(head.x + sx, head.y + sy, 4, 0, Math.PI * 2);
          ctx.fill();
      }

      // --- Draw Position Entry Level ---
      if (s.position) {
          // Calculate Y relative to CameraY
          const entryYRel = (s.position.avgEntry - camY) * 4 * (head?.scale || 1);
          const screenY = (height/2) - entryYRel + sy;

          ctx.beginPath();
          ctx.strokeStyle = s.position.type === 'CALL' ? '#10b981' : '#f43f5e';
          ctx.lineWidth = 1;
          ctx.setLineDash([4, 4]);
          ctx.moveTo(0, screenY);
          ctx.lineTo(width, screenY);
          ctx.stroke();
          ctx.setLineDash([]);

          ctx.fillStyle = s.position.type === 'CALL' ? '#10b981' : '#f43f5e';
          ctx.font = 'bold 10px monospace';
          ctx.textAlign = 'right';
          ctx.fillText(`AVG ENTRY $${s.position.avgEntry.toFixed(2)}`, width - 20, screenY - 4);
      }
  };

  // --- Actions ---
  const handleBuy = (type: 'CALL' | 'PUT') => {
      const s = state.current;
      const premium = 2.50; 
      const cost = premium * 100;

      if (s.cash >= cost) {
          s.cash -= cost;
          if (s.position && s.position.type === type) {
              const totalUnderlying = (s.position.avgEntry * s.position.contracts) + s.price;
              s.position.contracts += 1;
              s.position.avgEntry = totalUnderlying / s.position.contracts;
          } else {
              if (s.position) closePosition(); 
              s.position = { type, contracts: 1, avgEntry: s.price };
          }
      }
  };

  const closePosition = () => {
      const s = state.current;
      if (s.position) {
          s.realizedPnL += s.unrealizedPnL;
          s.cash += (250 * s.position.contracts) + s.unrealizedPnL; 
          s.position = null;
          s.unrealizedPnL = 0;
      }
  };

  // Loop
  useEffect(() => {
      let frameId: number;
      const loop = () => {
          updatePhysics();
          draw();
          frameId = requestAnimationFrame(loop);
      };
      frameId = requestAnimationFrame(loop);
      return () => cancelAnimationFrame(frameId);
  }, []);

  // Resize
  useEffect(() => {
      if (canvasRef.current && containerRef.current) {
          canvasRef.current.width = containerRef.current.clientWidth;
          canvasRef.current.height = containerRef.current.clientHeight;
      }
  }, []);

  return (
    <div ref={containerRef} className="relative w-full h-[600px] bg-slate-950 rounded-3xl overflow-hidden border border-white/10 shadow-2xl group select-none">
        <canvas ref={canvasRef} className="w-full h-full block" />

        {/* --- START SCREEN --- */}
        {!ui.isPlaying && !ui.isFinished && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/80 backdrop-blur-md z-50">
                <div className="text-center space-y-6 max-w-lg">
                    <h1 className="text-5xl font-black text-white tracking-tighter mb-2">DAY TRADER SIM</h1>
                    <div className="grid grid-cols-2 gap-4 text-left bg-slate-900/50 p-6 rounded-2xl border border-white/10">
                        <div className="space-y-2">
                            <div className="flex items-center gap-2 text-slate-400 text-sm font-bold uppercase"><Clock className="w-4 h-4"/> Time</div>
                            <div className="text-white font-mono">09:30 - 16:00</div>
                        </div>
                        <div className="space-y-2">
                            <div className="flex items-center gap-2 text-slate-400 text-sm font-bold uppercase"><Wallet className="w-4 h-4"/> Capital</div>
                            <div className="text-white font-mono">$25,000</div>
                        </div>
                        <div className="col-span-2 text-xs text-slate-500 mt-2 border-t border-white/5 pt-2">
                            React to news. Buy low, sell high. Manage your risk.
                        </div>
                    </div>
                    <button 
                        onClick={startGame}
                        className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-xl text-lg tracking-widest shadow-[0_0_30px_rgba(79,70,229,0.4)] transition-all hover:scale-[1.02]"
                    >
                        OPEN MARKET
                    </button>
                </div>
            </div>
        )}

        {/* --- GAME OVER SCREEN --- */}
        {ui.isFinished && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/90 backdrop-blur-md z-50">
                <div className="bg-slate-900 border border-white/10 p-8 rounded-3xl text-center max-w-md w-full shadow-2xl">
                    <h2 className="text-3xl font-black text-white mb-6">MARKET CLOSED</h2>

                    <div className="space-y-4 mb-8">
                        <div className="flex justify-between items-center text-slate-400 text-sm">
                            <span>Final P&L</span>
                            <span className={`font-mono text-xl font-bold ${ui.totalPnL >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                                {ui.totalPnL >= 0 ? '+' : ''}${Math.floor(ui.totalPnL).toLocaleString()}
                            </span>
                        </div>
                        <div className="flex justify-between items-center text-slate-400 text-sm">
                            <span>Ending Balance</span>
                            <span className="font-mono text-white font-bold">${Math.floor(ui.cash + ui.totalPnL).toLocaleString()}</span>
                        </div>
                    </div>

                    <button 
                        onClick={startGame}
                        className="w-full py-3 bg-white text-black font-bold rounded-xl flex items-center justify-center gap-2 hover:bg-slate-200 transition-colors"
                    >
                        <RotateCcw className="w-4 h-4" /> Next Trading Day
                    </button>
                </div>
            </div>
        )}

        {/* --- HUD --- */}
        {/* Top Bar: Time & Ticker */}
        <div className="absolute top-0 left-0 w-full p-6 flex justify-between items-start pointer-events-none">
            <div className="bg-slate-900/80 backdrop-blur border border-white/10 px-4 py-2 rounded-xl flex items-center gap-4">
                <div className="flex items-center gap-2">
                    <Clock className="w-4 h-4 text-indigo-400" />
                    <span className="font-mono font-bold text-xl text-white tracking-widest">{ui.time}</span>
                </div>
                <div className="h-6 w-px bg-white/10"></div>
                <div className="flex items-center gap-2">
                    <span className="text-slate-400 font-bold">SPY</span>
                    <span className="font-mono font-bold text-white">${ui.price.toFixed(2)}</span>
                </div>
            </div>

            {/* PnL Display */}
            <div className={`bg-slate-900/80 backdrop-blur border px-6 py-2 rounded-xl flex flex-col items-end ${ui.totalPnL >= 0 ? 'border-emerald-500/30' : 'border-rose-500/30'}`}>
                <span className="text-[10px] text-slate-500 uppercase font-bold tracking-wider">Session P&L</span>
                <span className={`font-mono text-2xl font-black ${ui.totalPnL >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                    {ui.totalPnL >= 0 ? '+' : ''}${Math.floor(ui.totalPnL).toLocaleString()}
                </span>
            </div>
        </div>

        {/* Dynamic News Ticker (Floating) */}
        {ui.lastEvent && (
            <div className="absolute top-24 left-1/2 -translate-x-1/2 animate-bounce-slight pointer-events-none">
                <div className="bg-slate-800/90 text-white px-4 py-2 rounded-lg border border-white/10 shadow-xl flex items-center gap-3">
                    <span className="relative flex h-2 w-2">
                      <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-rose-400 opacity-75"></span>
                      <span className="relative inline-flex rounded-full h-2 w-2 bg-rose-500"></span>
                    </span>
                    <span className="font-bold text-sm tracking-wide">{ui.lastEvent}</span>
                </div>
            </div>
        )}

        {/* Bottom Trading Desk */}
        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-end gap-3 pointer-events-auto">

            {/* CALL */}
            <button 
                onClick={() => handleBuy('CALL')}
                className="group w-28 h-24 bg-emerald-600/10 hover:bg-emerald-600/20 border border-emerald-500/30 hover:border-emerald-400 rounded-xl backdrop-blur-md flex flex-col items-center justify-center transition-all active:scale-95"
            >
                <TrendingUp className="w-6 h-6 text-emerald-400 mb-1 group-hover:scale-110 transition-transform" />
                <span className="text-xs font-bold text-emerald-100">BUY CALL</span>
                <span className="text-[9px] text-emerald-500/70 mt-1">Bullish</span>

                {ui.position?.type === 'CALL' && (
                    <div className="absolute -top-2 -right-2 bg-emerald-500 text-slate-900 w-6 h-6 rounded-full flex items-center justify-center font-bold text-xs shadow-lg">
                        {ui.position.contracts}
                    </div>
                )}
            </button>

            {/* CLOSE POSITION (Contextual) */}
            <div className="w-32 h-24 flex items-center justify-center">
                {ui.position ? (
                    <button 
                        onClick={closePosition}
                        className="w-full h-16 bg-slate-800 hover:bg-slate-700 border border-white/20 hover:border-white/40 rounded-xl flex flex-col items-center justify-center shadow-lg transition-all active:scale-95"
                    >
                        <span className="text-[10px] text-slate-400 font-bold uppercase mb-1">Unrealized</span>
                        <span className={`font-mono text-lg font-bold ${ui.pnl >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                            {ui.pnl >= 0 ? '+' : ''}${Math.floor(ui.pnl)}
                        </span>
                        <span className="text-[9px] text-slate-500 mt-1">CLICK TO CLOSE</span>
                    </button>
                ) : (
                    <div className="text-center opacity-30">
                        <Briefcase className="w-6 h-6 mx-auto mb-1" />
                        <span className="text-[10px] font-bold uppercase">No Position</span>
                    </div>
                )}
            </div>

            {/* PUT */}
            <button 
                onClick={() => handleBuy('PUT')}
                className="group w-28 h-24 bg-rose-600/10 hover:bg-rose-600/20 border border-rose-500/30 hover:border-rose-400 rounded-xl backdrop-blur-md flex flex-col items-center justify-center transition-all active:scale-95"
            >
                <TrendingDown className="w-6 h-6 text-rose-400 mb-1 group-hover:scale-110 transition-transform" />
                <span className="text-xs font-bold text-rose-100">BUY PUT</span>
                <span className="text-[9px] text-rose-500/70 mt-1">Bearish</span>

                {ui.position?.type === 'PUT' && (
                    <div className="absolute -top-2 -right-2 bg-rose-500 text-slate-900 w-6 h-6 rounded-full flex items-center justify-center font-bold text-xs shadow-lg">
                        {ui.position.contracts}
                    </div>
                )}
            </button>

        </div>

    </div>
  );
};

export default OptionsRunnerGame;

import React, { useRef, useEffect, useState } from 'react';
import { TrendingUp, TrendingDown, Play, RotateCcw, X, DollarSign, Clock, Briefcase, Activity, Wallet, Pause, FastForward, Rewind, Layers } from 'lucide-react';

interface Position {
  type: 'CALL' | 'PUT';
  contracts: number;
  avgEntry: number;
}

interface Candle {
    open: number;
    high: number;
    low: number;
    close: number;
    time: number;
    volume: number;
    isClosed: boolean;
}

interface NewsEvent {
  time: number; // Minutes from 9:30
  headline: string;
  impact: number; // Price velocity impulse
  volatility: number; // Volatility multiplier
}

const OptionsRunnerGame: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Game Configuration
  const MARKET_CLOSE_MINUTES = 390; // 6.5 hours
  const CANDLE_PERIOD = 5; // 5 minute candles

  // Simulation State (Refs for loop performance)
  const state = useRef({
    isPlaying: false,
    isFinished: false,
    marketTime: 0, 
    price: 150.00,
    velocity: 0,
    volatility: 0.10,

    // Candle System
    currentCandle: { open: 150, high: 150, low: 150, close: 150, time: 0, volume: 0, isClosed: false } as Candle,
    history: [] as Candle[],

    // Events
    events: [] as { time: number, text: string, priceAtEvent: number }[],
    dayEvents: [] as NewsEvent[],

    // Trading
    cash: 25000,
    position: null as Position | null,
    realizedPnL: 0,
    unrealizedPnL: 0,

    // Visuals
    cameraZ: 0, // Camera moves along time
    cameraShake: 0,
    speedMultiplier: 1.0
  });

  // React UI State
  const [ui, setUi] = useState({
    time: "09:30",
    price: 150.00,
    cash: 25000,
    pnl: 0,
    totalPnL: 0,
    position: null as Position | null,
    isPlaying: false,
    isFinished: false,
    lastEvent: "",
    speed: 1.0
  });

  // --- Engine Logic ---

  const generateEvents = () => {
      const evts: NewsEvent[] = [];
      const numEvents = 2 + Math.floor(Math.random() * 3);

      for(let i=0; i<numEvents; i++) {
          const t = Math.floor(Math.random() * (MARKET_CLOSE_MINUTES - 60)) + 30; 
          const types = [
              { h: "FED: RATES UNCHANGED", i: 0.3, v: 0.8 },
              { h: "INFLATION DATA HOT", i: -0.8, v: 2.5 },
              { h: "SECTOR ROTATION", i: -0.3, v: 1.5 },
              { h: "INSTITUTIONAL BUYING", i: 0.5, v: 1.2 },
              { h: "GEOPOLITICAL TENSION", i: -0.6, v: 2.0 },
              { h: "EARNINGS BEAT", i: 0.9, v: 1.5 }
          ];
          const type = types[Math.floor(Math.random() * types.length)];
          evts.push({ time: t, headline: type.h, impact: type.i, volatility: type.v });
      }
      return evts.sort((a,b) => a.time - b.time);
  };

  const startGame = () => {
      state.current = {
          isPlaying: true,
          isFinished: false,
          marketTime: 0,
          price: 150.00,
          velocity: 0,
          volatility: 0.10,
          currentCandle: { open: 150, high: 150, low: 150, close: 150, time: 0, volume: 0, isClosed: false },
          history: [],
          events: [],
          dayEvents: generateEvents(),
          cash: 25000,
          position: null,
          realizedPnL: 0,
          unrealizedPnL: 0,
          cameraZ: 0,
          cameraShake: 0,
          speedMultiplier: ui.speed
      };

      // Pre-seed some history for context
      let prePrice = 148.00;
      for(let i=-20; i<0; i++) {
          const open = prePrice;
          const close = open + (Math.random()-0.5);
          state.current.history.push({
              open, 
              close, 
              high: Math.max(open, close) + Math.random()*0.2, 
              low: Math.min(open, close) - Math.random()*0.2, 
              time: i * CANDLE_PERIOD,
              volume: Math.random() * 100,
              isClosed: true
          });
          prePrice = close;
      }
      state.current.price = prePrice;
      state.current.currentCandle.open = prePrice;
      state.current.currentCandle.high = prePrice;
      state.current.currentCandle.low = prePrice;
      state.current.currentCandle.close = prePrice;

      setUi(prev => ({ ...prev, isPlaying: true, isFinished: false, cash: 25000, pnl: 0, totalPnL: 0, position: null }));
  };

  const updatePhysics = () => {
      const s = state.current;
      if (!s.isPlaying || s.isFinished) return;

      // Time Step based on Speed Control
      const dt = 0.05 * s.speedMultiplier;
      s.marketTime += dt;

      // Check End of Day
      if (s.marketTime >= MARKET_CLOSE_MINUTES) {
          s.isPlaying = false;
          s.isFinished = true;
          if (s.position) closePosition();
          setUi(prev => ({ ...prev, isPlaying: false, isFinished: true }));
          return;
      }

      // Check Events
      const activeEvent = s.dayEvents.find(e => Math.abs(e.time - s.marketTime) < dt);
      if (activeEvent) {
          s.velocity += activeEvent.impact;
          s.volatility = Math.max(0.1, s.volatility * activeEvent.volatility); 
          s.events.push({ time: s.marketTime, text: activeEvent.headline, priceAtEvent: s.price });
          s.cameraShake = 15;
          setUi(prev => ({ ...prev, lastEvent: activeEvent.headline }));
      }

      // Price Physics (Geometric Brownian Motion approx)
      s.velocity *= 0.95; // Drag
      const noise = (Math.random() - 0.5) * s.volatility * (Math.sqrt(s.speedMultiplier)); 
      s.velocity += noise;
      s.price += s.velocity;

      // Candle Logic
      const c = s.currentCandle;
      c.close = s.price;
      c.high = Math.max(c.high, s.price);
      c.low = Math.min(c.low, s.price);
      c.volume += Math.abs(s.velocity) * 10;
      c.time = s.marketTime;

      // Close Candle
      if (Math.floor(s.marketTime / CANDLE_PERIOD) > Math.floor((s.marketTime - dt) / CANDLE_PERIOD)) {
          c.isClosed = true;
          s.history.push({ ...c });
          // Reset new candle
          s.currentCandle = {
              open: s.price,
              high: s.price,
              low: s.price,
              close: s.price,
              time: s.marketTime,
              volume: 0,
              isClosed: false
          };
      }

      // Update PnL
      if (s.position) {
          const diff = s.price - s.position.avgEntry;
          const dir = s.position.type === 'CALL' ? 1 : -1;
          s.unrealizedPnL = diff * dir * s.position.contracts * 100; 
      } else {
          s.unrealizedPnL = 0;
      }

      // Shake Decay
      s.cameraShake *= 0.9;

      // Sync UI periodically
      if (Math.random() > 0.8) {
          const totalMin = 570 + s.marketTime;
          const h = Math.floor(totalMin / 60);
          const m = Math.floor(totalMin % 60);
          const timeStr = `${h}:${m.toString().padStart(2, '0')}`;

          setUi(prev => ({
              ...prev,
              time: timeStr,
              price: s.price,
              pnl: s.unrealizedPnL,
              position: s.position ? {...s.position} : null,
              totalPnL: s.realizedPnL + s.unrealizedPnL
          }));
      }
  };

  // --- 3D Render Engine ---

  const project = (x: number, y: number, z: number, width: number, height: number, camZ: number, priceCenter: number) => {
      // World: X = Time, Y = Price, Z = Depth
      // Camera moves along X (Time)

      // Relative Coords
      const relX = (x - camZ) * 20; // Time spacing
      const relY = (y - priceCenter) * 8; // Price scaling
      const relZ = z; // Depth

      // Isometric-ish Projection
      const fov = 800;
      const camDist = 600;

      // We want to look from the side/top
      // Rotate world
      const angle = 0.2; // Slight tilt

      const rotY = relY; // Y stays Y roughly
      const rotZ = relZ * Math.cos(angle) + relX * Math.sin(angle); // Depth comes from X (Time) mostly
      const rotX = relX * Math.cos(angle) - relZ * Math.sin(angle); // Left/Right comes from X/Z mix

      // Only draw what's in front of camera plane
      const depth = camDist + rotZ;
      if (depth < 50) return null;

      const scale = fov / depth;

      return {
          x: width/2 + rotX * scale,
          y: height/2 - rotY * scale,
          scale,
          depth
      };
  };

  const draw = () => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      const width = canvas.width;
      const height = canvas.height;
      const s = state.current;

      // Calculate camera focus (smooth follow)
      const targetCamZ = s.marketTime / CANDLE_PERIOD;
      s.cameraZ += (targetCamZ - s.cameraZ) * 0.1;

      // Clear
      ctx.fillStyle = '#020617';
      ctx.fillRect(0, 0, width, height);

      // --- Draw Grid ---
      ctx.strokeStyle = 'rgba(255,255,255,0.05)';
      ctx.lineWidth = 1;

      // Horizontal Price Levels
      const basePrice = Math.floor(s.price / 5) * 5;
      for (let p = basePrice - 20; p <= basePrice + 20; p += 5) {
          const p1 = project(s.cameraZ - 10, p, -20, width, height, s.cameraZ, s.price);
          const p2 = project(s.cameraZ + 5, p, -20, width, height, s.cameraZ, s.price);
          const p3 = project(s.cameraZ + 5, p, 20, width, height, s.cameraZ, s.price);
          const p4 = project(s.cameraZ - 10, p, 20, width, height, s.cameraZ, s.price);

          if (p1 && p2 && p3 && p4) {
              ctx.beginPath();
              ctx.moveTo(p1.x, p1.y); ctx.lineTo(p2.x, p2.y); ctx.lineTo(p3.x, p3.y); ctx.lineTo(p4.x, p4.y); ctx.closePath();
              ctx.stroke();

              // Label
              ctx.fillStyle = 'rgba(255,255,255,0.2)';
              ctx.font = '10px monospace';
              ctx.fillText(`$${p}`, p2.x + 5, p2.y);
          }
      }

      // --- Draw Candles ---
      const allCandles = [...s.history, s.currentCandle];

      // Filter visible
      const visibleCandles = allCandles.filter(c => {
          const cIdx = c.time / CANDLE_PERIOD;
          return cIdx > s.cameraZ - 15 && cIdx < s.cameraZ + 5;
      });

      visibleCandles.forEach(c => {
          const cIdx = c.time / CANDLE_PERIOD;
          const isGreen = c.close >= c.open;
          const color = isGreen ? '#10b981' : '#f43f5e';
          const colorDark = isGreen ? '#064e3b' : '#881337';

          // Body Points (3D Box)
          const w = 0.3; // Width of candle in time units
          const d = 5; // Depth in Z units

          const top = Math.max(c.open, c.close);
          const bottom = Math.min(c.open, c.close);
          const wickTop = c.high;
          const wickBottom = c.low;

          // Wick
          const wt = project(cIdx, wickTop, 0, width, height, s.cameraZ, s.price);
          const wb = project(cIdx, wickBottom, 0, width, height, s.cameraZ, s.price);

          if (wt && wb) {
              ctx.beginPath();
              ctx.moveTo(wt.x, wt.y); ctx.lineTo(wb.x, wb.y);
              ctx.strokeStyle = color;
              ctx.lineWidth = 2 * wt.scale;
              ctx.stroke();
          }

          // Body Box vertices
          // Front Face
          const f1 = project(cIdx - w, top, d, width, height, s.cameraZ, s.price);
          const f2 = project(cIdx + w, top, d, width, height, s.cameraZ, s.price);
          const f3 = project(cIdx + w, bottom, d, width, height, s.cameraZ, s.price);
          const f4 = project(cIdx - w, bottom, d, width, height, s.cameraZ, s.price);

          // Back Face (Simple shading, just draw front + side)
          const s1 = project(cIdx + w, top, -d, width, height, s.cameraZ, s.price);
          const s2 = project(cIdx + w, bottom, -d, width, height, s.cameraZ, s.price);

          if (f1 && f2 && f3 && f4) {
              // Front
              ctx.beginPath();
              ctx.moveTo(f1.x, f1.y); ctx.lineTo(f2.x, f2.y); ctx.lineTo(f3.x, f3.y); ctx.lineTo(f4.x, f4.y); ctx.closePath();
              ctx.fillStyle = color;
              ctx.fill();

              if (s1 && s2) {
                  // Side (Thickness)
                  ctx.beginPath();
                  ctx.moveTo(f2.x, f2.y); ctx.lineTo(s1.x, s1.y); ctx.lineTo(s2.x, s2.y); ctx.lineTo(f3.x, f3.y); ctx.closePath();
                  ctx.fillStyle = colorDark;
                  ctx.fill();

                  // Top/Bottom caps
                  ctx.beginPath();
                  ctx.moveTo(f1.x, f1.y); ctx.lineTo(f2.x, f2.y); ctx.lineTo(s1.x, s1.y); 
                  const backTopLeft = project(cIdx - w, top, -d, width, height, s.cameraZ, s.price);
                  if (backTopLeft) ctx.lineTo(backTopLeft.x, backTopLeft.y);
                  ctx.closePath();
                  ctx.fillStyle = isGreen ? '#34d399' : '#fb7185'; // Lighter cap
                  ctx.fill();
              }
          }

          // Event Markers
          const evt = s.events.find(e => Math.abs(e.time - c.time) < CANDLE_PERIOD/2);
          if (evt) {
              const ep = project(cIdx, evt.priceAtEvent + 5, 0, width, height, s.cameraZ, s.price);
              if (ep) {
                  ctx.fillStyle = '#fff';
                  ctx.font = 'bold 10px sans-serif';
                  ctx.textAlign = 'center';
                  ctx.fillText(evt.text, ep.x, ep.y - 10);

                  ctx.beginPath();
                  ctx.moveTo(ep.x, ep.y);
                  const anchor = project(cIdx, evt.priceAtEvent, 0, width, height, s.cameraZ, s.price);
                  if (anchor) ctx.lineTo(anchor.x, anchor.y);
                  ctx.strokeStyle = 'rgba(255,255,255,0.5)';
                  ctx.lineWidth = 1;
                  ctx.stroke();
              }
          }
      });

      // --- Draw "Laser Level" (Current Price Line) ---
      // Replaces the "Dot"
      const laserY = s.price;
      const startX = s.cameraZ - 5;
      const endX = s.cameraZ + 5;

      const l1 = project(startX, laserY, 0, width, height, s.cameraZ, s.price);
      const l2 = project(endX, laserY, 0, width, height, s.cameraZ, s.price);

      if (l1 && l2) {
          ctx.beginPath();
          ctx.moveTo(l1.x, l1.y);
          ctx.lineTo(l2.x, l2.y);
          ctx.strokeStyle = s.currentCandle.close >= s.currentCandle.open ? '#10b981' : '#f43f5e';
          ctx.lineWidth = 2;
          ctx.setLineDash([5, 5]);
          ctx.stroke();
          ctx.setLineDash([]);

          // Glowing Pulse at tip (Current Candle Center)
          const tip = project(s.marketTime / CANDLE_PERIOD, laserY, 0, width, height, s.cameraZ, s.price);
          if (tip) {
              const pulse = Math.sin(Date.now() / 100) * 5;
              ctx.beginPath();
              ctx.arc(tip.x, tip.y, 4, 0, Math.PI*2);
              ctx.fillStyle = '#fff';
              ctx.fill();

              ctx.beginPath();
              ctx.arc(tip.x, tip.y, 10 + pulse, 0, Math.PI*2);
              ctx.strokeStyle = 'rgba(255,255,255,0.5)';
              ctx.stroke();
          }
      }

      // --- Draw Position Lines ---
      if (s.position) {
          const entryY = s.position.avgEntry;
          const color = s.position.type === 'CALL' ? '#10b981' : '#f43f5e';

          const e1 = project(startX, entryY, 0, width, height, s.cameraZ, s.price);
          const e2 = project(endX, entryY, 0, width, height, s.cameraZ, s.price);

          if (e1 && e2) {
              ctx.beginPath();
              ctx.moveTo(e1.x, e1.y);
              ctx.lineTo(e2.x, e2.y);
              ctx.strokeStyle = color;
              ctx.lineWidth = 1;
              ctx.stroke();

              ctx.fillStyle = color;
              ctx.font = 'bold 12px monospace';
              ctx.textAlign = 'right';
              ctx.fillText(`${s.position.type} ENTRY`, e2.x - 10, e2.y - 5);
          }
      }
  };

  // --- Actions ---
  const handleBuy = (type: 'CALL' | 'PUT') => {
      const s = state.current;
      const premium = 2.50; 
      const cost = premium * 100;

      if (s.cash >= cost) {
          s.cash -= cost;
          if (s.position && s.position.type === type) {
              const totalUnderlying = (s.position.avgEntry * s.position.contracts) + s.price;
              s.position.contracts += 1;
              s.position.avgEntry = totalUnderlying / s.position.contracts;
          } else {
              if (s.position) closePosition(); 
              s.position = { type, contracts: 1, avgEntry: s.price };
          }
      }
  };

  const closePosition = () => {
      const s = state.current;
      if (s.position) {
          s.realizedPnL += s.unrealizedPnL;
          s.cash += (250 * s.position.contracts) + s.unrealizedPnL; 
          s.position = null;
          s.unrealizedPnL = 0;
      }
  };

  const adjustSpeed = (val: number) => {
      state.current.speedMultiplier = val;
      setUi(prev => ({ ...prev, speed: val }));
  };

  // Loop
  useEffect(() => {
      let frameId: number;
      const loop = () => {
          updatePhysics();
          draw();
          frameId = requestAnimationFrame(loop);
      };
      frameId = requestAnimationFrame(loop);
      return () => cancelAnimationFrame(frameId);
  }, []);

  // Resize
  useEffect(() => {
      if (canvasRef.current && containerRef.current) {
          canvasRef.current.width = containerRef.current.clientWidth;
          canvasRef.current.height = containerRef.current.clientHeight;
      }
  }, []);

  return (
    <div ref={containerRef} className="relative w-full h-[600px] bg-slate-950 rounded-3xl overflow-hidden border border-white/10 shadow-2xl group select-none">
        <canvas ref={canvasRef} className="w-full h-full block" />

        {/* --- START SCREEN --- */}
        {!ui.isPlaying && !ui.isFinished && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/80 backdrop-blur-md z-50">
                <div className="text-center space-y-6 max-w-lg">
                    <h1 className="text-5xl font-black text-white tracking-tighter mb-2">PRO TRADER SIM</h1>
                    <div className="grid grid-cols-2 gap-4 text-left bg-slate-900/50 p-6 rounded-2xl border border-white/10">
                        <div className="space-y-2">
                            <div className="flex items-center gap-2 text-slate-400 text-sm font-bold uppercase"><Clock className="w-4 h-4"/> Time</div>
                            <div className="text-white font-mono">09:30 - 16:00</div>
                        </div>
                        <div className="space-y-2">
                            <div className="flex items-center gap-2 text-slate-400 text-sm font-bold uppercase"><Wallet className="w-4 h-4"/> Capital</div>
                            <div className="text-white font-mono">$25,000</div>
                        </div>
                    </div>
                    <button 
                        onClick={startGame}
                        className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-xl text-lg tracking-widest shadow-[0_0_30px_rgba(79,70,229,0.4)] transition-all hover:scale-[1.02]"
                    >
                        INITIATE SESSION
                    </button>
                </div>
            </div>
        )}

        {/* --- GAME OVER --- */}
        {ui.isFinished && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/90 backdrop-blur-md z-50">
                <div className="bg-slate-900 border border-white/10 p-8 rounded-3xl text-center max-w-md w-full shadow-2xl">
                    <h2 className="text-3xl font-black text-white mb-6">MARKET CLOSED</h2>
                    <div className="space-y-4 mb-8">
                        <div className="flex justify-between items-center text-slate-400 text-sm">
                            <span>Final P&L</span>
                            <span className={`font-mono text-xl font-bold ${ui.totalPnL >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                                {ui.totalPnL >= 0 ? '+' : ''}${Math.floor(ui.totalPnL).toLocaleString()}
                            </span>
                        </div>
                        <div className="flex justify-between items-center text-slate-400 text-sm">
                            <span>Ending Balance</span>
                            <span className="font-mono text-white font-bold">${Math.floor(ui.cash + ui.totalPnL).toLocaleString()}</span>
                        </div>
                    </div>
                    <button onClick={startGame} className="w-full py-3 bg-white text-black font-bold rounded-xl flex items-center justify-center gap-2 hover:bg-slate-200 transition-colors">
                        <RotateCcw className="w-4 h-4" /> Next Trading Day
                    </button>
                </div>
            </div>
        )}

        {/* --- HUD --- */}
        <div className="absolute top-0 left-0 w-full p-6 flex justify-between items-start pointer-events-none">
            <div className="bg-slate-900/80 backdrop-blur border border-white/10 px-4 py-2 rounded-xl flex items-center gap-4">
                <div className="flex items-center gap-2">
                    <Clock className="w-4 h-4 text-indigo-400" />
                    <span className="font-mono font-bold text-xl text-white tracking-widest">{ui.time}</span>
                </div>
                <div className="h-6 w-px bg-white/10"></div>
                <div className="flex items-center gap-2">
                    <span className="text-slate-400 font-bold">SPY</span>
                    <span className="font-mono font-bold text-white">${ui.price.toFixed(2)}</span>
                </div>
            </div>

            {/* Speed Control (Pointer Events Auto) */}
            <div className="pointer-events-auto bg-slate-900/80 backdrop-blur border border-white/10 px-2 py-1 rounded-xl flex items-center gap-1">
                <button onClick={() => adjustSpeed(0)} className={`p-2 rounded hover:bg-white/10 ${ui.speed === 0 ? 'text-rose-400' : 'text-slate-400'}`}><Pause className="w-4 h-4"/></button>
                <button onClick={() => adjustSpeed(0.5)} className={`p-2 rounded hover:bg-white/10 ${ui.speed === 0.5 ? 'text-indigo-400' : 'text-slate-400'}`}><Play className="w-4 h-4"/></button>
                <button onClick={() => adjustSpeed(2.0)} className={`p-2 rounded hover:bg-white/10 ${ui.speed === 2.0 ? 'text-emerald-400' : 'text-slate-400'}`}><FastForward className="w-4 h-4"/></button>
                <div className="text-[10px] font-mono text-slate-500 w-8 text-center">{ui.speed}x</div>
            </div>

            <div className={`bg-slate-900/80 backdrop-blur border px-6 py-2 rounded-xl flex flex-col items-end ${ui.totalPnL >= 0 ? 'border-emerald-500/30' : 'border-rose-500/30'}`}>
                <span className="text-[10px] text-slate-500 uppercase font-bold tracking-wider">Session P&L</span>
                <span className={`font-mono text-2xl font-black ${ui.totalPnL >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                    {ui.totalPnL >= 0 ? '+' : ''}${Math.floor(ui.totalPnL).toLocaleString()}
                </span>
            </div>
        </div>

        {/* News Ticker */}
        {ui.lastEvent && (
            <div className="absolute top-24 left-1/2 -translate-x-1/2 animate-bounce-slight pointer-events-none">
                <div className="bg-slate-800/90 text-white px-4 py-2 rounded-lg border border-white/10 shadow-xl flex items-center gap-3">
                    <Activity className="w-4 h-4 text-indigo-400 animate-pulse" />
                    <span className="font-bold text-sm tracking-wide">{ui.lastEvent}</span>
                </div>
            </div>
        )}

        {/* Trading Desk */}
        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-end gap-3 pointer-events-auto">
            <button 
                onClick={() => handleBuy('CALL')}
                className="group w-28 h-24 bg-emerald-600/10 hover:bg-emerald-600/20 border border-emerald-500/30 hover:border-emerald-400 rounded-xl backdrop-blur-md flex flex-col items-center justify-center transition-all active:scale-95"
            >
                <TrendingUp className="w-6 h-6 text-emerald-400 mb-1 group-hover:scale-110 transition-transform" />
                <span className="text-xs font-bold text-emerald-100">BUY CALL</span>
                <span className="text-[9px] text-emerald-500/70 mt-1">Bullish</span>
                {ui.position?.type === 'CALL' && (
                    <div className="absolute -top-2 -right-2 bg-emerald-500 text-slate-900 w-6 h-6 rounded-full flex items-center justify-center font-bold text-xs shadow-lg">
                        {ui.position.contracts}
                    </div>
                )}
            </button>

            <div className="w-32 h-24 flex items-center justify-center">
                {ui.position ? (
                    <button 
                        onClick={closePosition}
                        className="w-full h-16 bg-slate-800 hover:bg-slate-700 border border-white/20 hover:border-white/40 rounded-xl flex flex-col items-center justify-center shadow-lg transition-all active:scale-95"
                    >
                        <span className="text-[10px] text-slate-400 font-bold uppercase mb-1">Unrealized</span>
                        <span className={`font-mono text-lg font-bold ${ui.pnl >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                            {ui.pnl >= 0 ? '+' : ''}${Math.floor(ui.pnl)}
                        </span>
                        <span className="text-[9px] text-slate-500 mt-1">CLICK TO CLOSE</span>
                    </button>
                ) : (
                    <div className="text-center opacity-30">
                        <Briefcase className="w-6 h-6 mx-auto mb-1" />
                        <span className="text-[10px] font-bold uppercase">No Position</span>
                    </div>
                )}
            </div>

            <button 
                onClick={() => handleBuy('PUT')}
                className="group w-28 h-24 bg-rose-600/10 hover:bg-rose-600/20 border border-rose-500/30 hover:border-rose-400 rounded-xl backdrop-blur-md flex flex-col items-center justify-center transition-all active:scale-95"
            >
                <TrendingDown className="w-6 h-6 text-rose-400 mb-1 group-hover:scale-110 transition-transform" />
                <span className="text-xs font-bold text-rose-100">BUY PUT</span>
                <span className="text-[9px] text-rose-500/70 mt-1">Bearish</span>
                {ui.position?.type === 'PUT' && (
                    <div className="absolute -top-2 -right-2 bg-rose-500 text-slate-900 w-6 h-6 rounded-full flex items-center justify-center font-bold text-xs shadow-lg">
                        {ui.position.contracts}
                    </div>
                )}
            </button>
        </div>
    </div>
  );
};

